-- Poems batch 145
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b061a1eb-0a15-42c8-a3b8-992ec2848878','和韓欽聖學士襄陽聞喜亭','梅堯臣','宋','宋诗','song-poetry','','[]','亭欄下望漢江水，浄綠無風寫鏡明。',64,'全唐诗/poet.song.15000.json','["亭欄下望漢江水，浄綠無風寫鏡明。", "日脚穿雲射洲影，槎頭擺子出潭聲。", "檣帆落處遠鄉思，砧處動時歸客情。", "使者徘徊有佳興，高吟不減謝宣城。"]'),
('2b1a97fa-6a5d-43ce-9f93-c775f101063b','許仲塗屯田以新詩見訪','梅堯臣','宋','宋诗','song-poetry','','[]','許氏世工詩，渾棠格力微。',48,'全唐诗/poet.song.15000.json','["許氏世工詩，渾棠格力微。", "獨能兼古律，無不是珠璣。", "捧卷光蓬室，停車照竹扉。", "陽春復高調，自昔和人稀。"]'),
('0f74dec8-de4b-4d57-9580-29bf14aff611','答祖擇之惠黄雀鮓','梅堯臣','宋','宋诗','song-poetry','','[]','李白勸爾莫逐炎洲翠，亦莫近吳宮燕。',77,'全唐诗/poet.song.15000.json','["李白勸爾莫逐炎洲翠，亦莫近吳宮燕。", "爾不聽此言，禍患今乃見。", "吳火時雖無，越羅日生變。", "空知稻粱肥，豈悟杯盤薦。", "我不聞爾聲，謬成先生饌。", "咀嚼勿言非，雉雁猶充膳。"]'),
('d5f5cc94-7bd8-4d99-80b2-f992916d83b6','賦永叔家白鸚鵡雜言','梅堯臣','宋','宋诗','song-poetry','','[]','交翠衿，刷羽。',137,'全唐诗/poet.song.15000.json','["交翠衿，刷羽。", "性安馴，善言語。", "金籠愛，養婦女，是爲隴山之鸚鵡。", "有白其類，毛冠角舉。", "圓舌柔音世競許，方尾鶻身食稻稰。", "白鵠之白是其常，越羣超衆由天與。", "胡人望氣海上來，獻於公所奇公才。", "公持大筆寫萬物，驚葩萼，如春雷。", "方夸玉兔未詠此，依約似畏常娥猜。", "坐無禰正平，胡爲使我作賦其間哉。"]'),
('b1b0caa4-9bde-429b-a3bb-7dcdeca127c4','送永興書寄王申','梅堯臣','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','驅車西入關，有樂似王粲。',84,'全唐诗/poet.song.15000.json','["驅車西入關，有樂似王粲。", "灞陵十二月，風雪將漫漫。", "誰方策騫馿，舊道涉古岸。", "是時吟興愜，不問前亭爨。", "長安到未晚，文字當几案。", "却思車上趣，塵慮已歷亂。", "猶有終南山，晴明舉頭看。"]'),
('6908844e-4f1f-4003-a633-545ceacbfe29','覽顯忠上人詩','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昔讀遠公傳，頗聞高行僧。',48,'全唐诗/poet.song.15000.json','["昔讀遠公傳，頗聞高行僧。", "廬山將欲雪，瀑布結成冰。", "尋跡數百載，歷危千萬層。", "師來笑賈島，只解詠嘉陵。"]'),
('e7c379c7-fd30-4a68-8177-81aa96da38b4','依韻和吳長文舍人對雪懷永叔內翰','梅堯臣','宋','宋诗','song-poetry','','[]','紫禁低雲拂綺櫳，西垣人憶玉堂翁。',64,'全唐诗/poet.song.15000.json','["紫禁低雲拂綺櫳，西垣人憶玉堂翁。", "撚髭覓句方傳詠，著樹成花尚舞空。", "不管因風吹塞外，任教飛片落杯中。", "曉來城郭遮無路，阮籍驅車莫歎窮。"]'),
('ca81de06-1ad0-4840-ba67-c0314f922e81','送王巖夫秘校通判滑州','梅堯臣','宋','宋诗','song-poetry','','[]','昔聞信都侯，嘗作畫舫齋。',120,'全唐诗/poet.song.15000.json','["昔聞信都侯，嘗作畫舫齋。", "空戶兩向闢，罇席長對排。", "左顧樹若岸，右盼堵成崖。", "既無風波虞，但與物景諧。", "一從信都去，來者趣意乖。", "屋室改庫廐，花木爲薪柴。", "君當訪其蹟，更葺安舊牌。", "記石儻尚在，塵土加洗揩。", "然後釀井泉，吟醉前人偕。", "寄言靈河守，高此別乘懷。"]'),
('d4ab602e-7698-428b-934a-bc9a24c1e2dc','和宋次道答弟中道寄懷','梅堯臣','宋','宋诗','song-poetry','','[]','陸家兄弟苦西東，黄耳傳書近已通。',64,'全唐诗/poet.song.15000.json','["陸家兄弟苦西東，黄耳傳書近已通。", "共歎流年同轉轂，各驚華髮似飛蓬。", "河冰夜合知霜勁，寒霧朝開見日紅。", "臘盡春來又相遠，江南江北望歸鴻。"]'),
('83586a04-fde1-4c4d-b2ae-f76edc49c9f7','元日閤門拜表遇雪呈永叔','梅堯臣','宋','宋诗','song-poetry','','[]','六花隨表拜東廂，庭下遥呼萬歲長。',64,'全唐诗/poet.song.15000.json','["六花隨表拜東廂，庭下遥呼萬歲長。", "王會圖中陳璧馬，漢官儀裏濕旂常。", "因風亂絮霑螭首，似鵠輕毛落井床。", "素髮垂冠少顔色，衆人休笑老爲郎。"]'),
('e6ddaa26-7ee4-45e4-8446-e848a3022ce7','王樂道太丞立春早朝','梅堯臣','宋','宋诗','song-poetry','','[]','近臣頭上黄金勝，殿前拜賜東風應。',104,'全唐诗/poet.song.15000.json','["近臣頭上黄金勝，殿前拜賜東風應。", "蓼牙疏甲簇春盤，肉抹長絲何亙亙。", "寬衣武卒轝至庭，人歸下筯殊難稱。", "我家無火甑生塵，㡜柳綵花空著興。", "空著興，將底爲，但願得米資晨炊，不管飛霙與麥宜。", "千官隊中身最卑，五日一謁前旒垂。"]'),
('419020db-5555-4101-8365-75f12413e0c8','上元夕有懷韓子華閣老','梅堯臣','宋','宋诗','song-poetry','','[]','一歲老一歲，新年思舊年。',48,'全唐诗/poet.song.15000.json','["一歲老一歲，新年思舊年。", "東樓嘗共望，九陌聽爭先。", "白髮更中笑，舞姝應轉妍。", "追隨都已倦，强對月明前。"]'),
('afc8ff25-1b26-4fc5-a445-1d994887b360','錢君倚學士日本刀','梅堯臣','宋','宋诗','song-poetry','','[]','日本大刀色青熒，魚皮帖欛沙點星。',144,'全唐诗/poet.song.15000.json','["日本大刀色青熒，魚皮帖欛沙點星。", "東胡腰鞘過滄海，舶帆落越棲灣汀。", "賣珠入市盡明月，解絛換酒琉璃缾。", "當壚重貨不重寶，滿貫穿銅去求好。", "會稽上吏新得名，始將傳玩恨不早。", "歸來天祿示朋游，光芒曾射扶桑島。", "坐中燭明魑魅遯，呂虔不見王祥老。", "古者文事必武備，今人褒衣何足道。", "干將太阿世上無，拂拭共觀休懊惱。"]'),
('161ad807-953e-4172-8692-71dd657d9029','依韻和杭州梅龍圖入淮見寄','梅堯臣','宋','宋诗','song-poetry','','[]','東都車馬苦飛霾，南國桅帆喜過淮。',64,'全唐诗/poet.song.15000.json','["東都車馬苦飛霾，南國桅帆喜過淮。", "船背插旗風自展，沙頭迎浪雪相排。", "白魚已薦糟增味，紅稻新炊粟厭懷。", "定似謝公吟遠岫，錢塘應合有高齋。"]'),
('f3eb6e1a-5c90-447a-b0c3-b4c252e45159','送周直孺秘校和州都曹','梅堯臣','宋','宋诗','song-poetry','','[]','箭頭破賊棄不爲，筆端射策取桂枝。',96,'全唐诗/poet.song.15000.json','["箭頭破賊棄不爲，筆端射策取桂枝。", "殿前脫袍改舊色，庭下折腰甘去時。", "歷陽郡小太守好，督郵官閑衆吏嬉。", "江邊竹園啼竹雞，竹裏種花春過遲。", "東望望夫雲脚垂，煙雨隔岸風檣欹。", "濕鴈不起沙上嘶，君思歷亂如盎絲。"]'),
('e5510ba3-2428-4e24-88e8-adc998815e72','送謝師厚太博通判汾州','梅堯臣','宋','宋诗','song-poetry','','[]','頻官吳越館粳稻，況住南陽多水田。',80,'全唐诗/poet.song.15000.json','["頻官吳越館粳稻，況住南陽多水田。", "北登太行入汾曲，正穫𥝧䅉秋風前。", "晉人朴厚自寡訟，軟炊玉粒河鱗鮮。", "君方少壯齒頰健，甘美不負經腹便。", "有意南飛寄我信，滿川鳴雁下連連。"]'),
('6bf4c630-9e61-445f-8193-ff428ce3c0ad','依韻和永叔都亭館伴戲寄','梅堯臣','宋','宋诗','song-poetry','','[]','去年鎖宿得聯華，二月牆頭始見花。',32,'全唐诗/poet.song.15000.json','["去年鎖宿得聯華，二月牆頭始見花。", "今日都亭公感物，明朝太學我辭家。"]'),
('1ec97f28-d7c6-4fde-b67e-00cb1dde230b','敘兩會事戲寄刁景純學士','梅堯臣','宋','宋诗','song-poetry','','[]','東家紅梅開出牆，牆西女兒學新粧。',144,'全唐诗/poet.song.15000.json','["東家紅梅開出牆，牆西女兒學新粧。", "春風引客白日長，天河綠水浮鴛鴦。", "摘花贈渠到渠處，更問鴛鴦寄聲去。", "昨日吳郎坐上時，袖中小字鴛鴦付。", "酒雖入脣不能醉，醉得人心是朝暮。", "朝愁衾枕舊薰香，暮愁霰雪飄如絮。", "聽他雙韻舞伊州，舞徹夭妍不轉頭。", "衆人笑語曾不語，腸作車輪一萬周。", "屈節請還無甚媿，當時麈尾自驅牛。"]'),
('8ccee13e-5c1d-4cda-9e99-b7f1c5cfa875','送李君錫學士使契丹弔慰','梅堯臣','宋','宋诗','song-poetry','','[]','昨日匈奴來告哀，殿門不識桃花開。',64,'全唐诗/poet.song.15000.json','["昨日匈奴來告哀，殿門不識桃花開。", "今聞君去作弔使，正值雁嘷從北迴。", "風捲黄雲無遠近，山留白雪猶枯荄。", "歸看車馬汗流沫，逃暑爲傳河朔杯。"]'),
('b101cb09-c8bd-47ac-ab2c-79be780a6583','送朱純臣端公使契丹奠祭','梅堯臣','宋','宋诗','song-poetry','','[]','漢庭遣奠閼氏幕，二月陰山雪未銷。',64,'全唐诗/poet.song.15000.json','["漢庭遣奠閼氏幕，二月陰山雪未銷。", "行盡黄沙春不見，哀纏碧眼魄誰招。", "已將厚禮施殊俗，更錄專辭入本朝。", "名馬贈歸多愛惜，北風嘶處競蕭蕭。"]'),
('16f5d865-6a32-4859-88bb-b6b3167bd027','送邵裔長洲主簿','梅堯臣','宋','宋诗','song-poetry','','[]','姑蘇城頭烏哺時，長洲草綠春袍歸。',64,'全唐诗/poet.song.15000.json','["姑蘇城頭烏哺時，長洲草綠春袍歸。", "魯桑葉小蠶出遲，吳田水暖牛耕肥。", "里胥爭迎懸寮喜，入門先自易綵衣。", "拜親然後及王事，簿書豈得長相鞿。"]'),
('f3cb7622-064a-4264-917e-cf262ae78a54','送薛公期比部歸絳州展墓','梅堯臣','宋','宋诗','song-poetry','','[]','風雨梨花殘，松柏墓門晚。',48,'全唐诗/poet.song.15000.json','["風雨梨花殘，松柏墓門晚。", "嗣子千里駒，羊腸九折坂。", "春裘不畏寒，行路未爲遠。", "舊來河內守，父老將衣挽。"]'),
('48795901-4518-4730-b360-0553621237f2','送次道學士知太平州因寄曾子固','梅堯臣','宋','宋诗','song-poetry','','[]','春浦楊花撩亂飛，春江鮆魚來正肥。',112,'全唐诗/poet.song.15000.json','["春浦楊花撩亂飛，春江鮆魚來正肥。", "采石新林兒女去，茭白蒲牙艇子歸。", "歸令煑魚不得熟，已望使君船上磯。", "上磯亦不待潮應，爭牽篾纜泥污衣。", "姑熟溪頭槌大鼓，紅抹鞾刀趨俯僂。", "牙兵可擬岸傍蘆，森森甲立雄南土。", "更得西州謝法曹，新詠定多傳樂府。"]'),
('5e5cfcac-610f-4fce-b268-2e2b49a68f0a','依韻和劉原甫舍人楊州五題 時會堂二首 其一','梅堯臣','宋','宋诗','song-poetry','','[]','今年太守采茶來，驟雨千門禁火開。',32,'全唐诗/poet.song.15000.json','["今年太守采茶來，驟雨千門禁火開。", "一意愛君思去疾，不緣時會此中杯。"]'),
('846ed422-0cd3-455e-b0f1-ed2c42066480','依韻和劉原甫舍人楊州五題 時會堂二首 其二','梅堯臣','宋','宋诗','song-poetry','','[]','雨發雷塘不起塵，蜀崑岡上暖先春。',32,'全唐诗/poet.song.15000.json','["雨發雷塘不起塵，蜀崑岡上暖先春。", "煙牙才吐朱輪出，向此親封御餠新。"]'),
('844297ff-50ea-4962-a163-34d05f332e90','依韻和劉原甫舍人楊州五題 竹西亭','梅堯臣','宋','宋诗','song-poetry','','[]','結雨竹西若若川，楊州歌吹思當年。',32,'全唐诗/poet.song.15000.json','["結雨竹西若若川，楊州歌吹思當年。", "劉郎若向風前唱，夢入青樓事惘然。"]'),
('0d4b597b-fbaa-4ba5-8423-790c6ce32407','依韻和劉原甫舍人楊州五題 春貢亭','梅堯臣','宋','宋诗','song-poetry','','[]','夢谷浮船穩且平，泊登岡頂看茶生。',32,'全唐诗/poet.song.15000.json','["夢谷浮船穩且平，泊登岡頂看茶生。", "始從官屬二三輩，時聽春禽一兩聲。"]'),
('74ea9ae6-534f-4294-ac46-692a543fb79a','依韻和劉原甫舍人楊州五題 蒙谷','梅堯臣','宋','宋诗','song-poetry','','[]','茗園葱蒨與山籠，一夜驚雷發舊叢。',32,'全唐诗/poet.song.15000.json','["茗園葱蒨與山籠，一夜驚雷發舊叢。", "五馬留連未能去，土囊深處路微通。"]'),
('1ddff71e-6bc9-4c36-8807-d6f3fcbf4e46','依韻和劉原甫舍人楊州五題 崑丘','梅堯臣','宋','宋诗','song-poetry','','[]','隋家宮殿昔初成，不道荒凉獸迹行。',32,'全唐诗/poet.song.15000.json','["隋家宮殿昔初成，不道荒凉獸迹行。", "今日知來高處望，山川興廢使人驚。"]'),
('7cf7a8df-8a1a-4bac-9eeb-5e811a2ae5fb','送江陰簽判晁太祝','梅堯臣','宋','宋诗','song-poetry','','[]','去無珠履爲上賓，進船申浦憶春申。',64,'全唐诗/poet.song.15000.json','["去無珠履爲上賓，進船申浦憶春申。", "江田插秧鵓姑雨，絲網得魚雲母鱗。", "青天折桂香未滅，紫豉煑蒓甘更新。", "平時況可樂風月，吳物信美聊前陳。"]'),
('551267e7-580b-4116-ac4c-4efafc89110e','送朱表臣職方提舉運鹽','梅堯臣','宋','宋诗','song-poetry','','[]','蜃竈煑溟渤，航鹹播楚越。',228,'全唐诗/poet.song.15000.json','["蜃竈煑溟渤，航鹹播楚越。", "官榷利言盈，盜販弊相汨。", "連艘以轉致，攪灰或沉沒。", "雖使日鞭黥，未易窮姦窟。", "朝廷用朱侯，提職欲無闕。", "侯因許專畫，拜疏陳其說。", "曰臣有更張，敢以肝膽竭。", "荆湘嶺下城，恃遠不畏罰。", "堂堂事私賈，遮吏遭驅突。", "願使商自通，輸金無暴猝。", "淮江且循常，約束備本末。", "國用必餘資，亭民無滯物。", "事下丞相府，論議不可拔。", "從之東南蘇，拒之財賦遏。", "聽侯侯往施，所便黔黎活。", "五味既和調，萬里銷狂悖。", "汴水桃花時，犀舟順流發。", "過淮逢絮鮆，泊岸採蘆蕨。", "挂帆趨浪頭，應不勞歲月。"]'),
('2345de66-29bb-4401-856c-ce844e7564f8','送晁質夫太丞知深州','梅堯臣','宋','宋诗','song-poetry','','[]','蕪蔞問古亭，春入饒陽城。',48,'全唐诗/poet.song.15000.json','["蕪蔞問古亭，春入饒陽城。", "豆粥君王遠，壺漿刺史迎。", "地凉宜牧馬，塞近慣調兵。", "爲寄井泉石，老來思目明。"]'),
('5339464a-879c-4e96-9783-49d27b2d316f','送少卿知宣州','梅堯臣','宋','宋诗','song-poetry','','[]','汴水清明下，宣城太守行。',48,'全唐诗/poet.song.15000.json','["汴水清明下，宣城太守行。", "鴨頭吳蕩綠，燕尾楚船輕。", "族本三陽重，詩從小謝清。", "州民還最喜，門下舊通名。"]'),
('93cc9a9b-8735-4bde-bd61-3e15813f6c56','送知保定軍李太保','梅堯臣','宋','宋诗','song-poetry','','[]','山西世世李將軍，家聲前後多功勳。',64,'全唐诗/poet.song.15000.json','["山西世世李將軍，家聲前後多功勳。", "今乘一障俯絕塞，莫以久和無陣雲。", "菰蒲生塘長春綠，牛羊隔河歸暮雲。", "簡易自能齊士卒，不嚴刁斗亦名聞。"]'),
('9b1f8b78-6cd6-4bf9-b458-2892716cb993','依韻和李君錫學士北使見寄','梅堯臣','宋','宋诗','song-poetry','','[]','行色見車馬，爲之具壺觴。',72,'全唐诗/poet.song.15000.json','["行色見車馬，爲之具壺觴。", "暫辭甘泉宮，遠奉左賢王。", "蒙茸春裘薄，匼匝金絡光。", "唯知君命重，不數沙路長。", "魯酒雖入脣，胡笳易迴腸。", "歸來立螭頭，言動書不忘。"]'),
('9a6420bc-2b98-4f54-b4cb-bf1b6b308d51','送張山甫秘校歸緱氏','梅堯臣','宋','宋诗','song-poetry','','[]','去年來折桂，今年來娶婦。',48,'全唐诗/poet.song.15000.json','["去年來折桂，今年來娶婦。", "得意春風前，還家寒食後。", "蓬巷鬧雞犬，藤花蔭井臼。", "緱山白醪醇，重酌高堂壽。"]'),
('cc843a6e-f6dd-460d-a681-907cc33c6f3b','送江東轉運楊少卿','梅堯臣','宋','宋诗','song-poetry','','[]','世言楚使者，乃是漢名卿。',48,'全唐诗/poet.song.15000.json','["世言楚使者，乃是漢名卿。", "曾欲察黄綬，但能勤列城。", "江山無改故，草樹幾更榮。", "有意息民甚，不同求羨盈。"]'),
('7a597f8e-f75c-40f9-b8ce-d1eccc0c647b','宜春宴射篇李駙馬請賦雜言','梅堯臣','宋','宋诗','song-poetry','','[]','風雨未過桐華時，宜春苑中梨萼披。',96,'全唐诗/poet.song.15000.json','["風雨未過桐華時，宜春苑中梨萼披。", "天子賜宴羣臣嬉，少年都尉方追隨。", "暮歸遲喜聯留後，兄弟雙弓射熊皮。", "侯宗戚族坐上少，伯仲相顧驚恩私。", "鳳皇樓高玉簫吹，金絡駿馬不肯騎。", "自戒危溢作後規，何郎莫媿書與詩。"]'),
('9e535938-b45e-4048-bd09-e9929855cc85','送王樂道太丞應瀛州辟','梅堯臣','宋','宋诗','song-poetry','','[]','相如既擊劍，仲宣亦從軍。',84,'全唐诗/poet.song.15000.json','["相如既擊劍，仲宣亦從軍。", "二人當其時，皆以能賦聞。", "韓公守武垣，犀兵若屯雲。", "幄中欲寄畫，才智莫有君。", "請之天子所，朝奏夕離羣。", "爲沽斗酒飲，爲買赤鯉焚。", "魚盡酒亦盡，醉起衣袂分。"]'),
('9842e1ea-4170-41ea-aac4-c3751d2176ab','送楚屯田知扶溝','梅堯臣','宋','宋诗','song-poetry','','[]','客亭多少路，花信幾番風。',48,'全唐诗/poet.song.15000.json','["客亭多少路，花信幾番風。", "折柳贈新翠，種桃思舊紅。", "淵明節已異，潘岳趣還同。", "政治有餘力，歸來辭賦工。"]'),
('aad6d80b-e1d5-4a04-8aae-add18c9b76fb','呂山人同荆供奉見過','梅堯臣','宋','宋诗','song-poetry','','[]','街上春泥踏始開，山人忽同供奉來。',48,'全唐诗/poet.song.15000.json','["街上春泥踏始開，山人忽同供奉來。", "老奴行遲報我晚，怒氣欲拔庭中槐。", "聞說道心調伏久，等閑休要起嫌猜。"]'),
('10a8c732-1e43-4254-bdad-4cbd8fe90d72','觀劉元忠小鬟舞','梅堯臣','宋','宋诗','song-poetry','','[]','桃小未開春意濃，梢頭綠葉映微紅。',32,'全唐诗/poet.song.15000.json','["桃小未開春意濃，梢頭綠葉映微紅。", "君家歌管相催急，枝弱不勝花信風。"]'),
('efdcc089-5a2d-4c69-b3a0-49755bfea588','次韻奉和永叔謝王尚書惠牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','大梁有公子，洛陽有游俠。',300,'全唐诗/poet.song.15000.json','["大梁有公子，洛陽有游俠。", "昔時意氣相憑陵，不問興亡事栽插。", "栽紅插綠鬭青春，春風與開春雨颯。", "兩都富貴不相殊，走馬尋芳何合雜。", "只聞年少競爭先，摘葉嗅花身更捷。", "安知遺愛舊留守，馳獻百葩光浥浥。", "尚書最重歐陽公，盈盤分去蜂偷獵。", "但能爲樂飲醇酒，何必署名黄紙牒。", "翰林職清文字稀，不比外官煩應接。", "曩公爲花曾作譜，端相用意隨蝴蝶。", "擬王擬妃姚與魏，歲歲年年千萬葉。", "獨將顔色定高低，綠珠雖美猶爲妾。", "從來鑒裁主端正，不藉娉婷削肩胛。", "舊品既著新品增，偏惡妬芽須打拉。", "嘗憶同朋有七人，每失一人淚緣睫。", "唯我與公今且存，無復名園共携榼。", "公因尚書戴紅紫，白髮欺公生匼匝。", "磨墨揮毫興不衰，作詩坐使劉曹怯。", "副本能傳幸一觀，口誦舌摇徒囁囁。"]'),
('4a3b17cc-a0c1-436f-83c3-1cd8a82fa508','送王郎中知江陰','梅堯臣','宋','宋诗','song-poetry','','[]','持歸漢省青綾被，去看吳都白馬潮。',64,'全唐诗/poet.song.15000.json','["持歸漢省青綾被，去看吳都白馬潮。", "疊鼓渡江寒浪伏，鳴鐃入境野雲飄。", "魚穿楊柳誇鮮膾，人采芙蓉學細腰。", "家有二槐爲太守，弟兄誰似李文饒。"]'),
('d1585077-3d9c-4edb-b456-a09305f56ecf','送閻仲孚郎中南游山水','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','蜀山難於上青天，聞之李白爲舊傳。',192,'全唐诗/poet.song.15000.json','["蜀山難於上青天，聞之李白爲舊傳。", "蜀客往返曾又然，奇峯又與三峽連。", "巫陽神女暮爲雨，飛入楚臺王夢旃。", "相如楊雄不道此，宋玉景差其賦偏。", "西州才子邯鄲守，懷章往代尚踰年。", "家住岷峨多北宦，乘閑因借下江船。", "未浮洞庭沅湘去，還探禹穴希馬遷。", "春申樓觀已不見，子胥怒濤猶滿川。", "錢塘太守同鄉里，一見君來顔已喜。", "甘饌香脆與君游，詩貯篋囊携不起。", "浣沙溪頭西子家，自尋錦石菖蒲花。", "掃歸成都與士誇，君平曾已悟星槎。"]'),
('713ce114-8c3c-4167-ad60-8e83db5c0a0f','次韻和永叔嘗新茶雜言','梅堯臣','宋','宋诗','song-poetry','','[]','自從陸羽生人間，人間相學事春茶。',244,'全唐诗/poet.song.15000.json','["自從陸羽生人間，人間相學事春茶。", "當時採摘未甚盛，或有高士燒竹煑泉爲世誇。", "入山乘露掇嫩觜，林下不畏虎與蛇。", "近年建安所出勝，天下貴賤求呀呀。", "東溪北苑供御餘，王家葉家長白牙。", "造成小餠若带銙，鬭浮鬭色傾夷華。", "味甘迴甘竟日在，不比苦硬令舌窊。", "此等莫與北俗道，只解白土和脂麻。", "歐陽翰林最別識，品第高下無欹斜。", "晴明開軒碾雪末，衆客共賞皆稱嘉。", "建安太守置書角，青蒻包封來海涯。", "清明纔過已到此，正見洛陽人寄花。", "兔毛紫盞自相稱，清泉不必求蝦蟆。", "石缾煎湯銀梗打，粟粒鋪面人驚嗟。", "詩腸久饑不禁力，一啜入腹鳴咿哇。"]'),
('219a6ba7-2f7d-4845-bc10-ba1e3b9ca79a','次韻和再拜','梅堯臣','宋','宋诗','song-poetry','','[]','建溪茗株成大樹，頗殊楚越所種茶。',246,'全唐诗/poet.song.15000.json','["建溪茗株成大樹，頗殊楚越所種茶。", "先春喊山掐白萼，亦異鳥觜蜀客誇。", "烹新鬭硬要咬盞，不同飲酒爭畫蛇。", "從揉至碾用盡力，只取勝負相笑呀。", "誰傳雙井與日注，終是品格稱草芽。", "歐陽翰林百事得精妙，官職況已登清華。", "昔得隴西大銅碾，碾多歲久深且窊。", "昨日寄來新臠片，包以{𥫗/撩}蒻纏以麻。", "唯能賸啜任腹冷，幸免酩酊冠弁斜。", "人言飲多頭顫挑，自欲清醒氣味嘉。", "此病雖得優醉者，醉來顛踣禍莫涯。", "不願清風生兩腋，但願對竹兼對花。", "還思退之在南方，嘗說稍稍能啗蟆。", "古之賢人尚若此，我今貧陋休相嗟。", "公不遺舊許頻往，何必絲管喧咬哇。"]'),
('b1eec724-fe6f-4d7d-a983-7da8a042a5a9','送許當職方通判泉州','梅堯臣','宋','宋诗','song-poetry','','[]','乳烏不遠飛，乳獸不遠遊。',96,'全唐诗/poet.song.15000.json','["乳烏不遠飛，乳獸不遠遊。", "異類尚有戀，人獨安所求。", "許侯恰爲郡，乃甘貳一州。", "得以奉雙親，時物供膳羞。", "竹箭水順疾，紅旗插歸舟。", "歸舟莫苦急，睢陽多舊儔。", "丞相正喜士，樽酒應爲留。", "清源六千里，到日魚蟹秋。"]'),
('41395ed9-0055-4476-b4a0-6c7316c68850','送葛都官南歸','梅堯臣','宋','宋诗','song-poetry','','[]','不羨新爲赤縣尹，惟羨暫向江南歸。',64,'全唐诗/poet.song.15000.json','["不羨新爲赤縣尹，惟羨暫向江南歸。", "江南羃羃梅雨時，風帆差差並鳥飛。", "罾竿夾岸長若桅，水籠畜魚鮮且肥。", "家在千山古溪上，先應喜鵲噪門扉。"]'),
('558f3546-cd94-4ddd-a293-3c8eafb37944','楊樂道留飲席上客置黄紅絲頭芍藥','梅堯臣','宋','宋诗','song-poetry','','[]','洛陽賣牡丹，江都買芍藥。',204,'全唐诗/poet.song.15000.json','["洛陽賣牡丹，江都買芍藥。", "賣與富人歡，買爲游子樂。", "萬絲必同心，千葉必同萼。", "五色相淺深，百金相厚薄。", "栽培動經年，風雨便成昨。", "蕭條洛陽城，索寞江都郭。", "頼有一春花，能無十千酌。", "朝看門擁車，暮見門羅雀。", "嘗聞月底人，欲把月桂斫。", "要使清光多，四海意開廓。", "我亦愛明月，常滿不願落。", "上弦過楊侯，乃值寒雨作。", "共飲三四人，不覺傳鳴柝。", "持葩金谷豪，朱黄何灼爍。", "還思溱洧上，士與女相謔。", "實此香草芳，請我賦其略。", "酒闌爲追詠，思拙筆屢閣。"]'),
('454abb57-5ad8-4bc6-aa2f-c74bd4280814','項羽','梅堯臣','宋','宋诗','song-poetry','','[]','羽以匹夫勇，起于隴畝中。',60,'全唐诗/poet.song.15000.json','["羽以匹夫勇，起于隴畝中。", "遂將五諸侯，三年成霸功。", "天下欲滅秦，無不慕强雄。", "秦滅責以德，豁達歸沛公。", "自矜奮私智，奔亡竟無終。"]'),
('ca3c7dcd-3a35-4a9a-b7dc-bbb5aa6af4e3','送陳郎中知和州','梅堯臣','宋','宋诗','song-poetry','','[]','藹藹尚書郎，出爲二千石。',96,'全唐诗/poet.song.15000.json','["藹藹尚書郎，出爲二千石。", "伯父歷將相，兄弟皆烜赫。", "前罷永嘉守，民俗遮阡陌。", "獨將海松歸，夸與都下客。", "今去烏江邊，寂寞空舊跡。", "當求虞姬草，無風舞隨拍。", "城頭可曠望，千里波月白。", "俱助使君歡，平時遺吏責。"]'),
('ade1a4c1-41d4-4c5a-8836-2afd76b4bd48','送薛十水部通判并州','梅堯臣','宋','宋诗','song-poetry','','[]','并州自古近胡地，牛酒常行十萬兵。',64,'全唐诗/poet.song.15000.json','["并州自古近胡地，牛酒常行十萬兵。", "少尹曾爲五府辟，將軍況有舊家聲。", "桑麻故已知風俗，丘壠何須訪姓名。", "聞說至今猶好馬，試求安穩衆中行。"]'),
('0650cfea-5a13-4694-9356-31e4ce7925a0','寄題西洛致仕張比部靜居院四堂','梅堯臣','宋','宋诗','song-poetry','','[]','張侯歸靜居，堂宇結四隅。',216,'全唐诗/poet.song.15000.json','["張侯歸靜居，堂宇結四隅。", "堂中何所有，書畫羅籤厨。", "四堂各異名，名異義亦殊。", "夷心與會真，內以道德娛。", "清白及金蘭，外爲子孫模。", "西南夜落蟾，東北朝生烏。", "天門風相通，盛衰理可無。", "蒨爾松檜樹，間之花石株。", "雨晴氣候佳，鄰里或來俱。", "遣摘班林筍，共持香粳盂。", "飯畢循徑行，不使僮僕扶。", "所至舊衣坐，遍歷日過晡。", "時遇園果熟，甘漿而粉膚。", "就枝掇鮮美，咀味銷冰酥。", "以此樂歲月，豈是忘形軀。", "禮法不我棄，勞吝不我紆。", "上不媿二疎，下不泛五湖。", "自有逍遥趣，幸世遭唐虞。"]'),
('8475702e-9d41-44ce-99f6-aff336b6f529','送洪秘丞知大寧監','梅堯臣','宋','宋诗','song-poetry','','[]','三峽蠻溪上，千山楚俗兼。',48,'全唐诗/poet.song.15000.json','["三峽蠻溪上，千山楚俗兼。", "婦人樵入市，官井貨專鹽。", "魑魅或爲患，獼猴常可嫌。", "君能厚風化，男子使腰鎌。"]'),
('8907411b-4e88-4fa8-8126-665c6abf0604','送江西轉運馮廣淵學士','梅堯臣','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6ed5\u738b\u9601"]','五月江南行，南風江惡溯。',84,'全唐诗/poet.song.15000.json','["五月江南行，南風江惡溯。", "乘潮雖有信，不過湓城去。", "船經香爐峯，峯前須暫住。", "三年少尹勞，始得看瀑布。", "到官未必閑，舉察憂財賦。", "迴思廬山傍，塵土已生慮。", "尚存滕王閣，無忘一登顧。"]'),
('9ff87a51-f5d0-45ce-9327-3113d54acd1e','依韻和永叔景靈致齋見懷','梅堯臣','宋','宋诗','song-poetry','','[]','翰林文字本雄强，況復齋祠向靜坊。',64,'全唐诗/poet.song.15000.json','["翰林文字本雄强，況復齋祠向靜坊。", "高樹黄鸝無去意，深廊朱幕動微凉。", "不嗟門外塵沙苦，只覺壺中歲月長。", "庭下陰苔未教掃，榴花紅落點青蒼。"]'),
('f1b3ed58-3dd7-4977-9b25-5f8e38826f80','雜言送當世待制知楊州','梅堯臣','宋','宋诗','song-poetry','','[]','廣陵老人爭持壺酒，朝言送少年使君，暮言迎少年太守。',129,'全唐诗/poet.song.15000.json','["廣陵老人爭持壺酒，朝言送少年使君，暮言迎少年太守。", "少年俱是玉墀人，文章快利生銅吼。", "莫作蕪城賦，事往復何有。", "莫聽嵇康琴，商聲豈堪久。", "今當太平非不偶，星宿煌煌羅北斗。", "楊州古富變荒凉，萬俗一心依父母。", "地包淮海江湖寬，貨走荆吳楚越厚。", "開釀刲羊願遇賓，天下沄沄不輕口。"]'),
('c68b6317-1c82-4707-bc96-bcfc863c22b2','送蘇公佐屯田知單州','梅堯臣','宋','宋诗','song-poetry','','[]','柏上有羣烏，一烏飛向東。',56,'全唐诗/poet.song.15000.json','["柏上有羣烏，一烏飛向東。", "方棲城頭與人司吉凶。", "八月禾已穫，九月黍已舂。", "競持美酒相慶樂年豐。", "借問何能爾，時平無困窮。"]'),
('f5d47ead-4455-4e68-b720-4c6b24418a4a','王平甫惠畫水卧屏','梅堯臣','宋','宋诗','song-poetry','','[]','臨流別君時，羨君觀吳潮。',144,'全唐诗/poet.song.15000.json','["臨流別君時，羨君觀吳潮。", "君行識我意，遣畫一幅綃。", "畫作繞床屏，滔滔隨驚飈。", "前浪雪花捲，後浪白馬跳。", "宛然千萬重，不似筆墨描。", "窊亞亂我目，坐卧疑動摇。", "夜燈照河漢，如有織女招。", "朝日下天窗，東海無秦橋。", "秦橋不可度，織女不可邀。", "但慕乘桴公，空能誦唐堯。", "嘗聞挾柘彈，意必在食鴞。", "終當五湖上，歸去學漁樵。"]'),
('6e7294a4-2dca-4d4c-abb8-5abde259125b','送萬州武寧段尉','梅堯臣','宋','宋诗','song-poetry','','[]','相見三十載，喜君始成名。',84,'全唐诗/poet.song.15000.json','["相見三十載，喜君始成名。", "新袍照江綠，白髮憎鑑明。", "臨水必觀魚，獨傷魚命輕。", "朝爲淵底游，暮爲釜中烹。", "彼方路艱遠，其民亦天氓。", "餒之則爲盜，非是惡厥生。", "捕多勿夸能，能在不犯兵。"]'),
('a3392e64-7dd8-4e52-a724-a4e951bcbeb5','次韻答黄介夫七十韻','梅堯臣','宋','宋诗','song-poetry','','[]','春風不擇草，萬卉皆發萌。',288,'全唐诗/poet.song.15000.json','["春風不擇草，萬卉皆發萌。", "盛夏一長養，秋實俱與成。", "舂粒以蒸炊，刈枯以煎烹。", "工師調五音，不問咸與韺。", "自取衆律和，黍谷動華英。", "可以薦祖廟，可以陳帝庭。", "良將統萬卒，所向若驚霆。", "戰鬭衆益勇，號令夜益明。", "破敵必拉朽，不見堅陣橫。", "我觀欲物際，亦在農力興。", "我觀合奏時，亦在考擊并。", "我觀成功日，亦在間得情。", "草木有美惡，造化無喜憎。", "五聲有高下，一致不可評。", "三軍用貔虎，不較蚊睫螟。", "大君設時網，廣海無漏鯨。", "磊落黄夫子，爲學不自輕。", "四十登賢科，良賈售百朋。", "得志豈計晚，成名等衆熒。", "舊交半存沒，新知慕徒傾。", "老鶴晴一唳，隨風無近聲。", "好論古今詩，品藻笑鍾嶸。", "欲掃李杜壇，未審誰主盟。", "我衰百事倦，白首聊窮經。"]'),
('e910336c-cdd3-4a1d-928b-485f0d552936','永叔內翰見索謝公遊嵩書感歎希深師魯子聰幾道皆爲異物獨公與余二人在因作五言以敘之','梅堯臣','宋','宋诗','song-poetry','','[]','昔在洛陽時，共遊銅駞陌。',288,'全唐诗/poet.song.15000.json','["昔在洛陽時，共遊銅駞陌。", "尋花不見人，前代公侯宅。", "深堂鎖塵埃，空壁鬭蜥蜴。", "楸陰布苔綠，野蔓纏石碧。", "池魚有偷釣，林鳥有巧射。", "園隸見我來，朱門暫開闢。", "園婦見我還，便掃車馬跡。", "何以掃馬跡，實亦畏他客。", "我輩唯適情，一葉未嘗摘。", "他人或所至，生菓不得惜。", "又憶遊嵩山，勝趣無不索。", "各具一壺酒，各蠟一雙屐。", "登危相扶牽，遇平相笑噱。", "石搗雲衣輕，巖裂天窗窄。", "上飲醒心泉，高巔溜寒液。", "下看峯半雨，廣甸飛甘澤。", "夜宿岳頂寺，明月入戶白。", "分吟露氣冷，猛酌面易赤。", "明朝循歸途，兩脛痛若剌。", "日旰就馬乘，香草路迫阨。", "却望峻極居，已與天外隔。", "薄暮投少林，漱濯整冠幘。", "碑觀巡幸僧，指古定空壁。", "誓將新詠章，燈前互詆擿。"]'),
('1226e74c-655b-47b9-903a-c4a45e371b2c','送謝師直秘丞通判莫州兼寄張和叔','梅堯臣','宋','宋诗','song-poetry','','[]','河湟宿兵地，勁勇天下聞。',144,'全唐诗/poet.song.15000.json','["河湟宿兵地，勁勇天下聞。", "侵疆古甚熾，薄伐詩所云。", "往今勢且異，利害理頗分。", "遠以塘設險，遂輕甲屯雲。", "昔傳嘗膽國，能破怒蛙軍。", "越雖隔大江，吳遭若枯焚。", "實由持阻懈，抉目悲伍員。", "夫子負美才，議論高不羣。", "況有令兄弟，今亦貳河汾。", "助守戒不虞，慎勿倚和獯。", "張侯爲刺史，大族獨此君。", "法明而不苛，可共飾以文。"]'),
('0df68c7a-06b1-411f-9860-ddc0a5b143da','送白秀才福州省親','梅堯臣','宋','宋诗','song-poetry','','[]','士憂行不脩，不憂祿不及。',96,'全唐诗/poet.song.15000.json','["士憂行不脩，不憂祿不及。", "之子久好學，何患名未立。", "聖時開賢科，子獨不肯入。", "固非遠仕進，服期難赴集。", "南歸慰親顔，道路正暑濕。", "悠悠幾千里，赤日薄行笠。", "暫憩青林下，頼有寒泉汲。", "漱齒去塵埃，土風須漸襲。"]'),
('6dbc37dd-99da-4f9d-b284-1f36d378d639','送溫州楚屯田','梅堯臣','宋','宋诗','song-poetry','','[]','雁蕩山頭鴈，如隨太守來。',48,'全唐诗/poet.song.15000.json','["雁蕩山頭鴈，如隨太守來。", "秋風既與至，春日定同迴。", "上宰無忘舊，明時必用才。", "自於章句老，經冊向螢開。"]'),
('4b57ec2e-3995-4e10-aa6b-38438e5806e6','送僧在己歸秀州','梅堯臣','宋','宋诗','song-poetry','','[]','前歲嘉興火，僧居化刼灰。',48,'全唐诗/poet.song.15000.json','["前歲嘉興火，僧居化刼灰。", "四方持鉢去，千里渡江來。", "心向王城講，緣從海客迴。", "水天聞唳鶴，不復有塵埃。"]'),
('2b739426-4b6c-4173-af78-f3051b4b129a','送祖印大師顯忠','梅堯臣','宋','宋诗','song-poetry','','[]','黄紙賜祖印，鑄名不鑄金。',48,'全唐诗/poet.song.15000.json','["黄紙賜祖印，鑄名不鑄金。", "力笑蘇季子，責望小人深。", "渡江見海月，秋光上遥林。", "團團冰玉盤，瑩然如禪心。"]'),
('c2979758-1c3e-4179-b1fd-f78af4e0d53a','題譯經院同文軒','梅堯臣','宋','宋诗','song-poetry','','[]','有書無異文，有車無異軌。',48,'全唐诗/poet.song.15000.json','["有書無異文，有車無異軌。", "貝多得旁行，白馬來萬里。", "清軒延高僧，一歲譯幾紙。", "譯罷坐焚香，庭草洒寒水。"]'),
('631e69b0-ef8c-4489-ba25-053f80a0a508','和江鄰幾學士得雷殿直墨竹二軸','梅堯臣','宋','宋诗','song-poetry','','[]','昔見雷子之小篆，今見雷子之墨竹。',96,'全唐诗/poet.song.15000.json','["昔見雷子之小篆，今見雷子之墨竹。", "節瘦已似蛟龍孫，葉暗曾無鳳皇宿。", "江翁得之尤愛憐，作詩寫意酬雙軸。", "掛在空堂坐卧看，如玩蕭蕭巖畔綠。", "莫疑昏黑眼生花，松煤濃色切寒鴉。", "不問主人兼客至，明朝騎馬到君家。"]'),
('0175a4f2-25a1-4034-80b6-1afb1fa2f480','永叔內翰見過','梅堯臣','宋','宋诗','song-poetry','','[]','我居城東隅，地僻車馬少。',108,'全唐诗/poet.song.15000.json','["我居城東隅，地僻車馬少。", "忽聞大尹來，僮僕若驚鳥。", "入門且坐笑，豐頰光皎皎。", "問我餐若何，依舊抱糜麨。", "問我詩若何，亦未離纏繞。", "我庭有蔾莧，不堪秣腰褭。", "我壺無醪醴，不能犒介紹。", "乃喜百事稀，來此與世矯。", "固非傲不往，心實厭擾擾。"]'),
('8602e181-04c0-4ba8-9f63-a12a9613112a','韓子華內翰見過','梅堯臣','宋','宋诗','song-poetry','','[]','但見公軒過，未見我馬去。',108,'全唐诗/poet.song.15000.json','["但見公軒過，未見我馬去。", "我懶宜我嫌，公曾不我惡。", "秋雨天街凉，蕭蕭綠槐樹。", "遥聽高車聲，騶導門前駐。", "僕夫驚入扉，遽曰能來顧。", "度量何其宏，始終不改遇。", "索以新詩章，徧覽日欲暮。", "誠慙兜離音，唐突韶與濩。", "明朝當負荆，人莫譏貴附。"]'),
('1f9d47f7-3337-49c6-a505-2827684326ab','送董察推赴江寧','梅堯臣','宋','宋诗','song-poetry','','[]','金陵從事去，不歎食無魚。',48,'全唐诗/poet.song.15000.json','["金陵從事去，不歎食無魚。", "尺鯉日登俎，故鄉時得書。", "衰荷摘短袂，秋蘚曳長裾。", "若見府公問，年來懶更疎。"]'),
('fe94ea05-cf94-4a57-a422-fdc528d01289','次韻和司馬君實同錢君倚二學士見過','梅堯臣','宋','宋诗','song-poetry','','[]','棲棲太學官，日厭塵坌積。',108,'全唐诗/poet.song.15000.json','["棲棲太學官，日厭塵坌積。", "朋游絕經過，都未昧相識。", "幸得養疎慵，不能事役役。", "天京二賢佐，向晚忽來覿。", "笑我似盧仝，環然空四壁。", "只欠長鬚奴，訴尹惡少摘。", "移榻近簷楹，談詩俄至夕。", "迴車閭巷隘，跛馬愁所歷。", "明朝看蒼苔，已覺生轍跡。"]'),
('031a68ba-53d4-4e28-afa8-b0cbaf625614','次韻和錢君倚同司馬君實二學士見過','梅堯臣','宋','宋诗','song-poetry','','[]','府僚忽方駕，乃知决訟餘。',120,'全唐诗/poet.song.15000.json','["府僚忽方駕，乃知决訟餘。", "大尹不苛察，羣吏不牽拘。", "嘗稱二三賢，助治無偏隅。", "新晴乘此凉，行行過我居。", "何以延君子，唯有滿牀書。", "何以解君頤，淡句無足娛。", "何以留君久，燈燭已照塗。", "登車莫言遠，騶從美且都。", "夾道行人止，按轡寧馳驅。", "我老焉所羨，送子立躊躇。"]'),
('33c693c7-0dea-4cd9-9203-5aace3bf251a','送閬州駐泊荆供奉','梅堯臣','宋','宋诗','song-poetry','','[]','青天不可上，蜀道未嘗行。',48,'全唐诗/poet.song.15000.json','["青天不可上，蜀道未嘗行。", "每說褒斜險，唯聞猿鳥聲。", "去爲千里客，自握一方兵。", "所重恩威立，無將遠戍輕。"]'),
('914c8b03-c533-4b15-a6f9-02533fd6dcd3','江鄰幾沈文通二學士見過','梅堯臣','宋','宋诗','song-poetry','','[]','東城車馬多，巷無蹄與轍。',120,'全唐诗/poet.song.15000.json','["東城車馬多，巷無蹄與轍。", "如何二賢豪，侵晨顧衰苶。", "喜言雨後凉，早暮脫炎熱。", "愛子屋室靜，塵土都已絕。", "不唯清耳目，亦粗養愚拙。", "江碑讀頭陁，沈賦賞雌霓。", "固知世德高，學問冠時哲。", "我慙於其間，荆華參蟻蛭。", "然推鵬鷃分，自足不少別。", "君歸邀此吟，把筆强搜抉。"]'),
('b5886b02-f990-4efa-be63-69f680e2af9b','送壽州司理張元輿','梅堯臣','宋','宋诗','song-poetry','','[]','清川夜流明月光，城上有烏啼女牆。',128,'全唐诗/poet.song.15000.json','["清川夜流明月光，城上有烏啼女牆。", "月明不掩斗與氣，鳥啼未歸雲點霜。", "霜寒月冷古時獄，下有苔蠹之雄鋩。", "水方軒眉大靈智，見我西北天門傍。", "自言昔有切玉寶，嗟今非後百鍊鋼。", "用之補履亦何益，穎脫未如錐處囊。", "誰能爲封華陰土，背負七星生焜煌。", "君去味我書此意，莫歎淮水來湯湯。"]'),
('30b8fe94-5ba1-483d-b812-abc17ed4ee37','吳長文紫微見過','梅堯臣','宋','宋诗','song-poetry','','[]','豈敢以貧賤，而輙傲賢貴。',120,'全唐诗/poet.song.15000.json','["豈敢以貧賤，而輙傲賢貴。", "但恨門闌遥，赫日去可畏。", "瘦馬汗常流，寸步出無謂。", "是以逾十旬，景慕腸欲沸。", "近因秋雨來，纖纖有凉氣。", "九陌可以行，輕服可以衣。", "方將事請見，瘡足痛若䠊。", "忽枉騶騎過，顔厚言莫既。", "尚期新醪熟，還往襲經緯。", "乃知君子德，曩分替則未。"]'),
('aa7b10ea-268f-47ba-aef9-5a1425c9d4e9','范景仁紫微見過亦謁不遇道上逢之','梅堯臣','宋','宋诗','song-poetry','','[]','朝游翔鳳池，暮直中書省。',132,'全唐诗/poet.song.15000.json','["朝游翔鳳池，暮直中書省。", "無由見顔色，況乃當畏景。", "退朝八月朔，因得修造請。", "高閎一何新，未歸閭巷靜。", "版刺留姓名，不遑佇軒屏。", "驅馬返我廬，道逢騶從整。", "斂轡莫敢行，顧望立俄頃。", "還家稚子言，有車來炳炳。", "傳是紫微人，將迴猶引領。", "如何互相乖，徒自想形影。", "更待秋風高，緩步時往省。"]'),
('bac435a1-f413-40f2-96c4-828db097fc3c','送王道粹學士知亳州','梅堯臣','宋','宋诗','song-poetry','','[]','古者二千石，高車駕青驪。',180,'全唐诗/poet.song.15000.json','["古者二千石，高車駕青驪。", "車前陳曲蓋，車後建朱旗。", "金鼓鳴兩旁，壺漿擁通逵。", "所付重威惠，所仰撫惸嫠。", "景亳實鉅屏，往俾國相之。", "國相稱疾還，正值民阻饑。", "朝廷急恤養，選守莫與宜。", "君嘗典海陵，政績爲衆推。", "今授輙辭命，大夫多飛綏。", "屢上不得請，飭馭俄輕齎。", "既體堯舜仁，又答稷禼知。", "八月風漸高，木葉將披披。", "郊原棗已剝，場圃黍可治。", "必期寬賦斂，無乃息疲羸。", "何當過苦縣，肯暇觀舊碑。"]'),
('222efbbe-2d17-4323-98f8-42a0c1493d22','和江鄰幾學士畫鬼拔河篇','梅堯臣','宋','宋诗','song-poetry','','[]','蒲中古寺壁畫古，畫者隋代展子虔。',208,'全唐诗/poet.song.15000.json','["蒲中古寺壁畫古，畫者隋代展子虔。", "分明八鬼拔河戲，中建二旗觀却前。", "東廂四鬼苦用力，索尾拽斷一鬼顛。", "西廂四鬼來背挽，雙手搥下抵以肩。", "龍頭魚身霹靂使，持鉞植立旗左偏。", "拔山夜叉右握斧，各司勝負如爭先。", "兩旁撾鼓鼓四面，聲勢助勇努眼圓。", "臂梟張拳擊捧首，似與暴謔意態全。", "當正大鬼按膝坐，三鬼带韣一執旃。", "操刀擐囊力指督，怒髮上直筋舊纏。", "虎尾人身又踣顧，蒺蔾短挺金鎚堅。", "高下尊卑二十四，二十四鬼無黄泉。", "角雄競强欲何覩，曷不各各還荒埏。"]'),
('d8da1e38-c36f-474e-b7f8-907ee5ac2ba1','送制置發運唐子方學士','梅堯臣','宋','宋诗','song-poetry','','[]','本以諫諍稱，今以財賦用。',108,'全唐诗/poet.song.15000.json','["本以諫諍稱，今以財賦用。", "所爲各有能，何必於茲重。", "東南周萬里，海陸竭煑種。", "斂之爲公上，豈是與民共。", "民方苦久弊，將缺太平頌。", "有利得設施，無不可抑縱。", "大都守繩墨，曷異虱處縫。", "從來許國心，曾未苟祿俸。", "願無輸羨餘，終亦歸侍從。"]'),
('97788a41-d4f9-4484-bd97-d61c2a772ece','次韻和司馬學士慮囚','梅堯臣','宋','宋诗','song-poetry','','[]','縲囚往慮問，勤恤意不息。',204,'全唐诗/poet.song.15000.json','["縲囚往慮問，勤恤意不息。", "猛虎在陷穽，挑尾尚求食。", "常憂有詿誤，非罪罹暴迫。", "藹藹萬乘都，憧憧四方客。", "一遭纖微釁，鑑垢莫磨拭。", "是以大君心，惟恐橫抵摘。", "前法著以律，後法編以冊。", "每當炎蒸時，獄器用刷滌。", "應無古冤血，地下化爲碧。", "我今因牽吟，聊以肝膽瀝。", "刑人皆得辜，不似尤地脈。", "間歸即解鞍，浣手嫌控靮。", "昔言善烹魚，必先溉釜鬲。", "願言保兢慎，切勿厭此役。", "夜月可留翫，清樽可獨適。", "一榻寬且平，羣動都已寂。", "可用休其勞，不休庶終夕。"]'),
('fb155c55-9d12-4d23-b2c7-7753d57f1762','和吳沖卿江鄰幾二學士王景彝舍人秋興','梅堯臣','宋','宋诗','song-poetry','','[]','我謂蓬瀛客，清切不畏炎。',216,'全唐诗/poet.song.15000.json','["我謂蓬瀛客，清切不畏炎。", "及觀秋興篇，無遠此窮閻。", "乃知天地大，節候無愛嫌。", "寒不爲富減，暑不爲貧添。", "向者遭蒸炊，靡不同炮燖。", "西風吹雨至，凉氣何纖纖。", "霈然沃萬物，不更畢宿占。", "紈扇捉苦倦，盤冰得仍厭。", "蠅癡驅又來，蚊嚵喙猶尖。", "絺衣不復浹，醅醪壓初甜。", "客有憎壁蝎，客有困靴襜。", "一以磔爲喜，一以嬾自謙。", "唯有螭頭人，朝立宮殿簷。", "盛誇樓觀高，又極星斗瞻。", "予慙異羣公，歸意如陶潛。", "自念菊將坼，復思禾可鎌。", "舂禾作釀熟，獨邀影與蟾。", "此樂雖易有，彼榮安得兼。"]'),
('f9d4cb86-4cb4-4de4-8057-df123bbe34c4','送覺上人歸湖州','梅堯臣','宋','宋诗','song-poetry','','[]','古寺一盂飯，弊衣三歲塵。',48,'全唐诗/poet.song.15000.json','["古寺一盂飯，弊衣三歲塵。", "相應維帝祝，子已得袍新。", "范叔復何望，原生甘自貧。", "歸看五湖上，終有泛舟人。"]'),
('d15b76e0-5224-42fe-ad23-dd5917025570','送陝西提刑陸介夫學士','梅堯臣','宋','宋诗','song-poetry','','[]','輕車馳入關，秋色秦山厚。',72,'全唐诗/poet.song.15000.json','["輕車馳入關，秋色秦山厚。", "太華如相欣，高峯招以手。", "千古此路中，豈不名宦有。", "何日歷隴城，舊羌迎馬首。", "銅盤薦酥酪，皮服行牛酒。", "邊風與邊月，冷落諳應久。"]'),
('36bbf152-4090-4272-b337-5f5250dc09a8','送閔郎中知池州','梅堯臣','宋','宋诗','song-poetry','','[]','一送池陽守，頗懷當日遊。',48,'全唐诗/poet.song.15000.json','["一送池陽守，頗懷當日遊。", "青山臨岸盡，翠水入江流。", "楚舊茅爲貢，燕來雁報秋。", "牧之登覽處，故事待君修。"]'),
('32695cb7-df99-428c-bc55-7cf3cc514c5d','和吳沖卿學士省中植菊','梅堯臣','宋','宋诗','song-poetry','','[]','園菓已熟實未墜，野卉已老葉未瘁。',144,'全唐诗/poet.song.15000.json','["園菓已熟實未墜，野卉已老葉未瘁。", "菊叢是時方發榮，潭上籬邊俱有爲。", "一從潭島輔長年，一自籬根圖暫醉。", "今將移近省中蘭，壅培早與陶潛異。", "黄土肥濃沃井泉，朱欄屈曲侵堦地。", "勁風不到何動摇，清露能霑誰著意。", "看看重九各登高，金蕊滿頭無所忌。", "及此頻邀同舍歡，向來莫羨鍾繇賜。", "我家蓬藋不足云，强對嘉章顔起愧。"]'),
('58d96e81-606f-475f-9a2a-e06fdbab77a0','張仲通追賦洛中雜題和嘗歷覽者六章 伊川','梅堯臣','宋','宋诗','song-poetry','','[]','山斷瀉伊流，灘聲朝暮急。',48,'全唐诗/poet.song.15000.json','["山斷瀉伊流，灘聲朝暮急。", "東渡馬將登，西堤人已立。", "日看東西舟，爭途如不及。", "誰見捕魚郎，寒蓑雨中濕。"]'),
('4d9e004d-b605-40b0-aeba-fad492ddf928','張仲通追賦洛中雜題和嘗歷覽者六章 洛州','梅堯臣','宋','宋诗','song-poetry','','[]','上陽宮樹影，不隨寒波流。',48,'全唐诗/poet.song.15000.json','["上陽宮樹影，不隨寒波流。", "天津橋下石，激響無時休。", "至清自照物，遇險豈能柔。", "東過白馬去，凡經幾千秋。"]'),
('1576785a-d51a-410d-9995-2594cf2f96ab','張仲通追賦洛中雜題和嘗歷覽者六章 潛溪','梅堯臣','宋','宋诗','song-poetry','','[]','寒溪隨山迴，脩竹隠深寺。',48,'全唐诗/poet.song.15000.json','["寒溪隨山迴，脩竹隠深寺。", "頗逢老僧談，能憶先到事。", "白栝聖君憐，緋花土人蒔。", "不到三十秋，依稀猶可記。"]'),
('a0c1aeec-7ff9-43cd-bf13-f79c749b2cf6','張仲通追賦洛中雜題和嘗歷覽者六章 石樓','梅堯臣','宋','宋诗','song-poetry','','[]','山腰古石樓，杳藹石梯上。',48,'全唐诗/poet.song.15000.json','["山腰古石樓，杳藹石梯上。", "低窺巖際樹，對見龕中像。", "簷中嵩雲飛，檻逼伊湍響。", "同遊已零落，歲月成俯仰。"]'),
('225facc2-6daa-42c2-9aee-c99bbc323f2d','張仲通追賦洛中雜題和嘗歷覽者六章 大字寺','梅堯臣','宋','宋诗','song-poetry','','[]','庭中兩大樹，池上千竿竹。',48,'全唐诗/poet.song.15000.json','["庭中兩大樹，池上千竿竹。", "竹有紅淚班，樹無衆鳥宿。", "昔日白傅歸，愛吟裴令續。", "間流水西園，翻然入他族。"]'),
('2e388823-f327-480b-9012-142f93ce1c9f','張仲通追賦洛中雜題和嘗歷覽者六章 蘄竹','梅堯臣','宋','宋诗','song-poetry','','[]','顋肥節腦瘦，蘄水長笛材。',48,'全唐诗/poet.song.15000.json','["顋肥節腦瘦，蘄水長笛材。", "洛陽袁氏塢，此竹舊移來。", "雪霰飽已久，竅星誰爲開。", "與君作龍吟，吹發江南梅。"]'),
('3c96fd03-11d2-4773-924b-d3658f800c83','次韻任屯田感子飛內翰舊詩','梅堯臣','宋','宋诗','song-poetry','','[]','二十四年君日哦，翰林風韻郢中歌。',96,'全唐诗/poet.song.15000.json','["二十四年君日哦，翰林風韻郢中歌。", "歲華荏苒都如昨，世事升沈亦苦多。", "燕國駿蹄猶待樂，荆山美寶已逢和。", "賸求海內多何用，爛醉人間理莫過。", "歷覽昔賢皆泯泯，尋思魯叟自波波。", "我今不敢希高躅，蹇步年來任跌𧿶。"]'),
('8f82dfbc-d8b5-48c2-85e9-5c51e24ea7f0','次韻答德化尉郭功甫遂以送之','梅堯臣','宋','宋诗','song-poetry','','[]','江南有嘉禽，乘春弄清吭。',264,'全唐诗/poet.song.15000.json','["江南有嘉禽，乘春弄清吭。", "流音入我耳，慰愜若獲貺。", "朝聽已孤高，暮聽轉幽曠。", "何多燕雀羣，聲跡不相傍。", "始聞汾陽生，文行衆所諒。", "獨哦青山間，悼古或悲愴。", "棄官不屈人，頗學陶元亮。", "是時予愛之，顔采莫得望。", "倏然能見過，遠涉丹湖浪。", "袖携一卷詩，行橐更無長。", "固與俗人殊，於焉識敦尚。", "嗟嗟二千石，不知子所向。", "駭子發論高，萬仞聳孤嶂。", "又如决河湍，捧土安可障。", "吾方歎瓌材，恨未逢良匠。", "信哉騏驥駒，誰用伯樂相。", "自從昔還朝，汩汩走俗狀。", "未嘗寄子書，子言今行行。", "亦似昧相知，曾非事高閌。", "把筆誠不勤，强意乃爲妄。", "茲晨去湓城，聊以和子唱。", "子辭猶瀑布，敢挹不知量。"]'),
('b5723249-9cab-447b-bf7b-31860eca39ae','送李師錫太博通判懷州','梅堯臣','宋','宋诗','song-poetry','','[]','洛陽古道登北邙，河內碧山橫太行。',64,'全唐诗/poet.song.15000.json','["洛陽古道登北邙，河內碧山橫太行。", "朝騎快馬暮可到，風物人心皆故鄉。", "竹林無蹤懷阮籍，路傍有家嗟宣王。", "別乘差同二千石，教民惟在親耕桑。"]'),
('7757d0f8-3bc1-4d92-aeeb-fd17aa3b3b59','送潘士方建昌','梅堯臣','宋','宋诗','song-poetry','','[]','軍壘近仙山，麻源第三谷。',108,'全唐诗/poet.song.15000.json','["軍壘近仙山，麻源第三谷。", "靈運詩亦存，魯公記可讀。", "幸時無寇攘，閑日望雲木。", "儻見西王母，白麟如白鹿。", "來尋鳥爪人，神光生石屋。", "無念癢背搔，還恐罹怒扑。", "學道我未成，鍊氣不飽腹。", "安得羽翼生，下上同黄鵠。", "送君想君遊，星斗壇邊竹。"]'),
('3a8efeb6-ffbd-421f-a6cc-40d68c79ccaa','次韻和吳仲庶舍人送德化郭尉','梅堯臣','宋','宋诗','song-poetry','','[]','蒲葉高帆十二幅，秋風逆水滿檣開。',64,'全唐诗/poet.song.15000.json','["蒲葉高帆十二幅，秋風逆水滿檣開。", "是時不畏浪頭起，到日定將船尾堆。", "用捨東方言虎鼠，賤疎梅福比蒿萊。", "少年才辨無如美，廬岳峯前莫滯迴。"]'),
('aeb55fd8-9ad6-49c0-8c5a-d2f95b5be45b','和劉原父舍人樂郊詩','梅堯臣','宋','宋诗','song-poetry','','[]','太守東平來，固殊阮步兵。',168,'全唐诗/poet.song.15000.json','["太守東平來，固殊阮步兵。", "步兵醉乘馿，太守整佩纓。", "事物既已遺，駕車出東城。", "園荒久不治，道路生棘荆。", "地僻人馬入，草間狐兔驚。", "舊池堙猶窊，遺址巋不平。", "窊者使之濬，巋者使之營。", "博野高榭起，陳漁危臺成。", "榭前東山秀，臺下盧泉清。", "傍塢梧竹暗，翳水芹藻并。", "渠渠有深堂，燕賓飛玉觥。", "芍藥廣陵美，謔贈鄭女情。", "公子莫言歸，古人未以輕。", "欲知學山簡，倒載去欹傾。"]'),
('7c75edc5-69d6-4673-b5bc-283a51a3b653','送張聖民學士知登州','梅堯臣','宋','宋诗','song-poetry','','[]','慕君才行美，風義亦倜儻。',192,'全唐诗/poet.song.15000.json','["慕君才行美，風義亦倜儻。", "在遠恨未逢，既近不屢往。", "非以近爲輕，恃易遂成曩。", "倏爲東牟守，別我駐征鞅。", "又作千里遥，依然復懷想。", "昔聞之罘山，秦碑元有兩。", "一存東頂中，一在西頂上。", "篆實丞相斯，缺剝不可倣。", "願言試歷覽，聞見欲以廣。", "海晴望石橋，神仙事惝怳。", "始皇安得長，陰怪役罔象。", "橋斷水無涯，焉知有方丈。", "邇者地出金，發掘懷沃壤。", "良民皆逐末，茲事誰用長。", "凡爲二千石，唯在勸耕紡。", "幸君經術高，教化人所仰。"]'),
('6d01c15b-56a7-4049-bb64-bf104a3fdc7e','送王言秀才歸建昌','梅堯臣','宋','宋诗','song-poetry','','[]','來時槐開花，去日木隕葉。',48,'全唐诗/poet.song.15000.json','["來時槐開花，去日木隕葉。", "作賦未得薦，著書已盈篋。", "舊居近仙壇，獨往遇農饁。", "莫問鳥爪人，欲取月桂捷。"]'),
('eab95583-ef08-4e74-8de9-a24a7076ed88','次韻和劉原甫遊樂郊贈同遊','梅堯臣','宋','宋诗','song-poetry','','[]','積歲阻顔色，何以慰我思。',120,'全唐诗/poet.song.15000.json','["積歲阻顔色，何以慰我思。", "聞初遊樂郊，頗慕登望詩。", "下車未幾日，倏見白露滋。", "月弦不常滿，星畢屢已離。", "幸無風雨晦，時從寮寀嬉。", "大喜酒客難，莫顧尚書期。", "獨守詩書愚，未悟朝夕疲。", "引領君子風，東首自忘移。", "但當觀魚鳥，辟去旄與麾。", "優悠民亦康，何必苦吏爲。"]'),
('740479d1-193b-40f6-946a-83474af01725','次韻和王尚書答贈宣城花木瓜十韻','梅堯臣','宋','宋诗','song-poetry','','[]','百菓各甘酸，或由人所植。',120,'全唐诗/poet.song.15000.json','["百菓各甘酸，或由人所植。", "木瓜聞衛詩，贈好非玉色。", "投此瓊玖報，蓋重車馬飾。", "貴賤今既殊，凌紙字翕赩。", "一一如明珠，自得見安格。", "復何備國風，庶亦見王澤。", "捧之爲重賜，誦已乃忘食。", "幸資藥品用，少助宣調力。", "南土加文章，中州異肥瘠。", "公將和鼎餗，微意願尋繹。"]'),
('9c1e86b9-e645-4d41-88d1-d16968a21e2e','九月晦日謁韓子華遂留邀江鄰幾同飲是夕值其內宿不終席明日有詩予次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','乘興驅車偶一來，旋呼江老舊遊陪。',64,'全唐诗/poet.song.15000.json','["乘興驅車偶一來，旋呼江老舊遊陪。", "驚風送雨寒初動，舉酒浮蛆撥不開。", "騏驥鞴時聞內宿，琵琶彈急怨虛催。", "按籬带去令傳樣，自此逢歡未便迴。"]'),
('3c900f1e-ab65-4f81-abed-a804735fccae','送王省副寶臣北使','梅堯臣','宋','宋诗','song-poetry','','[]','紫服黄金带，銀鞍翠錦韉。',48,'全唐诗/poet.song.15000.json','["紫服黄金带，銀鞍翠錦韉。", "犯寒辭漢省，持禮入胡天。", "左袵通華語，名王接右賢。", "舊山迴可記，碣石與燕然。"]'),
('89d63f8e-9efd-420b-8c1f-3fb4eb8801e3','送李學士公達北使','梅堯臣','宋','宋诗','song-poetry','','[]','萬里使窮域，山川入馬蹄。',48,'全唐诗/poet.song.15000.json','["萬里使窮域，山川入馬蹄。", "駞鳴沙水凍，鵰擊雪雲低。", "食飲羊兼酪，供迎虜雜奚。", "禮成迴近日，喜聽早期雞。"]'),
('f640d250-6129-481d-ad3e-ce78b79b09f5','送祖擇之學士北使','梅堯臣','宋','宋诗','song-poetry','','[]','燕山常苦寒，漢使涉窮臘。',108,'全唐诗/poet.song.15000.json','["燕山常苦寒，漢使涉窮臘。", "路長人馬愁，風急沙霰雜。", "宿造氊廬開，行逢獵騎合。", "獻鮮禿髮馳，問譯華言答。", "每食冰生盤，欲飲酒凍榼。", "見其酋長時，國禮何勤納。", "中朝厚仁恩，四海望閶闔。", "乃知日月光，照必蠻夷匝。", "歸來易輕裘，賜對延英閤。"]'),
('8dd32bc5-1285-4637-a181-18fd45856e5a','送許璋監簿歸泰州','梅堯臣','宋','宋诗','song-poetry','','[]','木枯鳥不巢，泉涸魚不游。',120,'全唐诗/poet.song.15000.json','["木枯鳥不巢，泉涸魚不游。", "我非魚鳥情，貧縛路阻脩。", "高陽有令子，嗣世學已優。", "前日來京城，問恤忍涕流。", "今失王府薦，命奇言非讎。", "家聲喜未墜，辭我還海陬。", "爲酌一壺酒，敘懷心如抽。", "子之伯父歿，遣奠固莫由。", "豈欲寡恩義，力薄難置郵。", "因寄緣睫淚，洒向君衣裘。"]'),
('b2f491ac-5f57-4069-997f-cd6eff9f38fc','送棣州唐虞部','梅堯臣','宋','宋诗','song-poetry','','[]','人持左符去，馬逆北風行。',48,'全唐诗/poet.song.15000.json','["人持左符去，馬逆北風行。", "古路草初白，大河冰未成。", "暖科桑柘美，寒織杼梭鳴。", "風俗已如此，憩棠無訟爭。"]'),
('c90a04ad-42b5-4eaf-ab52-9f989f8d2747','金陵有美堂','梅堯臣','宋','宋诗','song-poetry','','[]','李白愛山如洛陽，三盃爲歌愁日長。',96,'全唐诗/poet.song.15000.json','["李白愛山如洛陽，三盃爲歌愁日長。", "廢基臺殿不可識，玉燕舊棲王謝堂。", "公來碧瓦起棟宇，羅列圖畫牙作牀。", "池頭古月城下江，照見萬里冰雪光。", "江流不盡月不死，寒浪素影東西翔。", "願公樂此殊未央，慎勿區區思故鄉。"]'),
('392c0d0e-70d5-47af-886d-8607fd8728a6','送張中樂屯田知永州','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','畏向瀟湘行，不入洞庭去。',132,'全唐诗/poet.song.15000.json','["畏向瀟湘行，不入洞庭去。", "鞍馬踏關山，衣裘冒霜露。", "零陵三千里，楚俗未改故。", "王澤久已覃，國刑亦當措。", "昔聞柳宗元，山水尋不飫。", "其記若丹青，因來問潭步。", "石燕飛有無，香草生觸處。", "仙姑異麻姑，歲月樓中度。", "不食顔渥赭，言語神靈預。", "莫將車騎喧，獨往探幽趣。", "有信報我知，惡欲驅塵慮。"]'),
('91892caf-6398-4e41-bc78-447ecfcd8174','陽武王安之寄石榴','梅堯臣','宋','宋诗','song-poetry','','[]','安榴若拳石，中藴丹砂粒。',84,'全唐诗/poet.song.15000.json','["安榴若拳石，中藴丹砂粒。", "割之珠落盤，不待蛟人泣。", "舊友大河濱，作宰實畿邑。", "嚴霜百果熟，爲贈忽我及。", "始時童稚嬌，爭取猴猿集。", "老夫所食微，何假更收拾。", "聊答君意勤，作詩恨短澀。"]'),
('91a9c0ba-20c6-4c61-90f5-1014e5f6e0b3','寄致仕余少卿','梅堯臣','宋','宋诗','song-poetry','','[]','仕苦戀朝廷，多爲老所逼。',60,'全唐诗/poet.song.15000.json','["仕苦戀朝廷，多爲老所逼。", "朝廷雖愛賢，不欲竭其力。", "君歸頗得宜，湖上遂偃息。", "男能智自謀，孫亦俛就職。", "人事當置之，自可樂胸臆。"]'),
('95505ab0-1205-4e52-a841-8786712673a0','和吳沖卿學士冬日私居事','梅堯臣','宋','宋诗','song-poetry','','[]','人知何晏宅，近住白楊頭。',48,'全唐诗/poet.song.15000.json','["人知何晏宅，近住白楊頭。", "車馬不還往，詩書多蓄收。", "風庭吹落葉，霜樹立鳴鳩。", "頗與市朝遠，閉門凡幾秋。"]'),
('2ea6ce20-866f-4ee1-9c74-f02c51a79cd1','和吳沖卿藏菜','梅堯臣','宋','宋诗','song-poetry','','[]','霜前收美菜，欲以禦冬時。',48,'全唐诗/poet.song.15000.json','["霜前收美菜，欲以禦冬時。", "備乏且增品，挑新那復思。", "菖葅嗜西伯，薑食語宣尼。", "未免效流俗，競將罌盆爲。"]'),
('a0ec1207-60c2-4d0c-b977-6d9152065a8a','依韻和王景彝學士紫宸仲冬早謁','梅堯臣','宋','宋诗','song-poetry','','[]','朝開閶闔九重深，望拜珠旒照玉簪。',64,'全唐诗/poet.song.15000.json','["朝開閶闔九重深，望拜珠旒照玉簪。", "霜氣稍迴龍陛峻，日光微轉鳳樓陰。", "庭中細仗穿旗脚，案外薰爐對殿心。", "我預千官少裨補，欲將歌頌播堯音。"]'),
('d6fc6cb2-e306-48f3-a443-03703124cf48','依韻答景彝謝予訪其居','梅堯臣','宋','宋诗','song-poetry','','[]','日暮乘羸馬，因過太史家。',48,'全唐诗/poet.song.15000.json','["日暮乘羸馬，因過太史家。", "竹窗談脫麈，槐樹暝栖鴉。", "邦瘁稽前詠，人亡起彼嗟。", "夜分歸不寐，猶照角巾斜。"]'),
('f5100ac3-8adf-49e9-96f0-5c74a3b4e86c','哀石昌言舍人  其一','梅堯臣','宋','宋诗','song-poetry','','[]','朔日望顔色，衣冠朝帝閽。',48,'全唐诗/poet.song.15000.json','["朔日望顔色，衣冠朝帝閽。", "西靈未生魄，東岱已收魂。", "弔哭新居啟，封題舊篋存。", "善人吾不見，何可問乾坤。"]'),
('2c189565-536a-48ef-a7d6-ef4bc7df44ac','哀石昌言舍人  其二','梅堯臣','宋','宋诗','song-poetry','','[]','聖賢無不死，壽夭復何云。',48,'全唐诗/poet.song.15000.json','["聖賢無不死，壽夭復何云。", "唯有名常在，其餘理莫分。", "朝榮金玉寶，莫殞蕙蘭焚。", "今日寢門哭，緒言長絕君。"]'),
('55249d1a-dd3a-47b2-89b8-eafe81071e79','哀石昌言舍人  其三','梅堯臣','宋','宋诗','song-poetry','','[]','賈誼過秦畢，相如諭蜀歸。',48,'全唐诗/poet.song.15000.json','["賈誼過秦畢，相如諭蜀歸。", "二人名既大，一日命何微。", "痟似烏常渴，災成鵩不飛。", "百年今已矣，冰結淚霑衣。"]'),
('a720f6e1-b542-4505-a9ec-4793276e87f3','鄭州王密諫漱玉齋','梅堯臣','宋','宋诗','song-poetry','','[]','渠渠梁照日，泯泯水分京。',48,'全唐诗/poet.song.15000.json','["渠渠梁照日，泯泯水分京。", "激作飛巖勢，流爲雜珮聲。", "圖書無近蹟，草樹有冬榮。", "景落人間處，漂花出古城。"]'),
('27754cf6-c4a5-457e-af81-272f74d41016','書李學士北使集後','梅堯臣','宋','宋诗','song-poetry','','[]','蘇武艱窮只四篇，五言風格到今傳。',32,'全唐诗/poet.song.15000.json','["蘇武艱窮只四篇，五言風格到今傳。", "節旄零落都無詠，枉在胡中十九年。"]'),
('c124bdce-5c83-45bc-b518-5ca7b69e1af6','送李學士河東轉運','梅堯臣','宋','宋诗','song-poetry','','[]','重持使者節，北上太行行。',72,'全唐诗/poet.song.15000.json','["重持使者節，北上太行行。", "未注螭頭筆，來賙塞下兵。", "朱轓邦伯至，黄綬縣官迎。", "臘雪臨關密，宵烽出堠明。", "山川壯汾晉，戎馬說幽并。", "此地多才俊，其人不易輕。"]'),
('60ec707c-6eb3-409e-8b0b-51f8ef48eac2','次韻和吳仲庶苗蔡二君村墅閑居','梅堯臣','宋','宋诗','song-poetry','','[]','聞說江南庾子山，卜居泉石愛孱顔。',64,'全唐诗/poet.song.15000.json','["聞說江南庾子山，卜居泉石愛孱顔。", "古來得喪何須問，世上榮枯只等閑。", "高闕浮雲徒有戀，夕陽飛鳥亦知還。", "予貧不及三君子，老愧朝紳進退間。"]'),
('02e328c7-9985-43e2-8cef-a0a421eb5a99','送良玉上人還崑山','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','來衣茶色袍，歸變椹色服。',48,'全唐诗/poet.song.15000.json','["來衣茶色袍，歸變椹色服。", "孤舟洞庭去，落日松江宿。", "水煙晦琴徽，山月上巖屋。", "野童遥相迎，風葉鳴橡槲。"]'),
('8092f715-b65b-4f4b-8773-7b4e8d0126f0','依韻和宋次道學士紫宸早謁','梅堯臣','宋','宋诗','song-poetry','','[]','陸生聲譽在雲間，來預簪裾謁帝顔。',64,'全唐诗/poet.song.15000.json','["陸生聲譽在雲間，來預簪裾謁帝顔。", "冠劍有容夔與禼，文章全盛馬兼班。", "躭躭玉宇龍纏棟，藹藹金鋪獸齧環。", "却出常衙殿前過，戟衣風動自相攀。"]'),
('f2ab6270-75eb-4bef-8378-301e57631425','和次道省中初直','梅堯臣','宋','宋诗','song-poetry','','[]','江南太守歸，夜直省中闈。',48,'全唐诗/poet.song.15000.json','["江南太守歸，夜直省中闈。", "霜氣冷侵被，月光斜入扉。", "官奴休執燭，侍史正薰衣。", "展轉不成寐，幽懷吟更微。"]'),
('f97d5f9d-6f48-4884-87e1-06f8a43b314b','去年宋中道自洺州以書令魏殊來謁予魏遂託主第後辭歸予因中道之兄次道有孔雀賦以送魏生','梅堯臣','宋','宋诗','song-poetry','','[]','置從南海桄榔林，籠入西州鸚鵡地。',96,'全唐诗/poet.song.15000.json','["置從南海桄榔林，籠入西州鸚鵡地。", "聳冠翕翼脩尾張，鱗鱗團花金縷翠。", "一身粲爛文章多，引聲笙竽奈遠何。", "五侯池館不可戀，桂樹深枝自有窠。", "鳳皇樓頭饒燕雀，入屋穿簾非爾樂。", "非爾樂，去何之，北方佳人或歌咢。"]'),
('96eed0b4-4e10-4d26-bdc3-d7937c1e811d','依韻和宋中道見寄','梅堯臣','宋','宋诗','song-poetry','','[]','歲在涒灘初別子，子適廣平裨郡理。',296,'全唐诗/poet.song.15000.json','["歲在涒灘初別子，子適廣平裨郡理。", "廉頗臺傾有遺址，今逢四方弓久弛。", "時不用兵皆樂鄉，念我貧居天子庠。", "抱經臨案空循行，貌垢不洗顔蒼蒼。", "得時少壯相揄揚，獨行無侶心浶浪。", "腸如轆轤轉井床，內饑外寒膚粟芒。", "若此煎炒何心腸。", "王都浩浩多球琅，懷珉安可爭焜煌。", "舊朋升騰皆俊良，歿不發語生括囊。", "巍巍堯舜開明堂，大調金石來鳳皇。", "鴛鴦戟翼方在梁，福祿其宜無不臧。", "已甘老死填溝隍，殭尸闔棺猶目張。", "仲尼生世尚徨徨，豈能强聒爭蹌蹌。", "未由見子舉以觴，北望大河衣袂攘。", "牽牛橫漢不服箱，欲往乘車無可當。", "天駟有星名曰房，又欲乘馬行幽荒。", "牛雖蹄瑩馬眼光，既不我駕路阻長。", "我懷炳炳何日忘，半夜攬琴彈履霜。", "寫意緘辭無雁將，低雲作雪正蒼茫。"]'),
('2e365a56-1d6f-42db-b437-af7ae2aa1be1','次韻和宋中道再寄','梅堯臣','宋','宋诗','song-poetry','','[]','鴻鴈北來聲甚悲，黄昏野雀相並枝。',168,'全唐诗/poet.song.15000.json','["鴻鴈北來聲甚悲，黄昏野雀相並枝。", "是時靜默月色淡，摵摵風草摇枯衰。", "夜深扣門兵卒至，八行文字曾無奇。", "書尾又看詩兩紙，若逢飲食充渴饑。", "駿馬明珠未入用，千金美價思燕隨。", "無鹽嫫母正逞貌，越客未可言西施。", "子雖淹迴年且壯，不比老醜令人嗤。", "朝廷得賢盛朱紫，玉階金闥步委蛇。", "聖君納諫無不聽，吾徒跡遠空行危。", "況乃庭下聞咸池，報書此方君可喜。", "我心如此頗得之。"]'),
('4f2da699-0d81-4a0e-b553-59d3485a6def','雷逸老以倣石鼓文見遺因呈祭酒吳公','梅堯臣','宋','宋诗','song-poetry','','[]','石鼓作自周宣王，宣王發憤蒐岐陽。',384,'全唐诗/poet.song.15000.json','["石鼓作自周宣王，宣王發憤蒐岐陽。", "我車我馬攻既良，射夫其同弓矢張。", "舫舟又漁鱄鱮魴，何以貫之維柳楊。", "從官執筆言成章，書在鼓腰鎸刻臧。", "歷秦漢魏下及唐，無人著眼來形相。", "村童戲坐老死喪，世復一世如鳥翔。", "唯聞元和韓侍郎，始得紙本歌且詳。", "欲以氈苞歸上庠，大官媕阿駞肯將。", "傳至我朝一鼓亡，九鼓缺剝文失行。", "近人偶見安碓床，亡鼓作臼刳中央。", "心喜遺篆猶在傍，以臼易臼庸何傷。", "以石補空恐舂梁，神物會合居一方。", "雷氏有子胡而長，日模月倣志暮强。", "聚完辨舛經星霜，四百六十飛鳳皇。", "書成大軸綠錦裝，偏斜曲直筋肯藏。", "携之謁我巧趨蹌，我無別識心徬徨。", "雖與乃父非故鄉，少與乃父同杯觴。", "老向太學鬢已蒼，樂子好古親縑箱。", "誰能千載師史倉，勤此冷淡何肝腸。", "而今祭酒裨聖皇，五經新石立兩廊。", "我欲效韓非癡狂，載致出關無所障。", "至寶宜列孔子堂，固勝朽版堆屋牆。", "然須雷生往度量，登車裹護今相當。", "誠非急務煩紀綱，太平得有朝廷光。"]'),
('9c22aa5d-b564-42c5-b1e4-3fe4c4011eab','和宋次道奠石昌言舍人','梅堯臣','宋','宋诗','song-poetry','','[]','金羈白馬曉朝天，嘒管行車暮已傳。',64,'全唐诗/poet.song.15000.json','["金羈白馬曉朝天，嘒管行車暮已傳。", "上帝樓成何遽召，青霄路絕不應還。", "飄階隕葉聲淒若，隔幕孤燈夜寂然。", "來奠一觴空湛湛，却思平昔淚漣漣。"]'),
('12ce4753-cc38-425d-bbf2-360f7fe88d0f','和王景彝寄呂縉叔','梅堯臣','宋','宋诗','song-poetry','','[]','白盡髭鬚史未成，不如能賦易登瀛。',64,'全唐诗/poet.song.15000.json','["白盡髭鬚史未成，不如能賦易登瀛。", "三冬足用侏儒飽，千里從看跛鼈行。", "知有清名在公議，自無餘力到高閎。", "磻溪八十猶垂釣，祖例推來亦後生。"]'),
('92829a9d-9251-471d-8dbc-9b97e05c2af0','依韻和宋次道答弟中道喜還朝','梅堯臣','宋','宋诗','song-poetry','','[]','白首謬陪兄弟間，阿連初喜客兒還。',64,'全唐诗/poet.song.15000.json','["白首謬陪兄弟間，阿連初喜客兒還。", "池塘夢句君能得，咳唾成珠我未閑。", "陋巷閉門誰扣扣，茂林飛鳥自班班。", "歸來又接同袍會，月下朱閎不用關。"]'),
('22fbe267-028c-40c1-9012-5cb82da49638','依韻和答王安之因石榴詩見贈','梅堯臣','宋','宋诗','song-poetry','','[]','當年仕宦忘其卑，朝出飲酒夜賦詩。',128,'全唐诗/poet.song.15000.json','["當年仕宦忘其卑，朝出飲酒夜賦詩。", "伊川嵩室恣游覽，爛熳徧歷焉有遺。", "是時交朋最爲盛，連值三相更保釐。", "謝公主盟文變古，歐陽才大何可涯。", "我於其間不量力，豈異鵬摶蒿鷃隨。", "見君弟兄入太學，俊譽籍籍聞一時。", "而今兩鬢各已白，偶因贈酬言及斯。", "升沉是非休要問，百歲歡樂誰能期。"]'),
('ed563450-1281-4915-bb3f-e8ec6859e9c5','陽武王安之寄兔魚','梅堯臣','宋','宋诗','song-poetry','','[]','原上一雙兔，河中兩尾魚。',60,'全唐诗/poet.song.15000.json','["原上一雙兔，河中兩尾魚。", "兔皮空被褐，魚腹不藏書。", "長跪置遠意，故人情何如。", "二物本潛伏，誰言罝網疎。", "崢嶸歲亦晚，將駕歸吾廬。"]'),
('0b94442d-9947-410f-b393-267121149210','依韻和王景彝對雪','梅堯臣','宋','宋诗','song-poetry','','[]','天雪霰成先暴集，地中陽復已如期。',64,'全唐诗/poet.song.15000.json','["天雪霰成先暴集，地中陽復已如期。", "穿林斗覺縈風急，入袖初驚學舞遲。", "樓上溫貂方貰酒，竹間寒雀未辭枝。", "平明君向螭頭立，玉座爐烟細細時。"]'),
('164b9fd7-2b8a-4249-b613-2b2ff8ab3734','依韻答永叔洗兒歌','梅堯臣','宋','宋诗','song-poetry','','[]','夜夢有人衣帔蜺，水邊授我黄龜兒。',128,'全唐诗/poet.song.15000.json','["夜夢有人衣帔蜺，水邊授我黄龜兒。", "仰看星宿正離離，玉魁東指生斗威。", "明朝我婦忽在蓐，乃生男子實秀眉。", "自磨丹砂調白蜜，辟惡辟邪無寶犀。", "我慙暮年又舉息，不可不令朋友知。", "開封大尹憐最厚，持酒作歌來慶之。", "畫盆香水洗且喜，老駒未必能千里。", "盧仝一生常困窮，亦有添丁是其子。"]'),
('a6b30e50-2349-4473-be52-b19b4bdde141','重送祖擇之北使','梅堯臣','宋','宋诗','song-poetry','','[]','文章世德已能傳，得桂高枝二十年。',64,'全唐诗/poet.song.15000.json','["文章世德已能傳，得桂高枝二十年。", "持節欲同蘇武勁，下帷曾似董君賢。", "衣裘袵領無嫌左，飲食盃盂暫厭羶。", "一過范陽應感槩，歸來圖畫彼山川。"]'),
('64c2e209-dac4-420c-a8bb-b935d653ced6','題老人泉寄蘇明允','梅堯臣','宋','宋诗','song-poetry','','[]','泉上有老人，隠見不可常。',96,'全唐诗/poet.song.15000.json','["泉上有老人，隠見不可常。", "蘇子居其間，飲水樂未央。", "淵中必有魚，與子自徜徉。", "淵中苟無魚，子特翫滄浪。", "日月不知老，家有雛鳳皇。", "百鳥戢羽翼，不敢言文章。", "去爲仲尼歎，出爲盛時祥。", "方今天子聖，無滯彼泉傍。"]'),
('894c3a0a-7e18-4640-843f-7a7dc5509519','景彝率和唐崇徽公主手痕詩','梅堯臣','宋','宋诗','song-poetry','','[]','兩壁美人虹已收，蒼崖纖手蘚痕秋。',64,'全唐诗/poet.song.15000.json','["兩壁美人虹已收，蒼崖纖手蘚痕秋。", "和親只道能稽古，沉略從來不解羞。", "漢月明明掌中照，胡塵漠漠指間留。", "昭君歿後更多恨，彈作琵琶曲未休。"]'),
('38b28fc6-b84e-42e5-91ac-05d7e738a59c','觀黄介夫寺丞所收丘潛畫牛','梅堯臣','宋','宋诗','song-poetry','','[]','丘畫吳牛希戴嵩，吳牛角偃彎如弓。',160,'全唐诗/poet.song.15000.json','["丘畫吳牛希戴嵩，吳牛角偃彎如弓。", "老牯望㹀犢望母，母下平坡離牧童。", "牧童吹笛坡頭坐，古樹蕭騷葉戰風。", "黄君買畫都城中，不惜滿貫穿青銅。", "賣從誰家不肖子，傳自幾世賢卿翁。", "今時貴人所尚同，競借觀玩題紙窮。", "紙窮磊落見墨妙，東府西樞三四公。", "應識古人丹青蹟，又辨古人於物通。", "一毛一尾不取次，豈以後代爲盲聾。", "願推此意佐國論，況乃聖德同堯聰。"]'),
('b2f92e4b-9b72-4f45-914a-6b356ca65d89','題嘉興永樂院檇李亭','梅堯臣','宋','宋诗','song-poetry','','[]','土化吳王甲，骨朽越王兵。',60,'全唐诗/poet.song.15000.json','["土化吳王甲，骨朽越王兵。", "五月菖蒲草，千年槜李城。", "蒲根蛙怒嚎，城中烏夜鳴。", "吳越滅已久，客心空屏營。", "落日孤亭間，悠悠鍾磬聲。"]'),
('4a8b3fe0-7966-4be3-a584-64cf10a582c8','吳沖卿鼓契','梅堯臣','宋','宋诗','song-poetry','','[]','暮契出，朝契歸，出入未嘗逢日暉。',128,'全唐诗/poet.song.15000.json','["暮契出，朝契歸，出入未嘗逢日暉。", "雄雌曾不離鍾室，百年刓弊知者稀。", "時移世異不改易，俗眼厭舊君前非。", "君王萬年千年壽，獨憐古器與衆違。", "昨日霜華厚如雪，百官凍靴朝紫微。", "吳王偷就溫漏火，始一識之增歎唏。", "不知逢逢六街鼓，自此發號通帝闈。", "人間鍾鼓有多少，多少亂鳴誰肯譏。"]'),
('2658cedd-5357-48d9-8b23-180d529a9df9','江鄰幾寄羊羓','梅堯臣','宋','宋诗','song-poetry','','[]','細肋胡羊卧苑沙，長春宮使踏霜羓。',64,'全唐诗/poet.song.15000.json','["細肋胡羊卧苑沙，長春宮使踏霜羓。", "蒺蔾苗盡初蕃息，苜蓿盤空莫嘆嗟。", "自乏良謀甘更鄙，猶能大嚼快無涯。", "磨刀爲削朝霞片，時引清盃興轉嘉。"]'),
('a21ed6a2-720b-48b2-846a-083ebe79d270','周仲章都官示卷因以贈之','梅堯臣','宋','宋诗','song-poetry','','[]','赭白西北來，本是天馬種。',72,'全唐诗/poet.song.15000.json','["赭白西北來，本是天馬種。", "朝秦暮至吳，嵩華如歷冢。", "伯樂曾未逢，垂頭牧青隴。", "今朝顧我鳴，振鬣耳聳聳。", "聲生秋風悲，已喪荆軻勇。", "誰牽駕鸞車，高躡雲霧擁。"]'),
('9c7d706b-b65a-4483-9b43-731a52b5687e','送弟禹臣','梅堯臣','宋','宋诗','song-poetry','','[]','王都寓居樹陰少，惟有牆隅兩株棗。',112,'全唐诗/poet.song.15000.json','["王都寓居樹陰少，惟有牆隅兩株棗。", "去年相見棗花開，今年相別棗實好。", "棗實未剝風莫吹，我鬢愁多似蓬葆。", "淮南到時何所逢，秋葉蕭蕭蟹應老。", "憶昔共歸江上初，對飲蘆洲月如縞。", "半夜魚跳鏡破光，萬事𣎛然何足道。", "自此重經二十秋，不改青青岸旁草。"]'),
('533a1f77-de1d-4023-8344-422a95075d3d','送叔昭上人附施屯田還宣城','梅堯臣','宋','宋诗','song-poetry','','[]','瓶巾過江去，遠託故人船。',24,'全唐诗/poet.song.15000.json','["瓶巾過江去，遠託故人船。", "借問風濤勢，何如杯度年。"]'),
('ef6d66bc-df58-4c47-9a93-11b8b48a1ced','山茶花樹子贈李廷老','梅堯臣','宋','宋诗','song-poetry','','[]','南國有嘉樹，花若赤玉杯。',108,'全唐诗/poet.song.15000.json','["南國有嘉樹，花若赤玉杯。", "曾無冬春改，常冒霰雪開。", "客從天目來，移比瓊與瑰。", "贈我居大梁，蓬門方塵埃。", "舉武尚有礙，何地可以栽。", "每游平棘侯，大第夾青槐。", "朱欄植奇卉，摩碧爲壅臺。", "於此豈不宜，亟致勿徘徊。", "將看榮茂時，莫嗤寒園梅。"]'),
('f4c745c1-1687-42ff-b648-50347ee33031','送吳照鄰都官通判成都','梅堯臣','宋','宋诗','song-poetry','','[]','君家婦何賢，捨舟具車轂。',60,'全唐诗/poet.song.15000.json','["君家婦何賢，捨舟具車轂。", "五年夢在梁，三年行向蜀。", "迢遞今日同，辛勤昔時獨。", "看花久莫留，買錦慰不足。", "歸來兒女大，婚嫁應相續。"]'),
('1e33fa58-844e-4e52-b893-e669813344e6','依韻和原甫昭君辭','梅堯臣','宋','宋诗','song-poetry','','[]','武帝常勒兵，北登單于臺。',120,'全唐诗/poet.song.15000.json','["武帝常勒兵，北登單于臺。", "始欲以威服，竟亦慙懷來。", "徒令出塞師，萬里求龍媒。", "未弭後世患，玉顔困黄埃。", "丹青不足恨，謀慮少徘徊。", "月如漢宮見，心向胡地摧。", "在昔李少卿，聽笳動悲哀。", "壯士尚如此，蛾眉安得開。", "情語既不通，豈止腸九回。", "初冬誠難保，死不如草萊。"]'),
('8acbdbbc-2b41-40e4-b377-bea0c05d5792','再依韻','梅堯臣','宋','宋诗','song-poetry','','[]','一嫁異域去，不復臨鏡臺。',120,'全唐诗/poet.song.15000.json','["一嫁異域去，不復臨鏡臺。", "念昔辭家時，豈爲單于來。", "適遐固亦命，配醜非由媒。", "始欲並日月，今嗟隨風埃。", "僕侍共慘戚，山川空徘徊。", "鴻鴈爲之悲，肝腸爲之摧。", "寧聞琵琶樂，但聞琵琶哀。", "休言羊酪甘，誰喜氊廬開。", "故國萬餘里，此生那得回。", "乃知女子薄，莫比原上萊。"]'),
('f229dd50-ccc1-4e19-b9a4-cc03b045ea61','飲劉原甫舍人家同江鄰幾陳和叔學士觀白鷴孔雀鳧鼎周亞夫印鈿玉寶赫連勃勃龍雀刀','梅堯臣','宋','宋诗','song-poetry','','[]','主人鳳皇池，二客天祿閣。',192,'全唐诗/poet.song.15000.json','["主人鳳皇池，二客天祿閣。", "共來東軒飲，高輪雜談謔。", "南籠養白鷴，北籠養孔雀。", "素質水紋纖，翠毛金縷薄。", "大誇鳬柄鼎，不比龍頭杓。", "玉印傳條侯，字辯亞與惡。", "鈿劍刻辟邪，符寶殊制作。", "末觀赫連刀，龍雀鑄鐶鍔。", "每出一物玩，必勸衆賓酌。", "又令三雲髻，行酒何綽約。", "固非世俗驩，自得閱古樂。", "聖賢泯泯去，安有不死藥。", "竟知不免此，烏用强檢縛。", "開目即是今，轉目已成昨。", "歸時見月上，酒醒見月落。", "怳然如夢寐，前語誠不錯。"]'),
('56a02709-46d2-427c-9952-fb54396f4015','次韻和永叔退朝馬上見寄兼呈子華原甫','梅堯臣','宋','宋诗','song-poetry','','[]','公歸初退內朝班，馳道南頭躍錦鞍。',64,'全唐诗/poet.song.15000.json','["公歸初退內朝班，馳道南頭躍錦鞍。", "欲雨浮雲猶復暗，背陰殘雪愈生寒。", "穿槐已覺春禽語，載酒重思結客驩。", "吟寄侍臣知有意，翠鬟爭唱口應乾。"]'),
('fe7db433-8a13-488b-bfbe-2be021ba321b','劉涇州以所得李士衡觀察家號蟾蜍硯其下刻云天寶八年冬端州刺史李元德靈卵石造示劉原甫原甫方與予飲辨云天寶稱載此稱年僞也遂作詩予與江鄰幾諸君和之','梅堯臣','宋','宋诗','song-poetry','','[]','硯如刳蟆腹如月，又若剖瓢萌强發。',96,'全唐诗/poet.song.15000.json','["硯如刳蟆腹如月，又若剖瓢萌强發。", "鎸題天寶年造之，刺氏李元傳自越。", "刳蟆剖瓢我莫分，稱載作年初辯君。", "君雖能辯猶曰寶，寶茲僞物吾何云。", "仰天大笑飲君酒，硯真硯僞休開口。", "願封漆匣還與侯，請共江翁獨持守。"]'),
('6386b15a-1121-440f-a248-4a5863e144fb','送劉㢸秘校赴婺源','梅堯臣','宋','宋诗','song-poetry','','[]','雲木葱蘢處，雞鳴古縣城。',48,'全唐诗/poet.song.15000.json','["雲木葱蘢處，雞鳴古縣城。", "山高地多險，源近水偏清。", "斫漆資商貨，栽茶雜賦征。", "案頭龍尾硯，切莫苦求精。"]'),
('9e8b8e1f-b7e3-414c-ae77-c4aeec8591f1','送閻中孚郎中知磁州','梅堯臣','宋','宋诗','song-poetry','','[]','簫管梁王臺，風雪邯鄲道。',48,'全唐诗/poet.song.15000.json','["簫管梁王臺，風雪邯鄲道。", "君行守趙城，我向夷門老。", "持麾邦寄重，歌褲民欣早。", "重岡古獵場，驚兔離衰草。"]'),
('3b3f1d26-2ccd-45dc-b5bc-3ec5b2e0209d','次韻和王景彝十四日冒雪晚歸','梅堯臣','宋','宋诗','song-poetry','','[]','子猷多興憐飛雪，向晚歸時又見飄。',64,'全唐诗/poet.song.15000.json','["子猷多興憐飛雪，向晚歸時又見飄。", "拂馬隨人如著莫，舞空吹面亦勝消。", "閉門我作袁安睡，呵筆君爲謝客謠。", "記取明朝朝謁去，毳裘重戴冷寥寥。"]'),
('f1e8ccfb-2e86-444b-bc1b-72356bb50785','和王景彝晚赴江鄰幾飲','梅堯臣','宋','宋诗','song-poetry','','[]','殘雪晚生寒，良朋邀我飲。',48,'全唐诗/poet.song.15000.json','["殘雪晚生寒，良朋邀我飲。", "逢君三省歸，交轡一相審。", "乘興興未盡，既杯杯太甚。", "夜闌踏月迴，火冷人已寢。"]'),
('4f16dbc5-4d61-4c5c-8d75-ff743eae36fe','次韻和吳沖卿傷何濟川','梅堯臣','宋','宋诗','song-poetry','','[]','生愛虛名苦辯亡，淪精竭智可哀傷。',64,'全唐诗/poet.song.15000.json','["生愛虛名苦辯亡，淪精竭智可哀傷。", "誰將事附三公傳，自有文誇古戰場。", "墳土未乾還卜穴，挽聲纔絕又新章。", "是非從此方應定，弟子猶爭左氏長。"]'),
('0c2dddee-2324-40ee-881b-52aa8f38c625','次韻景彝赴省宿馬上','梅堯臣','宋','宋诗','song-poetry','','[]','烏紗帽底青眸轉，朱雀街頭玉轡摇。',64,'全唐诗/poet.song.15000.json','["烏紗帽底青眸轉，朱雀街頭玉轡摇。", "燈火高樓吹短笛，簾櫳斜巷隘初宵。", "身歸蘭省唯看月，心在天津欲倚橋。", "枕上夜深應不寐，羨他年少酒微銷。"]'),
('1d44bc61-3069-4df2-8826-0a249fc2b45e','送李獻甫','梅堯臣','宋','宋诗','song-poetry','','[]','覽君南來詩，如對江上景。',48,'全唐诗/poet.song.15000.json','["覽君南來詩，如對江上景。", "今忽告我歸，東風生馬頸。", "馬行日幾里，到家梅萼逞。", "重登石頭城，爲我一引領。"]'),
('b20b610d-518d-46b4-8e83-4cb033a1ae85','送周諫議知襄陽','梅堯臣','宋','宋诗','song-poetry','','[]','藹藹荆州幾萬家，竟持壺酒望高牙。',64,'全唐诗/poet.song.15000.json','["藹藹荆州幾萬家，竟持壺酒望高牙。", "里兒尚唱銅鞮曲，耆舊爭隨畫鹿車。", "雄鴨綠頭看漢水，肥鯿縮項出漁查。", "鄉人應笑張平子，只有歸田賦可誇。"]'),
('17a6022b-9682-42e6-825b-7c94e2ff016b','次韻和酬裴寺丞喜子修書','梅堯臣','宋','宋诗','song-poetry','','[]','唐宋典冊竟駢羅，漢詔重令與削磨。',64,'全唐诗/poet.song.15000.json','["唐宋典冊竟駢羅，漢詔重令與削磨。", "古聖規模猶可法，衆賢馳騁必無蹉。", "既除太史來爲尹，遂用非才往補訛。", "代匠只憂傷手甚，君宜憐我不遑他。"]'),
('d35a8ce4-f485-4ded-9c39-3e090d8839cf','送趙虞部士宏知蜀州','梅堯臣','宋','宋诗','song-poetry','','[]','春風跨臘至，雪作蝴蝶飛。',60,'全唐诗/poet.song.15000.json','["春風跨臘至，雪作蝴蝶飛。", "偏知蜀太守，撩亂撲行衣。", "何當海棠下，歌管紅袖圍。", "一飲一斗酒，决訟如發機。", "洛陽花自好，聽從杜鵑啼。"]'),
('e6e84502-d9b6-4626-8826-69ada2838f9a','月蝕','梅堯臣','宋','宋诗','song-poetry','','[]','有婢上堂來，白我事可驚。',72,'全唐诗/poet.song.15000.json','["有婢上堂來，白我事可驚。", "天如青玻瓈，月若黑水精。", "時當十分圓，只見一寸明。", "主婦煎餠去，小兒敲鏡聲。", "此雖淺近意，乃重補救情。", "夜深桂兔出，衆星隨西傾。"]'),
('5a98fe08-ce65-4f85-b4be-e663bd1d568c','次韻和酬刁景純春雪戲意','梅堯臣','宋','宋诗','song-poetry','','[]','雪與春歸落歲前，曉開庭樹有餘妍。',64,'全唐诗/poet.song.15000.json','["雪與春歸落歲前，曉開庭樹有餘妍。", "楊花撲撲白漫地，蛺蝶紛紛飛滿天。", "胡馬嘶風思塞草，吳牛喘月困沙田。", "我貧始覺今朝富，大片如錢不解穿。"]'),
('c622c8cf-9e30-4c3d-b376-cca91cea7367','次韻和酬楊樂道待制詠雪','梅堯臣','宋','宋诗','song-poetry','','[]','梁苑孝王跡，灞陵游客心。',96,'全唐诗/poet.song.15000.json','["梁苑孝王跡，灞陵游客心。", "牧羊來海上，泛棹向山陰。", "興賞曾何淺，羈棲亦以深。", "穆歌猶在竹，郢曲自傳琴。", "旗凍霑天仗，鎗寒拂羽林。", "且爲豐歲慶，休作苦寒吟。", "掩帙都忘慮，焚香靜擁衾。", "晴明一登閣，暮色徧高岑。"]'),
('c6658b4e-5073-42fa-8180-8dbebff72406','次韻和景彝閏臘二十五日省宿','梅堯臣','宋','宋诗','song-poetry','','[]','君嘗編史似吳兢，又值甘泉馬踏冰。',64,'全唐诗/poet.song.15000.json','["君嘗編史似吳兢，又值甘泉馬踏冰。", "重臘雪花方漫漫，宿廳書架自層層。", "桉頭美酒初溫火，簾底微風欲動燈。", "永夜未眠鍾已發，此心閒寂似高僧。"]'),
('96d7b94d-c059-4824-851b-6cee416a9dec','姪宰與外甥蔡駰下第東歸','梅堯臣','宋','宋诗','song-poetry','','[]','事莫必有勝，必勝難可持。',84,'全唐诗/poet.song.15000.json','["事莫必有勝，必勝難可持。", "邇來罕相見，世上多誇馳。", "黄金鑄佩印，白玉刻佩龜。", "朝見恃赫赫，夕見同蚩蚩。", "方得靡不羨，既處焉所施。", "此理非一日，更後當應知。", "志士無終窮，斯言非爾欺。"]'),
('2c54066c-27b0-4fb7-a3f4-4d4e26dbf7b7','次韻和永叔','梅堯臣','宋','宋诗','song-poetry','','[]','省樹高槐雪壓條，沉沉古屋蔽疏寮。',64,'全唐诗/poet.song.15000.json','["省樹高槐雪壓條，沉沉古屋蔽疏寮。", "每嗟守印如枯木，欲棄明珠學緯蕭。", "漸老但知貧賤樂，向來徒用歲時銷。", "新年不管魚龍躍，安得乘風入剡樵。"]'),
('067865b4-f343-41ad-8c58-636cf7f1c9e4','次韻和范景仁舍人對雪','梅堯臣','宋','宋诗','song-poetry','','[]','三尺沒腰雪，京華頻歲無。',120,'全唐诗/poet.song.15000.json','["三尺沒腰雪，京華頻歲無。", "高低相掩覆，竅隙似封糊。", "帖缺都迷醜，增妍不問枯。", "因時混貧富，遇物得圓觚。", "眩目曾何數，流風不可圖。", "冥冥山霧合，浩浩海雲鋪。", "未覺花飛葉，先看霰集珠。", "落機裁扇素，獵野割膚腴。", "粲爾娥奔月，皤然叟赴酺。", "薄才今揣稱，小巧媿非夫。"]'),
('8078a9ff-f52d-4a4d-9faf-7d7291681fd2','嘉祐己亥歲旦永叔內翰','梅堯臣','宋','宋诗','song-poetry','','[]','堦前去年雪，鏡裏舊時人。',48,'全唐诗/poet.song.15000.json','["堦前去年雪，鏡裏舊時人。", "不覺應銷盡，相看只似新。", "屠酥先尚幼，綵勝又宜春。", "獨愛開封尹，鍾陵請去頻。"]'),
('9230de77-060a-4586-a521-e5c72fc424b2','次韻和吳沖卿歲暮有懷','梅堯臣','宋','宋诗','song-poetry','','[]','舊曆卷將盡，慨然增永懷。',48,'全唐诗/poet.song.15000.json','["舊曆卷將盡，慨然增永懷。", "唯希步兵醉，莫作太常齋。", "孟浪從人笑，疎愚共世乖。", "定知當汨沒，名不與功偕。"]'),
('a12a64bd-4079-4567-940e-915d0e122613','次韻和沖卿元日','梅堯臣','宋','宋诗','song-poetry','','[]','天心欲銷變，元會罷來朝。',48,'全唐诗/poet.song.15000.json','["天心欲銷變，元會罷來朝。", "新歲起今日，舊年猶昨宵。", "凍雲低覆闕，殘雪稍封條。", "又聽驅儺鼓，羣邪不可饒。"]'),
('505d9631-a3b0-4fb9-b331-c62742ef14b9','次韻和景仁對雪','梅堯臣','宋','宋诗','song-poetry','','[]','北風吹雪至，浩蕩地疑無。',120,'全唐诗/poet.song.15000.json','["北風吹雪至，浩蕩地疑無。", "奕奕將如舞，漫漫欲似糊。", "沙場行不盡，銀漢落應枯。", "興發詩千首，豪吞酒百觚。", "山川容可改，圭璧巧能圖。", "花竟因酥點，砧爭以練鋪。", "未燖調鼎鵠，全混蔽旒珠。", "懷昔餐衣絮，誰今食豢腴。", "善歌知寡和，醵飲遂成酺。", "衆筆排堅陣，多多困老夫。"]'),
('37db9bd1-52a7-4e75-b1c3-a4f04e3ac8ef','次韻三和景仁對雪','梅堯臣','宋','宋诗','song-poetry','','[]','北度龍沙遠，南來狗犬無。',120,'全唐诗/poet.song.15000.json','["北度龍沙遠，南來狗犬無。", "玉階三尺峻，粉壁萬重糊。", "獸餒行迷穴，禽寒立並枯。", "長川平界限，大屋竦稜觚。", "稍見蓬萊闕，初張雲霧圖。", "受降鍪甲積，罷獵羽毛鋪。", "被褐思懷寶，游都學賣珠。", "車皆陳鋈轡，人盡得瓊腴。", "縞已贈吳札，席將開漢酺。", "鳳池批詔手，特地逞工夫。"]'),
('bb3a7657-59ab-4e28-99c2-9979122ede1d','次韻和永叔新歲書事見寄','梅堯臣','宋','宋诗','song-poetry','','[]','尖風細細欲穿簾，殘雪微銷凍結簷。',64,'全唐诗/poet.song.15000.json','["尖風細細欲穿簾，殘雪微銷凍結簷。", "盞裏醇醪無限滿，鏡中白髮不知添。", "妍童喜舞開羅幕，小吏愁凘入硯蟾。", "幸得從公持直筆，定應無復歎齏鹽。"]'),
('e8dab93c-a5e4-4120-87df-5d42b3f1672d','送辛都官知鄂州','梅堯臣','宋','宋诗','song-poetry','','[]','衣上大梁雪，門前武昌車。',108,'全唐诗/poet.song.15000.json','["衣上大梁雪，門前武昌車。", "使君行有期，將逢鳥隼旟。", "車動自轣轆，旟輕自舒舒。", "去都越千里，城在江上居。", "黄鶴有高樓，樓頭挂蟾蜍。", "下見鸚鵡洲，葭茁可以菹。", "爲弔禰處士，沉蹤異三閭。", "憶昔我仲父，五馬立躊躇。", "願君訪舊跡，因報八行書。"]'),
('60087aa5-39af-4248-b314-8ed1664e5448','次韻王景彝正月十六夜省宿過景靈街','梅堯臣','宋','宋诗','song-poetry','','[]','宮街不閉東城月，圓影纔虧夜色春。',64,'全唐诗/poet.song.15000.json','["宮街不閉東城月，圓影纔虧夜色春。", "自躍金羈來宿省，從他錦帳欲誇人。", "燈光遠近疑爭晝，歌韻高低競起塵。", "我老都無游樂意，似君清枕睡侵晨。"]'),
('ccb6b8dd-8212-4e51-b63f-45e8e57c9a6a','送韓玉汝太傅知洋州三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','函關見殘雪，襃谷聞春禽。',72,'全唐诗/poet.song.15000.json','["函關見殘雪，襃谷聞春禽。", "禽響通朱輪，馬嘶入青林。", "花明亂石路，雲抱寒泉岑。", "天外漢江來，城下漁網沉。", "庖供縮項鯿，坐使宮娥斟。", "農桑不須教，古俗自通今。"]'),
('b107c2cc-65b6-4070-a0fd-18164391f799','送韓玉汝太傅知洋州三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','渭入秦宮古，襃分蜀道難。',48,'全唐诗/poet.song.15000.json','["渭入秦宮古，襃分蜀道難。", "泉聲春雨後，月色曉程寒。", "蠶浴桑芽短，禽啼杏萼丹。", "從來稱召杜，民俗在君安。"]'),
('8ae636bf-69d0-4d3e-b4f1-b85790c5a7be','送韓玉汝太傅知洋州三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','春風東來幾萬里，相送入關如有情。',144,'全唐诗/poet.song.15000.json','["春風東來幾萬里，相送入關如有情。", "灞陵原邊柳條暗，咸陽橋畔桃花明。", "自古恨別此兩處，十千美酒瑠璃傾。", "日落未落車馬動，子規滴血壯士驚。", "行哉使君負膽氣，蜀道雖險心常輕。", "是時門前大桐樹，爛漫紫萼啼流鶑。", "弟兄同懷不可見，應亦夢覺嗟遠程。", "太白山前一尺雨，桑下問蠶田問耕。", "郡城夜開百姓喜，喜從迢遞壺漿迎。"]'),
('f3c7ec72-a5bf-4b98-98cc-78730c943a54','李廷老祠部寄荆柑子','梅堯臣','宋','宋诗','song-poetry','','[]','踏雪衝風馳小吏，带霜連葉寄黄柑。',64,'全唐诗/poet.song.15000.json','["踏雪衝風馳小吏，带霜連葉寄黄柑。", "擗包欲咀牙全動，舉盞逢衰酒易酣。", "書尾自題知遠意，筆頭親答厭多談。", "故人莫覓新詩卷，都似嵇康七不堪。"]'),
('5a43a471-dd95-477a-938c-ad9f6d97e212','韻語答永叔內翰','梅堯臣','宋','宋诗','song-poetry','','[]','世人作肥字，正如論饅頭。',228,'全唐诗/poet.song.15000.json','["世人作肥字，正如論饅頭。", "厚皮雖然佳，俗物已可羞。", "字法歎中絕，今將五十秋。", "近日稍稍貴，追蹤慕前流。", "曾未三數人，得與古昔儔。", "古人皆能書，獨其賢者留。", "後世不推此，但務於書求。", "不知前日工，隨紙泯已休。", "顔書苟不佳，世豈不寶收。", "設如楊凝式，言且直節修。", "又若李廷中，清慎實罕侔。", "乃知愛其書，兼取爲人優。", "豈書能存久，賢哲人焉廋。", "非賢必能此，惟賢乃爲尤。", "其餘皆泯泯，死去同馬牛。", "大尹歐陽公，昨日喜疾瘳。", "信筆寫此語，謂可忘病憂。", "黄昏走小校，寄我東郭陬。", "綴之輙成篇，聯以助吟謳。"]'),
('2719b3c8-e7c2-45ba-947e-592fefee6652','次韻和韓子華內翰於李右丞家移紅薇子種學士院','梅堯臣','宋','宋诗','song-poetry','','[]','紅薇花樹小扶疏，春種秋芳賞愛餘。',64,'全唐诗/poet.song.15000.json','["紅薇花樹小扶疏，春種秋芳賞愛餘。", "丞相舊園移带土，侍臣清署看臨除。", "薄膚癢不勝輕爪，嫩幹生宜近禁廬。", "此地結根千萬歲，聯華榮莫比茅茹。"]'),
('1c61c73d-b423-41a8-a1b2-ebeb03c0e0e2','次韻和吳長文舍人即事見寄','梅堯臣','宋','宋诗','song-poetry','','[]','莫問春風有後先，但逢佳處去揚鞭。',64,'全唐诗/poet.song.15000.json','["莫問春風有後先，但逢佳處去揚鞭。", "桃花洞遠迷應久，杏樹壇荒迹自傳。", "放與曉寒能幾許，即看芳意不多偏。", "古來閒氣爭强弱，謾費黄金拋楚權。"]'),
('86317f81-768d-4d63-b28c-12352b852b5f','次韻和長文社日禖祀出城','梅堯臣','宋','宋诗','song-poetry','','[]','曉出春風已擺條，應逢社伯馬蹄驕。',64,'全唐诗/poet.song.15000.json','["曉出春風已擺條，應逢社伯馬蹄驕。", "壇邊宿雨微霑麥，水上殘冰壅過橋。", "燕子飛來依約近，鴈行歸去試教調。", "北扉西掖多才思，相與飄飄在泬寥。"]'),
('32569291-6e9b-477e-83bf-3ecf00fa74ca','次韻和長文禖祀郊外見寄并呈韓子華','梅堯臣','宋','宋诗','song-poetry','','[]','鵓鴣知雨在桑中，雄逐雌飛自不同。',64,'全唐诗/poet.song.15000.json','["鵓鴣知雨在桑中，雄逐雌飛自不同。", "胡粉未生輕蝶白，燕脂先綻野櫻紅。", "高高樹裏鞦韆月，獵獵牆頭蓓蕾風。", "曉下祠壇多寄詠，衣冠方侍大明宮。"]'),
('6aeaa3d6-f4fe-45c4-9d84-610765491071','送馬行之都官','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昭亭山下送君時，不畏西行劍棧危。',64,'全唐诗/poet.song.15000.json','["昭亭山下送君時，不畏西行劍棧危。", "笮馬跨來身更健，吳船乘去計非遲。", "錢塘湖上尋雲屋，巾子峯前種槿籬。", "此趣已高天下士，不須功業似鴟夷。"]'),
('04f1b9b4-8258-4399-8e14-c71b1c89fd1c','和王景彝詠薜荔','梅堯臣','宋','宋诗','song-poetry','','[]','植物有薜荔，足物有蜥蜴。',48,'全唐诗/poet.song.15000.json','["植物有薜荔，足物有蜥蜴。", "固知不同類，亦各善緣壁。", "根隨枝蔓生，葉侵苔蘚碧。", "後凋雖可嘉，勁挺異松柏。"]'),
('7a550b03-f11a-47e1-80cb-4025fce09455','和江鄰幾省中賞小桃','梅堯臣','宋','宋诗','song-poetry','','[]','年年二月賣花天，唯有小桃偏占先。',64,'全唐诗/poet.song.15000.json','["年年二月賣花天，唯有小桃偏占先。", "初見嫩紅無不喜，終知俗豔幾多妍。", "鄰翁已折郊園裏，貴客爭誇粉署邊。", "可惜工夫吟向此，會須留醉牡丹前。"]'),
('d25d6493-185b-435d-b724-6afa722b47c4','長歌行','梅堯臣','宋','宋诗','song-poetry','','[]','世人何惡死，死必勝於生。',180,'全唐诗/poet.song.15000.json','["世人何惡死，死必勝於生。", "勞勞塵土中，役役歲月更。", "大寒求以𣋉，大暑求以清。", "維餒求以饁，維渴求以觥。", "其少慾所惑，其老病所嬰。", "富貴拘法律，貧賤畏笞榜。", "生既若此苦，死當一切平。", "釋子外形骸，道士完髓精。", "二皆趨死途，足以見其情。", "遺形得極樂，昇僊上玉京。", "是乃等爲死，安有蛻骨輕。", "日中不見影，陽魂與鬼并。", "莊周謂之息，漏泄理甚明。", "仲尼曰焉知，不使人道傾。", "此論吾得之，曷要世間行。"]'),
('dadc48b2-5ddc-46e9-a785-685068dbeac8','依韻和長文紫微春雨二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','年年潑火雨，苦作清明寒。',72,'全唐诗/poet.song.15000.json','["年年潑火雨，苦作清明寒。", "梨花猶半綻，塘水已迷漫。", "愁看日更永，冷漏夜未闌。", "酒沫起玉盞，燭淚生銅盤。", "春衣向來脫，带眼斗覺寬。", "試問彼俠少，何處跨金鞍。"]'),
('bbba8f96-8c31-426d-bd68-92cf9ae869bd','依韻和長文紫微春雨二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','春雨固多喜，雖多安得愁。',96,'全唐诗/poet.song.15000.json','["春雨固多喜，雖多安得愁。", "既能勒花苞，又解滋耕疇。", "池添痕痕漲，渠有細細流。", "不同離婦怨，一落不可收。", "定知矜有年，豈似斗粟賙。", "西掖吳夫子，吟觀意遲留。", "正聲隮雅頌，高論等陽秋。", "我慙才甚薄，難繼東山謳。"]'),
('f3d78743-c1d4-4ef6-ba42-c72c1b7cff8c','送滕寺丞歸蘇州','梅堯臣','宋','宋诗','song-poetry','','[]','驅車入蜀時，有弟母不往。',96,'全唐诗/poet.song.15000.json','["驅車入蜀時，有弟母不往。", "留婦侍母傍，以子囑婦養。", "昨得閶門書，婦子死泉壤。", "此心那得安，棄官提轡鞅。", "東馳三千里，鬻馬求吳槳。", "吳槳速如飛，歸來拜堂上。", "堂前去時樹，已覺枝條長。", "豈無懷抱感，爲壽酌春醠。"]'),
('518f94ce-4c3f-4715-91fe-865c1d337322','次韻和酬永叔','梅堯臣','宋','宋诗','song-poetry','','[]','春候倏已和，林上鳴鳥譁。',168,'全唐诗/poet.song.15000.json','["春候倏已和，林上鳴鳥譁。", "前日是清明，驟雨霑梨花。", "初聞結客游，愛此物景嘉。", "歌舞未終宴，夕暮各興嗟。", "所嗟歸路暗，嘶馬自知家。", "公家八九姝，鬒髮如盤鴉。", "朱唇白玉膚，參年始破瓜。", "幾日苦霖霪，當道跳魚蝦。", "閉門飲濁醪，鞦韆繫樹丫。", "羣姝莫要劇，爲公歌啞啞。", "公當是日醉，歡適不可涯。", "孔氏有高第，內自戰紛華。", "我公豈其然，秉直異蓬麻。", "果從歸田去，願從招轅車。"]'),
('6791707b-0d62-4840-b01e-37ef878cba5a','次韻和江鄰幾送客回同過金明池  其一','梅堯臣','宋','宋诗','song-poetry','','[]','送別西亭車馬塵，天池回傍欲迷津。',32,'全唐诗/poet.song.15000.json','["送別西亭車馬塵，天池回傍欲迷津。", "畫船龍尾何時發，丹杏梢頭漏泄春。"]'),
('224c8dfb-ee58-4473-812d-d2835a6aac22','次韻和江鄰幾送客回同過金明池  其二','梅堯臣','宋','宋诗','song-poetry','','[]','風光猶未老於人，獸口泉聲瀉碧津。',32,'全唐诗/poet.song.15000.json','["風光猶未老於人，獸口泉聲瀉碧津。", "一洗塵襟無俗慮，柳條開眼共看春。"]'),
('60320b1b-ac5b-4f5b-9046-dcd01f3226d4','次韻和劉原甫紫微過予飲酒','梅堯臣','宋','宋诗','song-poetry','','[]','所居汴水近，未有鼓吹蛙。',168,'全唐诗/poet.song.15000.json','["所居汴水近，未有鼓吹蛙。", "昨日春雨晴，車騎臨我家。", "我家苦僻遠，庭下無泥沙。", "爲撇甕面醅，爲煎鷹爪茶。", "乳羹芼紫蒓，蜜果飣乾瓜。", "與我相對飲，但恨諸友遐。", "笑語雖同昔，放浪不少加。", "忽觀壁間字，坐歎目昏花。", "公壯尚若此，我老死豈賒。", "門前賣桃李，呼買婀娜華。", "東簷大槐樹，上有鳥雀譁。", "恃舊無猜嫌，醉弁已傾斜。", "將去還見規，禮數何檢差。", "後從江韓來，褫带歡莫涯。"]'),
('b58c976b-a26e-4563-bf7d-630e5d6ddb67','送湯延賞秀才下第歸','梅堯臣','宋','宋诗','song-poetry','','[]','參差綠柳上，撩亂黄鸚飛。',48,'全唐诗/poet.song.15000.json','["參差綠柳上，撩亂黄鸚飛。", "失意暫時屈，獨嗟千里歸。", "淮船行欲馳，江鮆去應肥。", "謝脁吾鄉守，欣欣見綵衣。"]'),
('1d1265e4-7583-4295-9fa3-c8e8b6fcf5c4','送門人歐陽秀才游江西','梅堯臣','宋','宋诗','song-poetry','','[]','客心如萌芽，忽與春風動。',60,'全唐诗/poet.song.15000.json','["客心如萌芽，忽與春風動。", "又隨落花飛，去作西江夢。", "我家無梧桐，安可久留鳳。", "鳳巢在桂林，烏哺不得共。", "無忘桂枝榮，舉酒一以送。"]'),
('744066be-99b3-49e4-ad3a-7347942c6b01','答來上人春日即事','梅堯臣','宋','宋诗','song-poetry','','[]','南國三衣客，王城一見春。',48,'全唐诗/poet.song.15000.json','["南國三衣客，王城一見春。", "花明馳道遠，雨漲御溝新。", "茗憶山中物，雲懷嶺上鄰。", "如何異鄉感，却出解空人。"]'),
('9bb365b6-5c06-4fba-b33c-83c3a66dde8f','送楊申職方通判信州','梅堯臣','宋','宋诗','song-poetry','','[]','從來饒信吏，愛寶襲侈越。',72,'全唐诗/poet.song.15000.json','["從來饒信吏，愛寶襲侈越。", "莫買冰玉盤，蒼山斵明月。", "明月有時生，窮巖有時竭。", "君常抱清節，歷職老無闕。", "與我年齒同，獨未變華髮。", "又爲江外行，畫舸羨明發。"]'),
('f6c04e77-2f27-4113-af08-25358be3faca','送勾諶太丞通判潁州','梅堯臣','宋','宋诗','song-poetry','','[]','潁川倒灣流，欄船曲轉鈎。',48,'全唐诗/poet.song.15000.json','["潁川倒灣流，欄船曲轉鈎。", "吏迎如太守，民望亞諸侯。", "芳圃深通野，寒湖半抱州。", "前賢多舊迹，佳詠聽君留。"]'),
('cca2266b-9bf7-460e-b3d9-4d619982b404','和永叔六篇 詳定幕次呈同舍','梅堯臣','宋','宋诗','song-poetry','','[]','苑樹天邊雨露勻，羣公偷看錦叢新。',32,'全唐诗/poet.song.15000.json','["苑樹天邊雨露勻，羣公偷看錦叢新。", "眼穿欲折無由折，賞到人間不是春。"]'),
('b450a39a-6006-431e-a803-47153426ebe6','和永叔六篇 代鳩婦言','梅堯臣','宋','宋诗','song-poetry','','[]','不如作蠒依蠶蔟，以絲自裹還自足。',112,'全唐诗/poet.song.15000.json','["不如作蠒依蠶蔟，以絲自裹還自足。", "與爾爲婦過一生，怒即分飛同轉目。", "辛勤哺雛寄鵲巢，子母生離因爾逐。", "羽毛曾未顔色衰，飲啄不計豐儉時。", "天陰輙遣呼輙歸，恩情紙薄誰信之。", "朝爲夫婦夕行路，世間反覆那能知。", "伋妻白母非美事，後代放此誠堪悲。"]'),
('51bc65d9-8328-4ca5-aca7-fec7dc7d15b2','和永叔六篇 看花呈子華內翰','梅堯臣','宋','宋诗','song-poetry','','[]','時不選數老獨嗟，鬢毛未變目未花。',128,'全唐诗/poet.song.15000.json','["時不選數老獨嗟，鬢毛未變目未花。", "愛公深殿見桃李，長才高詠無能加。", "紅英灼灼弄日色，穠豔皎皎生鉛華。", "長廊垂幕風不動，映柳黄鶑吟未涯。", "燕銜新泥補巢缺，蝸壓峻陛臨角斜。", "是時唯聞鳥雀鬧，盡日不聽車輪譁。", "雖傳此景無分到，但訝習慣猶豪誇。", "他年造物儻有意，不使齪齪居貧家。"]'),
('b4ab83bd-bdcd-40c9-a703-633a2ff17719','和永叔六篇 禁中鞓紅牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','與公同是洛陽客，今日論年皆作翁。',32,'全唐诗/poet.song.15000.json','["與公同是洛陽客，今日論年皆作翁。", "一見此花知有感，衰顔不似舊時紅。"]'),
('1f5b2502-fa71-43b1-908e-c4c4f5a7b3a0','和永叔六篇 和鄰幾學士桃花','梅堯臣','宋','宋诗','song-poetry','','[]','深殿有春人到稀，武陵雖說昧當時。',32,'全唐诗/poet.song.15000.json','["深殿有春人到稀，武陵雖說昧當時。", "躊躇莫憶人間世，恐至塵中悔却遲。"]'),
('a62e2d74-a69f-46db-b1f0-00f1bba74b46','和永叔六篇 啼鳥','梅堯臣','宋','宋诗','song-poetry','','[]','提胡蘆，提胡蘆，爾莫勸翁沽美酒。',142,'全唐诗/poet.song.15000.json','["提胡蘆，提胡蘆，爾莫勸翁沽美酒。", "公多金錢賜醇酎，名聲壓時爲不朽。", "百舌子，百舌子，春泥方滑滑。", "泥雖滑滑輦道平，莫學竹雞言易發。", "深宮許爾來報春，便是好鳥同其羣。", "清聲囀入君王耳，安用穿叢苦避人。", "桃李無言何所益，畢竟有謝須紛紛。", "莫以榮華長不歇，人間已見翟公門。", "安不忘危誰可貴，貴時能憶困時聞。"]'),
('dd5f3776-a35a-46a3-a3f6-ddb5d00d3bda','縉叔以詩遺酒次其韻','梅堯臣','宋','宋诗','song-poetry','','[]','君嘗謂我性嗜酒，又復謂我躭於詩。',116,'全唐诗/poet.song.15000.json','["君嘗謂我性嗜酒，又復謂我躭於詩。", "一日不飲情頗惡，一日不吟無所爲。", "酒能銷憂忘富貴，詩欲主盟張鼓旗。", "百觚孔聖不可擬，白眼步兵吾久師。", "君多賜壺能以遺，向口滿碗傾玻瓈。", "醇釀甘滑泛綠蟻，從此便醉醒無期。", "既以樂吾真，亦以泰吾身，莫問今人與古人。"]'),
('b0da8aeb-c751-454f-912e-3891443687fa','和范景仁王景彝殿中雜題三十八首並次韻 殿幕閒興','梅堯臣','宋','宋诗','song-poetry','','[]','宮殿深沉處，鶑花爛漫時。',48,'全唐诗/poet.song.15000.json','["宮殿深沉處，鶑花爛漫時。", "關關哢清吭，蒨蒨發朱蕤。", "天上春應早，人間日轉遲。", "得賢如漢盛，五字變周詩。"]'),
('24d7bef3-1f67-4620-b67e-7f87424582b2','和范景仁王景彝殿中雜題三十八首並次韻 游延羲閣後藥欄','梅堯臣','宋','宋诗','song-poetry','','[]','授經聞漢帝，嘗此講秦餘。',72,'全唐诗/poet.song.15000.json','["授經聞漢帝，嘗此講秦餘。", "一日承丹詔，同時見子虛。", "來游瓊閣外，閒傍藥欄初。", "柳絮輕黏履，薇條澀惹裾。", "解歸巢上燕，思寄袖中書。", "此鳥如矜慎，飛飛與客疎。"]'),
('fc70b316-263e-4d4f-a788-02b7842bf615','和范景仁王景彝殿中雜題三十八首並次韻 龍柏','梅堯臣','宋','宋诗','song-poetry','','[]','花非龍香葉非柏，獨竊二美誇芳蕤。',48,'全唐诗/poet.song.15000.json','["花非龍香葉非柏，獨竊二美誇芳蕤。", "苦練不分顔色近，紫荆未甘開謝遲。", "羣公莫以得地貴，竟費佳句何足思。"]'),
('4ef07325-16a3-4e71-b69b-347462884f05','和范景仁王景彝殿中雜題三十八首並次韻 延羲閣牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','花中第一品，天上見應難。',48,'全唐诗/poet.song.15000.json','["花中第一品，天上見應難。", "近署多紅藥，層城有射干。", "生雖由地勢，開不許人看。", "天子何時賞，宮娥捧玉盤。"]'),
('3519ab12-c094-4780-90d7-d502ad851ee3','和范景仁王景彝殿中雜題三十八首並次韻 奉呈諸君','梅堯臣','宋','宋诗','song-poetry','','[]','參天朱閣峻，拂地柳條垂。',48,'全唐诗/poet.song.15000.json','["參天朱閣峻，拂地柳條垂。", "太液綠波漲，建章春漏遲。", "長人執兵立，小豎插花嬉。", "但只逢人說，無由預此時。"]'),
('b7a500f6-eeb8-48d5-abad-175714cf67a2','和范景仁王景彝殿中雜題三十八首並次韻 細竹','梅堯臣','宋','宋诗','song-poetry','','[]','森森漢宮竹，託本異孤生。',48,'全唐诗/poet.song.15000.json','["森森漢宮竹，託本異孤生。", "玉砌緣根迸，朱欄與筍平。", "朝煙生密翠，晚影漏斜明。", "應待女媧采，參差鳳琯清。"]'),
('c479fa55-fccc-4cc3-9e30-843c51ca2805','和范景仁王景彝殿中雜題三十八首並次韻 夜賦','梅堯臣','宋','宋诗','song-poetry','','[]','月從東殿生，叢竹照脩竦。',48,'全唐诗/poet.song.15000.json','["月從東殿生，叢竹照脩竦。", "葉間清露滴，枝上寒禽動。", "閒覺萬慮空，靜聞嚴鼓重。", "官燭翦更明，相看應似夢。"]'),
('652b80e3-c008-49b8-a431-0252e12eef38','和范景仁王景彝殿中雜題三十八首並次韻 三月九日迎駕','梅堯臣','宋','宋诗','song-poetry','','[]','前殿臨朝百辟回，後宮廷閣九重開。',64,'全唐诗/poet.song.15000.json','["前殿臨朝百辟回，後宮廷閣九重開。", "鳴梢已自金階出，黄屋初迎玉輦來。", "不問偷桃方朔飽，誰知載戟子雲才。", "羣官望幸無名姓，只有窮吟許外陪。"]'),
('f4ef9a15-1320-42a0-b905-973adbc53ca1','和范景仁王景彝殿中雜題三十八首並次韻 浹日','梅堯臣','宋','宋诗','song-poetry','','[]','光陰天上早，氣候日邊溫。',48,'全唐诗/poet.song.15000.json','["光陰天上早，氣候日邊溫。", "懸蟢時過眼，飛蟲稍入軒。", "看花成子大，聞燕養雛喧。", "每覺瑶池宴，風飄管吹繁。"]'),
('855ee57e-7a6d-4000-b602-27030feb866e','和范景仁王景彝殿中雜題三十八首並次韻 宮槐','梅堯臣','宋','宋诗','song-poetry','','[]','漢家宮殿蔭長槐，嫩色葱葱不染埃。',64,'全唐诗/poet.song.15000.json','["漢家宮殿蔭長槐，嫩色葱葱不染埃。", "天仗龍旂穿影去，鈎陳豹尾拂枝來。", "青蟲掛後蜂銜子，素月生時桂並栽。", "我意方同杜工部，冷淘唯喜葉新開。"]'),
('6c712d97-ce2e-45f4-afcf-44383f05181e','和范景仁王景彝殿中雜題三十八首並次韻 有折景福殿後酴醾花至者','梅堯臣','宋','宋诗','song-poetry','','[]','有鳥銜花出，清香不畏風。',48,'全唐诗/poet.song.15000.json','["有鳥銜花出，清香不畏風。", "初從上林發，來過未央中。", "蔟蔟霜包密，層層玉葉同。", "誰將作美酒，醉看月生東。"]'),
('a80c4fa8-01a4-4812-80ea-1c2adc67e7bb','和范景仁王景彝殿中雜題三十八首並次韻 詩癖','梅堯臣','宋','宋诗','song-poetry','','[]','人間詩癖勝錢癖，搜索肝脾過幾春。',64,'全唐诗/poet.song.15000.json','["人間詩癖勝錢癖，搜索肝脾過幾春。", "囊橐無嫌貧似舊，風騷有喜句多新。", "但將苦意摩層宙，莫計終窮涉暮津。", "試看一生銅臭者，羨他登第亦何頻。"]'),
('dc19d98e-a2b1-4225-812a-15557246baa7','和范景仁王景彝殿中雜題三十八首並次韻 石詠','梅堯臣','宋','宋诗','song-poetry','','[]','君王愛石醜，百孔皆相通。',48,'全唐诗/poet.song.15000.json','["君王愛石醜，百孔皆相通。", "怪狀一如此，補天有何功。", "匪言不可轉，安得來宮中。", "女豈比柱礎，瑩然受磨礱。"]'),
('498e3bb4-9be4-4ca2-9cc3-7d9790ce34ee','和范景仁王景彝殿中雜題三十八首並次韻 逾旬','梅堯臣','宋','宋诗','song-poetry','','[]','重說已經旬，應懷獨寢人。',48,'全唐诗/poet.song.15000.json','["重說已經旬，應懷獨寢人。", "通宵彈玉枕，白晝拂牀塵。", "幾想迎雕輦，何當快倦身。", "門前車馬立，疑是角生輪。"]'),
('ba8d3d28-e0ca-46c5-a427-1f373b7fcb5d','和范景仁王景彝殿中雜題三十八首並次韻 晨起','梅堯臣','宋','宋诗','song-poetry','','[]','月向西樓下，天光候日開。',48,'全唐诗/poet.song.15000.json','["月向西樓下，天光候日開。", "殘星明寶鑑，百舌響宮槐。", "玉井傳新汲，金爐換宿灰。", "黄門馳有詔，唱第許卿來。"]'),
('788b5ea7-b5c1-4f0d-8a7a-bc02759316c4','和范景仁王景彝殿中雜題三十八首並次韻 金沙花','梅堯臣','宋','宋诗','song-poetry','','[]','金有披沙得，花應不可多。',48,'全唐诗/poet.song.15000.json','["金有披沙得，花應不可多。", "栽培由地力，豔色與天和。", "玉座君王賞，朱欄將相羅。", "稱觴千萬壽，繁葉奈香何。"]'),
('fefe46a7-b2ed-4fd2-97f8-1429a562ddf7','和范景仁王景彝殿中雜題三十八首並次韻 賜食','梅堯臣','宋','宋诗','song-poetry','','[]','誰言出相是山東，今日求賢欲致功。',64,'全唐诗/poet.song.15000.json','["誰言出相是山東，今日求賢欲致功。", "玉饌滿盤來禁裏，鵠羹分鼎下天中。", "但知愷弟酬君賜，舊訝權輿向國風。", "曾笑侏儒飽欲死，宜思薇蕨不忘忠。"]'),
('1252e836-022d-41aa-9164-9235de9e2f0d','和范景仁王景彝殿中雜題三十八首並次韻 賜酒','梅堯臣','宋','宋诗','song-poetry','','[]','時頒光祿酒，花出漢宮牆。',48,'全唐诗/poet.song.15000.json','["時頒光祿酒，花出漢宮牆。", "湛露承天渥，流霞落羽觴。", "近親龍尾道，遠襲雀頭香。", "溺殿人誰見，終知曼倩狂。"]'),
('5f654c57-de71-4f4a-a794-415515272c90','和范景仁王景彝殿中雜題三十八首並次韻 賜書','梅堯臣','宋','宋诗','song-poetry','','[]','選來金殿盡英豪，帝筆親承始是遭。',64,'全唐诗/poet.song.15000.json','["選來金殿盡英豪，帝筆親承始是遭。", "就裏少年唯賈誼，其間蜀客乃王襃。", "善經有意尊儒甚，推澤方知待士高。", "歸付子孫傳百世，深堂閒挂亦蕭騷。"]'),
('88ef06bd-2c48-4b19-ad7f-1a3a440cfb8f','和范景仁王景彝殿中雜題三十八首並次韻 賜燭','梅堯臣','宋','宋诗','song-poetry','','[]','天子賜燭昏夜時，嫦娥閉月栽桂枝。',144,'全唐诗/poet.song.15000.json','["天子賜燭昏夜時，嫦娥閉月栽桂枝。", "稱量高下唯妍辭，相與盡心無附離。", "求安去病如上池，照耀不容毫髮私。", "品藻一定何可移，光焰奪晝資爾爲。", "宣王徒美庭燎詩，魏帝自徹月殿披。", "我朝好士萬古垂，搜索賢俊登蒿藜。", "孰不力吐肝膽脾，枉用宴飲生脛脂。", "雲龍將見升騤騤，燃此必欲無所遺。", "收殘喜氣如蒸炊，蜜蜂慙愧空多知。"]'),
('604c61ce-6610-42d0-be8c-c58b60bf5055','和范景仁王景彝殿中雜題三十八首並次韻 賜果','梅堯臣','宋','宋诗','song-poetry','','[]','前日宮醪賜玉尊，今朝持果小黄門。',64,'全唐诗/poet.song.15000.json','["前日宮醪賜玉尊，今朝持果小黄門。", "乾桃熏李非時物，置案盈盤不次恩。", "投以赤心思武帝，握同玄璧詠劉琨。", "嘗聞食奠陳王業，知是豳公幾世孫。"]'),
('0421ea71-c7ed-47a0-904c-67cd57b8ef73','和范景仁王景彝殿中雜題三十八首並次韻 檜詠','梅堯臣','宋','宋诗','song-poetry','','[]','文章老重欲追古，便作帝宮蒼檜詩。',64,'全唐诗/poet.song.15000.json','["文章老重欲追古，便作帝宮蒼檜詩。", "青葱玉樹傳楊子，盤屈洪桃見左思。", "龍鱗已愛松身直，珠實還看柏葉垂。", "秀木豔叢那可擬，但將霜雪定堅姿。"]'),
('597dcf35-2d4d-49f8-8ce6-b03128775885','和范景仁王景彝殿中雜題三十八首並次韻 柳絮','梅堯臣','宋','宋诗','song-poetry','','[]','陶令生涯漉酒巾，門前種柳萬條新。',64,'全唐诗/poet.song.15000.json','["陶令生涯漉酒巾，門前種柳萬條新。", "花今吹作蓬萊雪，曲舊得於關塞人。", "應與殘紅閑是伴，不隨舞蝶去爭春。", "可憐輕質都無定，一落銀河莫問津。"]'),
('7f8379f5-c696-4a02-9bca-3bead5dbe0c4','和范景仁王景彝殿中雜題三十八首並次韻 殿後書事','梅堯臣','宋','宋诗','song-poetry','','[]','天子尋常幸直廬，裹頭宮女捧雕輿。',64,'全唐诗/poet.song.15000.json','["天子尋常幸直廬，裹頭宮女捧雕輿。", "紅泥已賜春醅酒，黄帕曾經御覽書。", "林果鳥應銜去後，燕窠蟲有落來餘。", "禁中事事能傳詠，播在人間不是虛。"]'),
('cfd03308-9880-47cf-92f4-20a3fd1ab2e6','和范景仁王景彝殿中雜題三十八首並次韻 雨夜','梅堯臣','宋','宋诗','song-poetry','','[]','電光初照樹峨峨，葉上微風與雨和。',64,'全唐诗/poet.song.15000.json','["電光初照樹峨峨，葉上微風與雨和。", "玉腕愁聞無處奈，庭花暗落不應多。", "長楊靜響千重瓦，太液寒生幾寸波。", "洗濯青春如有意，平明濕羽未離柯。"]'),
('459626ca-efa6-4695-9322-8d3f4d91beb3','和范景仁王景彝殿中雜題三十八首並次韻 景福殿水','梅堯臣','宋','宋诗','song-poetry','','[]','宮井蛟龍夭矯垂，曉缾初汲渴禽窺。',64,'全唐诗/poet.song.15000.json','["宮井蛟龍夭矯垂，曉缾初汲渴禽窺。", "清泠已向金盆貯，甘滑還從玉椀知。", "九醖酒醇由此得，小團茶味爲留遲。", "閤門地脈應相似，翰苑曾邀詠昔詩。"]'),
('5a27d70d-ac81-4c06-9a5a-ffbafd2a7448','和范景仁王景彝殿中雜題三十八首並次韻 雨後','梅堯臣','宋','宋诗','song-poetry','','[]','新晴殿閤曉，初日霧煙中。',48,'全唐诗/poet.song.15000.json','["新晴殿閤曉，初日霧煙中。", "柳重宮腰弱，花肥粉頰豐。", "渥恩君自厚，藜藿我纔充。", "草木欣欣發，誰知造化功。"]'),
('c0fc377c-f70e-424c-a58b-cfbba02e45fc','和范景仁王景彝殿中雜題三十八首並次韻 象戲','梅堯臣','宋','宋诗','song-poetry','','[]','象戲本從棋局爭，後宮龜背等人情。',64,'全唐诗/poet.song.15000.json','["象戲本從棋局爭，後宮龜背等人情。", "今聞儒者飽無事，亦學婦人閑鬭明。", "堂上有奇誰可勝，罇中賭酒令方行。", "直驅猛獸如尋邑，何似昇平不用兵。"]'),
('81a7bd07-854a-4155-b611-baff416c1063','和范景仁王景彝殿中雜題三十八首並次韻 再觀牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','聞說偷觀近玉欄，腸如車轂走千盤。',32,'全唐诗/poet.song.15000.json','["聞說偷觀近玉欄，腸如車轂走千盤。", "無人憶著洛陽日，走馬魏王堤上看。"]'),
('674929a2-6d6f-4616-ba74-b7fc59a227aa','和范景仁王景彝殿中雜題三十八首並次韻 白牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','白雲堆裏紫霞心，不與姚黄色鬭深。',32,'全唐诗/poet.song.15000.json','["白雲堆裏紫霞心，不與姚黄色鬭深。", "閒伴春風有時歇，豈能長在玉階陰。"]'),
('b2eab792-2158-42c6-9e58-4a5b3ec5b395','和范景仁王景彝殿中雜題三十八首並次韻 紫牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','葉底風吹紫錦囊，宮爐應近更添香。',32,'全唐诗/poet.song.15000.json','["葉底風吹紫錦囊，宮爐應近更添香。", "試看沉色濃如潑，不愧逢君翰墨場。"]'),
('72fcbf85-79ab-4e91-b3ef-ed920c487658','和范景仁王景彝殿中雜題三十八首並次韻 七寶茶','梅堯臣','宋','宋诗','song-poetry','','[]','七物甘香雜蕊茶，浮花泛綠亂於霞。',32,'全唐诗/poet.song.15000.json','["七物甘香雜蕊茶，浮花泛綠亂於霞。", "啜之始覺君恩重，休作尋常一等誇。"]'),
('35a6170e-6dd2-4a37-9905-bcbb4a96eb8d','和范景仁王景彝殿中雜題三十八首並次韻 庖烟','梅堯臣','宋','宋诗','song-poetry','','[]','羃歷庖烟出綵油，欲通雲霧未能周。',32,'全唐诗/poet.song.15000.json','["羃歷庖烟出綵油，欲通雲霧未能周。", "濕薪燒盡日停午，試問霏霏何處浮。"]'),
('4fd80a14-0408-4d5f-a319-889f6cd86b9f','和范景仁王景彝殿中雜題三十八首並次韻 省中','梅堯臣','宋','宋诗','song-poetry','','[]','漢相家人尚苦疑，不言溫室樹何枝。',32,'全唐诗/poet.song.15000.json','["漢相家人尚苦疑，不言溫室樹何枝。", "君今坦坦無猜忌，夸說皇居盡入詩。"]'),
('e50dc62b-4ade-49d2-9692-6d0fde48db11','和范景仁王景彝殿中雜題三十八首並次韻 天上','梅堯臣','宋','宋诗','song-poetry','','[]','紫微垣裏月光飛，玉佩腰間正陸離。',32,'全唐诗/poet.song.15000.json','["紫微垣裏月光飛，玉佩腰間正陸離。", "天上去來知幾日，蟠桃結子是歸時。"]'),
('a487eb06-1559-47fd-9971-3743ab8e920d','和范景仁王景彝殿中雜題三十八首並次韻 明月','梅堯臣','宋','宋诗','song-poetry','','[]','明月已生城上頭，小星光滅大星流。',32,'全唐诗/poet.song.15000.json','["明月已生城上頭，小星光滅大星流。", "來朝放牓出宮去，何處殘花轉入溝。"]'),
('060f2892-3cde-45e9-bbf8-862246406554','和范景仁王景彝殿中雜題三十八首並次韻 再賦','梅堯臣','宋','宋诗','song-poetry','','[]','誰人重詠大刀頭，只顧長明不願流。',32,'全唐诗/poet.song.15000.json','["誰人重詠大刀頭，只顧長明不願流。", "縱使西傾必東出，寧同寒水瀉宮溝。"]'),
('ab67daa6-44f9-486d-856a-8358be0dccdb','和范景仁王景彝殿中雜題三十八首並次韻 殿中飛','梅堯臣','宋','宋诗','song-poetry','','[]','玉几當中寶作牀，無端絮惹御袍香。',32,'全唐诗/poet.song.15000.json','["玉几當中寶作牀，無端絮惹御袍香。", "羣公唱第魚龍化，列侍金階若堵牆。"]'),
('8360b454-1c03-4ace-84a5-a18eddc2bb1a','次韻景彝春宴','梅堯臣','宋','宋诗','song-poetry','','[]','法座初瞻戶牖間，衮衣垂處見雲山。',64,'全唐诗/poet.song.15000.json','["法座初瞻戶牖間，衮衣垂處見雲山。", "滿斟玉酒傳宣盡，齊插宮花拜賜閒。", "紅線織成庭下毯，明珠結出耳中環。", "鬭雞旗底蓬蓬鼓，逐勝爭名利害關。"]'),
('29528138-d94a-46f1-9634-48848db308d7','次韻景彝三月十六日范景仁家同飲還省宿','梅堯臣','宋','宋诗','song-poetry','','[]','種桃依竹似僊家，邀對春風共泛霞。',64,'全唐诗/poet.song.15000.json','["種桃依竹似僊家，邀對春風共泛霞。", "席上未觀雙舞鳳，城頭已覺聚啼鴉。", "怱怱跨馬人歸省，羃羃生烟樹斂花。", "稚子候門知我醉，東方明月照扉斜。"]'),
('7b49c4c7-e2a3-48eb-9435-f4b2ed297f3d','次韻永叔試諸葛高筆戲書','梅堯臣','宋','宋诗','song-poetry','','[]','公負天下才，用心如用筆。',132,'全唐诗/poet.song.15000.json','["公負天下才，用心如用筆。", "端勁隨意行，曾無一畫失。", "因看落紙字，大小得疎密。", "筆工諸葛高，海內稱第一。", "頻年值我來，我媿不堪七。", "安能事墨研，欲效前人述。", "懶性真嵇康，閒坐喜捫蝨。", "是以持獻公，不使物受屈。", "果然公愛之，奇蹤寫名實。", "豈惟播今時，當亦傳異日。", "嗟哉試筆詩，藏不容人乞。"]'),
('a11ac1cc-f094-4e5b-affd-e0dda58a3002','唐書局叢莽中得芸香一本','梅堯臣','宋','宋诗','song-poetry','','[]','有芸如苜蓿，生在蓬藋中。',108,'全唐诗/poet.song.15000.json','["有芸如苜蓿，生在蓬藋中。", "草盛芸不長，馥烈隨微風。", "我來偶見之，乃穉彼蘙蒙。", "上當百雉城，南接文昌宮。", "借問此何地，刪修多鉅公。", "天喜書將成，不欲有蠹蟲。", "是産茲弱本，蒨爾發荒叢。", "黄花三四穗，結實植無窮。", "豈料鳳閣人，偏憐葵葉紅。"]'),
('7437a949-084b-410b-a294-ab3abb463bb5','嘲江翁還接籬','梅堯臣','宋','宋诗','song-poetry','','[]','何言恐偷樣，自是君婦懶。',24,'全唐诗/poet.song.15000.json','["何言恐偷樣，自是君婦懶。", "五日縫一巾，猶道苦未晚。"]'),
('e60fabde-f1ad-4d90-a12d-ae4f5872c12e','次韻景彝閣後紫薇花盛開','梅堯臣','宋','宋诗','song-poetry','','[]','禁中五月紫薇樹，閣後近聞都著花。',64,'全唐诗/poet.song.15000.json','["禁中五月紫薇樹，閣後近聞都著花。", "薄薄嫩膚搔鳥爪，離離碎葉剪晨霞。", "鳳皇浴去池波響，鳷鵲陰來日影斜。", "六十無名空執筆，顛毛應笑映簪華。"]'),
('71cc8df3-ed73-4329-974b-4d64f767b675','送李泰伯歸建昌','梅堯臣','宋','宋诗','song-poetry','','[]','推天以知命，自古豈不然。',216,'全唐诗/poet.song.15000.json','["推天以知命，自古豈不然。", "桓魋及臧倉，嘗毀聖與賢。", "後人何蹈之，其事實好還。", "君居麻源谷，學禮如鄭玄。", "聲名久已大，籍籍四海傳。", "昨因丞相舉，便謂升雲烟。", "朅來太學館，食貧向三年。", "忽懷枌榆下，歸思獨綿綿。", "得告許暫往，落莫求楚船。", "捋髯滄江上，仰看饑飛鳶。", "誰識鵷雛志，閒誦莊叟篇。", "喜問里中兒，重到舊林泉。", "洗蕩俗塵垢，焚烈跨馬韉。", "不向世路去，徒取悉腸煎。", "雞豚粗可養，禾黍亦足田。", "不慙莎衣蟲，以葉自包纏。", "及其飽滿時，曷異冠貂蟬。", "君意我强寫，雖慕何由緣。"]'),
('97784e43-01a8-48d0-b4b7-010cfe5f6d92','送林大年殿丞登第倅和州','梅堯臣','宋','宋诗','song-poetry','','[]','和靖先生負美才，族孫今似漢庭枚。',32,'全唐诗/poet.song.15000.json','["和靖先生負美才，族孫今似漢庭枚。", "敗亡項籍江邊廟，應媿文場戰勝來。"]'),
('6d2c8968-854e-41d0-b007-0d8bcba82146','王知章尉河內','梅堯臣','宋','宋诗','song-poetry','','[]','古縣太行下，老槐三四株。',48,'全唐诗/poet.song.15000.json','["古縣太行下，老槐三四株。", "以言新作吏，不似舊爲儒。", "黄綬心猶壯，青雲志豈無。", "漢朝吾遠祖，不道此官麤。"]'),
('eaab34c8-92b7-424d-88df-28d223853dac','送祖擇之赴陝府','梅堯臣','宋','宋诗','song-poetry','','[]','古來分陝重，猶有召公棠。',72,'全唐诗/poet.song.15000.json','["古來分陝重，猶有召公棠。", "此樹且能久，後人宜不忘。", "君從金馬去，郡在鐵牛旁。", "山色臨關險，河聲出地長。", "罇無空美酒，魚必薦嘉魴。", "天子憂民切，行當務勸桑。"]'),
('98dc8b52-21fc-44c9-a5c8-2b88edcb287a','中伏日永叔遺冰','梅堯臣','宋','宋诗','song-poetry','','[]','日色若炎火，正當三伏時。',144,'全唐诗/poet.song.15000.json','["日色若炎火，正當三伏時。", "盤冰賜近臣，絡繹中使馳。", "瑩澈肖水玉，凜氣侵人肌。", "近日多故友，分貺能者誰。", "信都顧貧賤，物物義不遺。", "念我老且病，赤疿生枯皮。", "巨塊置我前，凝結造化移。", "畏冷不敢食，有類夏蟲疑。", "雖然已快意，何必咀嚼爲。", "天子厚於公，不使熾毒欺。", "公亦厚於我，將恐煎熬隨。", "我有舐犢愛，自憐小子龜。"]'),
('683325c1-de0d-4460-b310-5d6d50918714','次韻和永叔贈別擇之赴陝郊','梅堯臣','宋','宋诗','song-poetry','','[]','古人相送贈以言，今人相送舉以酒。',144,'全唐诗/poet.song.15000.json','["古人相送贈以言，今人相送舉以酒。", "酒行殷勤意豈疎，酒罷躊躇悲更有。", "行當何之來者誰，陝府兵吏爭迎走。", "壺漿往往過函關，翰林惜別方携手。", "自言老大遇知難，願得公詩爲不朽。", "公因索筆作長謠，落落寓言誠十九。", "我慙竹管厠宮懸，縱合律度應非偶。", "太守西行已不貧，忽獲明珠盈大斗。", "歸立螭頭未是遲，暫向棠陰問遺叟。"]'),
('21919612-7a8e-4d5d-a0dd-a2b20868504f','送施縡秀才下第','梅堯臣','宋','宋诗','song-poetry','','[]','君嘗老於敵，輕彼羣兒嬉。',60,'全唐诗/poet.song.15000.json','["君嘗老於敵，輕彼羣兒嬉。", "堅銳不可恃，屢北還自疲。", "胸中多奇秘，既衂何所爲。", "東走滄海上，夏果采荔枝。", "奉親樂無涯，豈愧祿仕遲。"]'),
('a15f0ce2-a129-46e9-8dfe-4a021d4074b0','送張山甫武功簿','梅堯臣','宋','宋诗','song-poetry','','[]','洛陽舊交有七人，五人已爲泉下塵。',80,'全唐诗/poet.song.15000.json','["洛陽舊交有七人，五人已爲泉下塵。", "各家生兒爲門戶，唯子弟兄先立身。", "我與信都侯獨在，喜見及祿知天仁。", "昨日聞補武功吏，氣調欲與南山親。", "少年勉力向職事，莫學老貪文字新。"]'),
('e0a5f0ca-6e35-49d2-ba31-ea59dbe7cda7','送微上人歸省天台','梅堯臣','宋','宋诗','song-poetry','','[]','釋子懷慈母，吾儒未易輕。',48,'全唐诗/poet.song.15000.json','["釋子懷慈母，吾儒未易輕。", "不尋琪樹去，肯向石橋行。", "海近雲多潤，山高日少晴。", "天恩新賜服，書字欲傳名。"]'),
('941e6b19-0aab-46f2-87b4-ec3b4b9f64b3','寄天台梵才上人','梅堯臣','宋','宋诗','song-poetry','','[]','常觀月從東海出，想照石橋旁畔人。',32,'全唐诗/poet.song.15000.json','["常觀月從東海出，想照石橋旁畔人。", "試問當年與今日，清光不改只如新。"]'),
('53035290-ce6c-491d-8e51-ff7a30b2f54c','送李信臣尉節縣先歸湖州','梅堯臣','宋','宋诗','song-poetry','','[]','梁王吹臺側，五月多荷花。',60,'全唐诗/poet.song.15000.json','["梁王吹臺側，五月多荷花。", "荷開對翹鷺，吳客還思家。", "家在水中城，四面如鋪霞。", "焉能長相守，千里獨起嗟。", "補官東海上，物景莫言賒。"]'),
('f56cbf0f-c0ea-4b84-9675-7d9c5f5d3c07','送王巡檢之定海','梅堯臣','宋','宋诗','song-poetry','','[]','休淬鸊鵜劍，休調鵲血弓。',60,'全唐诗/poet.song.15000.json','["休淬鸊鵜劍，休調鵲血弓。", "平時自壯大，何所立戰功。", "得兵不滿百，防寇滄海東。", "駕船如飛鶻，出入巨浪中。", "苟能勇於此，遇敵無廢忠。"]'),
('d3a55bb0-c637-4031-ac89-5a27eb0ecfc5','謹賦','梅堯臣','宋','宋诗','song-poetry','','[]','避暑就高臺，不如就賢人。',96,'全唐诗/poet.song.15000.json','["避暑就高臺，不如就賢人。", "賢人若冰雪，論道通鬼神。", "自言信手書，字字事有因。", "往往得遺逸，烜赫見名臣。", "是日劉夫子，拍手氣益振。", "重覩太史公，吾徒幸來親。", "大笑舉玉杯，陶然任天真。", "內樂不復熱，豈以身爲身。"]'),
('67c4f4ea-c0a8-4312-a48b-27584c084bd3','來上人歸宣城兼柬太守孫學士','梅堯臣','宋','宋诗','song-poetry','','[]','李白不厭昭亭山，看盡飛鳥雲獨閒。',32,'全唐诗/poet.song.15000.json','["李白不厭昭亭山，看盡飛鳥雲獨閒。", "我今相送一懷想，想在謝公窗戶間。"]'),
('63a8ac72-4096-4156-a647-97d264be2464','始作燕子巾','梅堯臣','宋','宋诗','song-poetry','','[]','裹髻不裹額，自名燕子巾。',24,'全唐诗/poet.song.15000.json','["裹髻不裹額，自名燕子巾。", "翼覆尾涏涏，誰問巢由人。"]'),
('33a72809-643b-414c-8faf-7b2dcb8047d2','送侯孝傑殿丞簽判潞州','梅堯臣','宋','宋诗','song-poetry','','[]','同在洛陽時，交游盡豪傑。',168,'全唐诗/poet.song.15000.json','["同在洛陽時，交游盡豪傑。", "倏忽三十年，浮沈漸磨滅。", "惟餘一二人，或位冠夔禼。", "我今存若亡，似竹空有節。", "人皆欲吹置，老硬不可截。", "君自緱山來，別我不畏熱。", "言作潞從事，家貧祿仕切。", "六月上太行，辛勤非計拙。", "天當氣候凉，清風自騷屑。", "雖云數日勞，斗與炎蒸絕。", "君本公王孫，才行實修潔。", "鏘鏘發英聲，瑩瑩如佩玦。", "是爲君子器，終見不渝涅。", "相逢未易期，夢寐歸鼓枻。"]'),
('8df69061-1c49-4234-8fb6-1268ada17365','送張子野知虢州先歸湖州','梅堯臣','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','未赴虢太守，暫歸吳興家。',84,'全唐诗/poet.song.15000.json','["未赴虢太守，暫歸吳興家。", "吳興近洞庭，橘林正吹花。", "君當橘柚時，摘包带霜華。", "清甘不楚齒，若酒傾殘霞。", "谿山小女兒，姹姹兩髮丫。", "褭褭上氍毹，嘈嘈弄琵琶。", "是時與之醉，何似走塵沙。"]'),
('829b33ea-d022-49a4-8f4b-a5b298f8e026','送尹瞻駕部監靈仙觀','梅堯臣','宋','宋诗','song-poetry','','[]','天地如轉磨，屑屑今古人。',132,'全唐诗/poet.song.15000.json','["天地如轉磨，屑屑今古人。", "一落大化手，團品惟其新。", "不幸積不用，衮衮同埃塵。", "日月行何窮，過盡千萬春。", "人生占幾許，百歲猶比晨。", "君求灊山潛，捨去兩朱輪。", "願效陶淵明，翦紗爲破巾。", "山前溪多鱗，山下酒甚醇。", "看雲舉大杓，杓造舒州民。", "李白嘗愛之，死生曾與均。", "此志我亦有，更將猿鳥親。"]'),
('4273702d-8efd-4a8e-a5e2-cddcb72a9d10','送朱玠戶曹之廣德軍','梅堯臣','宋','宋诗','song-poetry','','[]','南方小兒纔讀書，往往得官呵路衢。',80,'全唐诗/poet.song.15000.json','["南方小兒纔讀書，往往得官呵路衢。", "君今五十始作掾，手板青袍非壯圖。", "況來桐汭水上城，折腰强顔休歎吁。", "城西古祠能致雨，歲不有旱民無逋。", "民樂未央君可娛，舊俗不與吾鄉殊。"]'),
('f9df834a-bbf9-4d9b-94ae-929c1ae78087','次韻和永叔原甫致齋集禧','梅堯臣','宋','宋诗','song-poetry','','[]','廟蠁靈祠屬二公，齊心相望切朱宮。',64,'全唐诗/poet.song.15000.json','["廟蠁靈祠屬二公，齊心相望切朱宮。", "綠渠繚繞壖垣水，廣沼清泠漲殿風。", "已詠應麟來五畤，仍歌翔雁雜殊翁。", "遥知畢事期尋勝，尚問衰羸未厭窮。"]'),
('cb683417-8068-4139-9e3c-d9e18a73addd','送王司徒定海監酒稅','梅堯臣','宋','宋诗','song-poetry','','[]','悠悠信風帆，杳杳向滄島。',48,'全唐诗/poet.song.15000.json','["悠悠信風帆，杳杳向滄島。", "商通遠國多，釀過東夷少。", "懷鄉寄書遲，見日知晨早。", "應聞有海花，何必樹萱草。"]'),
('34267110-1e76-451f-bcb4-d00b378a0ac0','端明李侍郎挽歌三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','少年爲侍從，名譽竟軒騰。',48,'全唐诗/poet.song.15000.json','["少年爲侍從，名譽竟軒騰。", "每吐胸中鳳，寧容筆上蠅。", "受釐延漢室，被謗過周陵。", "今日泉宮啟，師臣禮秩增。"]'),
('550482da-d1ba-4816-aef1-748dbec6f38f','端明李侍郎挽歌三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','官豈不爲達，其如望未充。',48,'全唐诗/poet.song.15000.json','["官豈不爲達，其如望未充。", "敏辭傾一代，發問詘三公。", "厭向承明直，思行邵伯風。", "嗟嗟玉樹折，埋沒彼蒿宮。"]'),
('d6e4bd9e-69d0-4877-b0b8-f0724f791ed0','端明李侍郎挽歌三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','秋樹無黄鳥，蟬聲亦自哀。',48,'全唐诗/poet.song.15000.json','["秋樹無黄鳥，蟬聲亦自哀。", "素車新隴去，白馬舊賓來。", "薤上朝陽露，池中歲刼灰。", "短長何足較，嗣子有高才。"]'),
('f1569fd3-5516-4bf4-87f7-3bfb2c401f59','次韻和永叔夜聞風聲有感','梅堯臣','宋','宋诗','song-poetry','','[]','月落夜正黑，風起庭槐端。',168,'全唐诗/poet.song.15000.json','["月落夜正黑，風起庭槐端。", "窗間星動摇，枕上人寤歎。", "所歎吹陰雲，苦熱彌不歡。", "當其氣莫出，曷若無衣寒。", "虛堂卧竹簟，汗體如露漙。", "驅蚊爇蒿艾，寧復襲芝蘭。", "煎灼一如此，衰枯誰可完。", "消磨任寒暑，安有不死丹。", "三伏已過二，炎赫應漸殘。", "試看蜣蜋蟲，辛勤方轉丸。", "焉得從釣舟，逆上嚴子湍。", "此事人所易，謝榮爲獨難。", "誰顧萬古名，黑石持鎸刊。", "風聲不用撼，牀頭閒素紈。"]'),
('52406648-b9aa-4fcf-8fc9-83e0dfe0c03d','次韻和永叔石枕與笛竹簟','梅堯臣','宋','宋诗','song-poetry','','[]','溪上枕部龍卵石，蘄匠簟製蛇皮紋。',288,'全唐诗/poet.song.15000.json','["溪上枕部龍卵石，蘄匠簟製蛇皮紋。", "客從東方一持贈，竹色蒸青石抱雲。", "磨沙斵骨自含潤，飽霜弔節無留塵。", "京師貴豪空有力，六月耐此炎蒸劇。", "旱風赤日吹熱來，大厦高簷任雕飾。", "頭顱汗匝無富貧，雖有頒冰論官職。", "官高職重冰則多，日永冰消難更得。", "唯公掃室施枕簟，迎凉自感東方客。", "東方客應非俗昏，能使賢人心體適。", "賢人何以偏伏人，天下才名方赫赫。", "我吟困窮不可聽，晝夜蚊蚋蒼蠅聲。", "蠅如遠雞耳初感，蚊若隠雷空際鳴。", "葛厨頂綻屋蝎墮，菅席中裂麻經橫。", "平生賦分只煎炒，安有祿玉琉璃清。", "猶勝昔年杜子美，老走耒陽牛炙死。", "因思楊惲廢時言，但願人生行樂爾。", "公今事業在朝廷，去就尤當慎終始。", "待公睡足秋風來，去奉高談揮麈尾。"]'),
('d9f11f00-d1f0-4440-b0fc-2dbba3a02d6c','寄題朱表臣職方真州新園','梅堯臣','宋','宋诗','song-poetry','','[]','青葱江上樹，杳藹宮前道。',48,'全唐诗/poet.song.15000.json','["青葱江上樹，杳藹宮前道。", "道側有新園，園中無惡草。", "松隴方在望，茅屋聞已考。", "朝廷正急才，何得言歸老。"]'),
('06d1afcc-50b2-4a44-bc33-7fae00837785','次韻和原甫閣下午寢晚歸見示','梅堯臣','宋','宋诗','song-poetry','','[]','殿閣風來夏日長，青林抽嫩見餘芳。',64,'全唐诗/poet.song.15000.json','["殿閣風來夏日長，青林抽嫩見餘芳。", "筆供五吏詞休敏，簟展雙紋睡正凉。", "故事早歸何獨晚，舊交新詠尚無忘。", "不言偃仰中園樂，還愛眉間喜色黄。"]'),
('e6ca31f4-e31d-4a8c-8122-05c267624e2d','三十二弟寺丞歸宣城因寄太守孫學士','梅堯臣','宋','宋诗','song-poetry','','[]','謝公下車日，郡內一登望。',96,'全唐诗/poet.song.15000.json','["謝公下車日，郡內一登望。", "昭亭山蒼蒼，寒溪水瀁瀁。", "句清宛微渾，三洲分細浪。", "小艇下灘來，羣鷗舞潭上。", "借問鷗何若，水深魚莫向。", "鷗餒猶識機，魚樂不忘餉。", "子去見太守，於我必有訪。", "但寄此薄言，罇前爲之唱。"]'),
('d8ff1346-a933-4be2-bf54-8bb6a19c3d01','送刁景純學士赴越州','梅堯臣','宋','宋诗','song-poetry','','[]','會稽迎太守，舟屋畫粉雘。',108,'全唐诗/poet.song.15000.json','["會稽迎太守，舟屋畫粉雘。", "前舟載圖書，後舟載女樂。", "月出鏡湖心，長笛使孤作。", "還見漁者來，曾令李謩愕。", "吹裂比竹管，士果不可度。", "二分學宮裝，艷色鬭京洛。", "嘗聞有西子，菡萏不相若。", "得郡考故跡，精絕古所怍。", "慎莫爲俗牽，乘閒數斟酌。"]'),
('bf071510-39e9-43b6-8160-7c32f613faea','送宋郎中知商州','梅堯臣','宋','宋诗','song-poetry','','[]','商於六百里，太守二千石。',72,'全唐诗/poet.song.15000.json','["商於六百里，太守二千石。", "地廣任亦重，車建旗仍赤。", "嘗聞四老人，采芝留舊跡。", "古廟藏空山，曾無漢羽翼。", "其事有圖畫，家傳多典籍。", "願君爲政閒，案覽知疇昔。"]'),
('242bead3-2785-4e6a-bc87-82d7b0b31c63','六月晦日定力院同原父賦送伯鎮景純樞言三學士','梅堯臣','宋','宋诗','song-poetry','','[]','清秋三黄鵠，舉翼東來飛。',48,'全唐诗/poet.song.15000.json','["清秋三黄鵠，舉翼東來飛。", "鳴聲既相呼，烟水亦相依。", "蓬池不暫止，太液未言歸。", "酌酒望滄海，飄颻思菊衣。"]'),
('3cd63044-2085-46c1-b126-b5b79ac14f6f','次韻和景彝省闈宿齋二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','晝日南宮雨後凉，齋嚴官重靜於常。',64,'全唐诗/poet.song.15000.json','["晝日南宮雨後凉，齋嚴官重靜於常。", "庭前鬭雀墮還起，欄下秋花落自香。", "看盡雲容天漏碧，讀殘書帙卷披黄。", "九衢塵土莫能到，蕭瑟微風葉響廊。"]'),
('033de74d-948f-4bbe-b503-22d046a3ea25','次韻和景彝省闈宿齋二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','新月斜光依約見，夜蟬高樹有時鳴。',64,'全唐诗/poet.song.15000.json','["新月斜光依約見，夜蟬高樹有時鳴。", "曲眉不想西家樣，餒腹還思二子清。", "迭代物華何足較，古今榮辱豈須驚。", "靜來應覺能閒少，人事區區逐日生。"]'),
('17027b43-87e6-4540-8a2a-90f13554c8d7','送刁景純知會稽','梅堯臣','宋','宋诗','song-poetry','','[]','前有朱翁子，後經王右軍。',48,'全唐诗/poet.song.15000.json','["前有朱翁子，後經王右軍。", "至今風俗美，自昔誦歌聞。", "秦望臨丹戟，耶溪漱白雲。", "只應絲管去，驚動海鷗羣。"]'),
('876069fe-2539-4ad5-88da-2b737c7b9f64','次韻答王景彝聞余月下與內飲','梅堯臣','宋','宋诗','song-poetry','','[]','仰頭看月見新鴻，形影雙飛玉鑑中。',32,'全唐诗/poet.song.15000.json','["仰頭看月見新鴻，形影雙飛玉鑑中。", "呼我作卿方舉酒，更煩佳句賞高風。"]'),
('6c97644e-2a23-475d-b598-3b3dc389e6a5','次韻和景彝對月','梅堯臣','宋','宋诗','song-poetry','','[]','蕭蕭風雨變凉意，索索晚雲開斗晴。',64,'全唐诗/poet.song.15000.json','["蕭蕭風雨變凉意，索索晚雲開斗晴。", "已洗浮埃天外靜，忽生圓月樹頭明。", "草根蟲穴吟來久，屋角星河落更清。", "我愧西垣侍臣比，景寒霜鬢兩三莖。"]'),
('43910a66-c3ac-4f63-b1f7-31aedcb656d4','和景彝西閣獨直','梅堯臣','宋','宋诗','song-poetry','','[]','池頭鳳皇寒，井上梧桐老。',96,'全唐诗/poet.song.15000.json','["池頭鳳皇寒，井上梧桐老。", "鳳寒浴已晚，桐老脫亦早。", "是時有詞臣，獨直正視藁。", "嚴嚴代王言，落落奮清藻。", "演成五色絲，世作非常寶。", "貶如市朝撻，襃若華衮好。", "四方號令施，萬耳昏聾掃。", "此職唯其才，用居寧草草。"]'),
('5b9be7f4-5b4c-4585-bb9f-10953a51af7b','次韻景彝奉慈廟孟秋攝事二十韻','梅堯臣','宋','宋诗','song-poetry','','[]','閟宮初告饗，駕輅已迎秋。',240,'全唐诗/poet.song.15000.json','["閟宮初告饗，駕輅已迎秋。", "公衮惟時攝，齋廬用爾休。", "椒漿茲往奠，鸞馭或來游。", "任姒徽音繼，邦家故事脩。", "前期嚴受誓，侵曉肅傳騶。", "雞狗藏深戶，蚊蠅響暗溝。", "別祠緣相漢，舊禮傚宗周。", "蕭氣接庭燎，鼓聲通市樓。", "樂章分廟奏，牲物用毛柔。", "木主升新座，牙盤列庶羞。", "叩階除劍履，宿羽動梧楸。", "錫胙人移俎，焚辭漏晝籌。", "豆籩將降陛，胥史劇奔牛。", "事畢歸烏巷，陰餘晦綵油。", "驅車多叱咤，負擔起歌謳。", "却直中書省，重瞻十二旒。", "詞供五更敏，詔示四方優。", "密議存王體，斜封贊禹謀。", "勤誠酬異等，潤色闡嘉猷。", "强擬鄴中詠，我思康樂侯。"]'),
('456dbf77-838b-4320-ada6-cb10d1b0a620','次韻和景彝秋興','梅堯臣','宋','宋诗','song-poetry','','[]','日月機上梭，年華東注波。',48,'全唐诗/poet.song.15000.json','["日月機上梭，年華東注波。", "未驚凉葉墜，已見白髮多。", "牧馬歸方健，調弓力漸和。", "籬邊賸曉菊，陶令奈貧何。"]'),
('a2eb7971-dd8e-4675-8d6b-38392e9cf6b3','司徒陳公挽詞二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','位至三公有，恩加賜謚無。',48,'全唐诗/poet.song.15000.json','["位至三公有，恩加賜謚無。", "再調金鉉鼎，屢剖玉麟符。", "已歎鸞同穴，還嗟鳳欠雛。", "擁途看鹵部，誰爲畢三虞。"]'),
('5b266c2f-ec01-4518-9d9d-bc0f0f3afd0a','司徒陳公挽詞二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','公在中書日，朝廷百事崇。',48,'全唐诗/poet.song.15000.json','["公在中書日，朝廷百事崇。", "王官多不喜，天子以爲忠。", "富貴人間少，恩榮歿更隆。", "若非笳鼓咽，寂寞奈秋風。"]'),
('c5de79b7-381d-4cf2-b0e6-c0213c12416b','秋思','梅堯臣','宋','宋诗','song-poetry','','[]','梧桐在井上，蟋蟀在牀下。',48,'全唐诗/poet.song.15000.json','["梧桐在井上，蟋蟀在牀下。", "物情有與無，節候不相假。", "寥寥風動葉，颯颯雨墮瓦。", "耳聽心自靜，誰是忘懷者。"]'),
('731be1a2-eab8-4238-b4b4-43f43432486d','送葉都官赴蜀州倅','梅堯臣','宋','宋诗','song-poetry','','[]','每有人之蜀，先憑問海棠。',48,'全唐诗/poet.song.15000.json','["每有人之蜀，先憑問海棠。", "徒知花底醉，不報樹頭芳。", "上馬秋風急，登山古路長。", "西南生片月，遥想見清光。"]'),
('c84f7436-8355-4cef-ae88-84795fd3236b','次韻答吳長文內翰遺石器八十八件','梅堯臣','宋','宋诗','song-poetry','','[]','山工日斵器，殊匪事樵牧。',120,'全唐诗/poet.song.15000.json','["山工日斵器，殊匪事樵牧。", "掘地取雲根，剖堅如剖玉。", "食具與果具，待賓良有勗。", "亦將茶具并，飽啜時出俗。", "公何都贈予，金多不入目。", "我家固宜之，瓦椀居漏屋。", "得此尤稱窮，客來無不足。", "唯應赤脚婢，收拾怨常酷。", "夏席堆青齏，冬盤飣旨蓄。", "竟無粱肉饌，甚愧蕭家錄。"]'),
('a08c2293-6cdd-4723-99be-ce5d5576e5da','送張君儀太祝簽判奉寧軍','梅堯臣','宋','宋诗','song-poetry','','[]','社雨燕巢空，古陂菱葉老。',72,'全唐诗/poet.song.15000.json','["社雨燕巢空，古陂菱葉老。", "燕去春當還，菱枯秋不早。", "莫以西風高，於焉亂懷抱。", "指途無幾里，駛馬一秣草。", "彼美賢主公，文章爲世寶。", "笑談樽俎間，勿負風月好。"]'),
('e16ca29e-c937-420e-bb08-0937ecfb9ed7','寄題陽武宰王安之慶豐亭','梅堯臣','宋','宋诗','song-poetry','','[]','官爲人父母，身自奉其親。',96,'全唐诗/poet.song.15000.json','["官爲人父母，身自奉其親。", "結宇後園中，散步以怡神。", "寒溫適所適，朝夕饋爾珍。", "諸孫同在傍，嬉戲情各均。", "庭下香草秀，梁中乳鳥馴。", "乳鳥名曰烏，反哺豈不仁。", "香茶名曰蘭，相襲使之紉。", "二物已可知，百里風俗淳。"]'),
('5a225bc9-3897-483f-967d-70ac7883d9bb','北州人有致達頭魚于永叔者素未聞其名蓋海魚也分以爲遺聊知異物耳因感而成詠','梅堯臣','宋','宋诗','song-poetry','','[]','孰云北海魚，乃與東溟異。',72,'全唐诗/poet.song.15000.json','["孰云北海魚，乃與東溟異。", "適聞達頭乾，偶得書尾寄。", "枯鱗冒輕雪，登俎爲厚味。", "向來昧知名，漁官疑竊位。", "有如臧文仲，不與柳下惠。", "從茲入杯盤，應莫慙鮑肆。"]'),
('4589e9c2-1822-4ff7-bff9-a3f8c1d3999a','送柳秘丞大名知錄','梅堯臣','宋','宋诗','song-poetry','','[]','言今魏都去，聽我願少休。',108,'全唐诗/poet.song.15000.json','["言今魏都去，聽我願少休。", "地息戎馬牧，民苦黄河流。", "渾渾發西極，奮奮入九州。", "自古患决溢，于今爲瘡疣。", "禹力順而東，漢防築其陬。", "完壞非一日，利害經千秋。", "主印無切責，治水莫輕謀。", "府公山西種，貴已爲通侯。", "樽酒與歌舞，上客共優游。"]'),
('eccb9d3b-77a6-4fdc-96c5-1032042d5f51','送何都官通判虔州','梅堯臣','宋','宋诗','song-poetry','','[]','楚越封圻接，帆檣上下頻。',48,'全唐诗/poet.song.15000.json','["楚越封圻接，帆檣上下頻。", "商通洲橘熟，信到嶺梅春。", "白紵歌脩頸，金盤饋紫鱗。", "同勤太守職，龔遂漢名臣。"]'),
('1123bdcd-4050-450c-a0cb-dc9344724fb7','秋雷','梅堯臣','宋','宋诗','song-poetry','','[]','春雷不發蟄，秋雷不收聲。',144,'全唐诗/poet.song.15000.json','["春雷不發蟄，秋雷不收聲。", "向無一日雨，今無一日晴。", "昨夕玉女笑，閃閃揚目睛。", "雷公與雨師，自取號令明。", "舒慘由上天，誕妄推五行。", "日月不粒食，安問下土耕。", "雖然屋瓦爛，還有地菌生。", "損彼以益此，誰能較人情。", "堯時不無水，用禹水乃平。", "黎民思堯仁，往往見於羹。", "猶吾大君意，星火立水衡。", "水衡雖努力，豈將雷雨爭。"]'),
('2e389e74-2d39-4c2e-bc13-9e9365343096','送俞尚寺丞知蘄春縣','梅堯臣','宋','宋诗','song-poetry','','[]','應見言風物，於今有貢蛇。',48,'全唐诗/poet.song.15000.json','["應見言風物，於今有貢蛇。", "潛蹤遠蛙黽，飲露上蒹葭。", "清潔一如此，傷殘都莫涯。", "君惟修職業，男耒女繰車。"]'),
('690499fc-2961-4598-840e-fac5f97a4e9c','和劉原甫白鸚鵡','梅堯臣','宋','宋诗','song-poetry','','[]','能言異國鳥，來與舶帆飄。',48,'全唐诗/poet.song.15000.json','["能言異國鳥，來與舶帆飄。", "嘗過西王母，曾殊北海鰩。", "雪衣應不妬，隴客幸相饒。", "因憶禰處士，舊洲蘭蕙凋。"]'),
('b16b4da1-7b08-4548-bd44-ce9fdc22fbb1','送劉定賢良下第赴廣陵令','梅堯臣','宋','宋诗','song-poetry','','[]','劉蕡不登科，衆口誦其策。',156,'全唐诗/poet.song.15000.json','["劉蕡不登科，衆口誦其策。", "得者爲之羞，聞者爲之惜。", "摧藏一時屈，論議千古白。", "至今簡篇中，一字不敢易。", "其言究時病，舂刺若戈戟。", "引經見大法，非蹈春秋僻。", "我朝屢得人，無不陞顯赫。", "乃知所中否，實命繫通厄。", "中則首公相，人情作冠幘。", "否則走仕塗，人情作履舄。", "秋風廣陵城，千里夷門客。", "壯心雖暫失，美寶有時獲。", "怊悵以送君，致龍翻點額。"]'),
('8456880f-0486-4c7b-b2ee-3002cd06fa74','九日永叔長文原甫景仁鄰幾持國過飲','梅堯臣','宋','宋诗','song-poetry','','[]','秋堂雨更靜，佳菊粲粲芳。',48,'全唐诗/poet.song.15000.json','["秋堂雨更靜，佳菊粲粲芳。", "置酒延羣公，掇英浮新黄。", "心猶慕淵明，歸來醉柴桑。", "莫問車馬之，去跡亂康莊。"]'),
('e4e6e421-9028-4c65-a272-e5fc9af57b87','送鮑都官錢塘通判','梅堯臣','宋','宋诗','song-poetry','','[]','文鰩游西海，夕飛向吳洲。',60,'全唐诗/poet.song.15000.json','["文鰩游西海，夕飛向吳洲。", "朱鼈生明月，淵潛未可求。", "由來有變化，何能計沉浮。", "君子蹈出處，誰能等隅陬。", "臨水賦二者，相送無離憂。"]'),
('83b74a00-9210-47f4-a171-6998373c022c','送通州通判刁國博','梅堯臣','宋','宋诗','song-poetry','','[]','古郡見郎山，海雲遮一半。',108,'全唐诗/poet.song.15000.json','["古郡見郎山，海雲遮一半。", "陽烏出滄波，光彩臨硯桉。", "小吏抱牘來，磨墨爲點竄。", "豈以島嶼人，百事皆漫漫。", "朝廷通守任，不使守專斷。", "是恐繆其才，民勞乃生亂。", "辛勤雖然多，魚蟹莫知筭。", "夜月上蓬瀛，偷閒舉杯看。", "因行計較足，少別休興歎。"]'),
('1c98dbb0-bfcd-4b00-b77b-033a7eb8e462','吳資政挽詞二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','天下文章老，爲公地底銘。',48,'全唐诗/poet.song.15000.json','["天下文章老，爲公地底銘。", "平生懷道德，鋪寫若丹青。", "蒲市一朝罷，洛人皆淚零。", "嗟嗟廟堂貴，今以柏爲庭。"]'),
('8e62e018-0eac-450f-9a7d-7912aa8ceb66','吳資政挽詞二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','峨峨陘土厚，自古葬賢人。',48,'全唐诗/poet.song.15000.json','["峨峨陘土厚，自古葬賢人。", "百尺不逢水，千年空閉春。", "夜臺埋琬琰，隴道刻騏驎。", "西望緣纓淚，曾無幕府賓。"]'),
('e8c4c0b3-96b1-4b7f-85e4-f59039de5098','九月二十四日大風','梅堯臣','宋','宋诗','song-poetry','','[]','秋飈無蹤跡，空中聲奔馳。',48,'全唐诗/poet.song.15000.json','["秋飈無蹤跡，空中聲奔馳。", "枯桑因已驗，老病仍先知。", "驚沙入破隙，危葉墮綠枝。", "幽懷聒不寐，山岳將恐移。"]'),
('be79f9b6-4ff1-4a51-949d-117cf3ad26a2','二十五日雪','梅堯臣','宋','宋诗','song-poetry','','[]','秋露未爲霜，秋空已飛雪。',48,'全唐诗/poet.song.15000.json','["秋露未爲霜，秋空已飛雪。", "著樹增葉危，壓叢憂菊折。", "平明開戶看，斗覺頹簷潔。", "天時莫蒼猝，誰預衣裘設。"]'),
('cb4df29f-a0fc-4b7b-af62-7266ff005ec0','送唐待制子方北使','梅堯臣','宋','宋诗','song-poetry','','[]','王命來天外，閼氏坐帳中。',48,'全唐诗/poet.song.15000.json','["王命來天外，閼氏坐帳中。", "儀雖聘鄰國，禮豈異和戎。", "漢使方持節，胡人自带弓。", "唯應沙漠凜，不減諫臣風。"]'),
('2660a75a-52e6-4de9-8c15-760abaf746a5','送劉元忠學士歸陳州省親','梅堯臣','宋','宋诗','song-poetry','','[]','芸香閒秘秩，蘇合著新裘。',48,'全唐诗/poet.song.15000.json','["芸香閒秘秩，蘇合著新裘。", "公子言歸日，天王賜問優。", "治分周太宰，禮重漢諸侯。", "拜慶無如樂，黄金作酒舟。"]'),
('81ca7cb0-3e1d-45b3-8edd-4ab08cd1aa7f','送陳賢良忠正軍簽判','梅堯臣','宋','宋诗','song-poetry','','[]','書對三千字，恩科第一人。',48,'全唐诗/poet.song.15000.json','["書對三千字，恩科第一人。", "鯤魚飛北海，龍劍躍平津。", "直悟聰文主，深論險尅臣。", "已能明世弊，枉作幕中賓。"]'),
('bac2abb4-6d3c-41a0-8459-fb49d26310d6','送韓持正寺丞知餘姚','梅堯臣','宋','宋诗','song-poetry','','[]','君家二仲父，連爲吳越宰。',48,'全唐诗/poet.song.15000.json','["君家二仲父，連爲吳越宰。", "錢唐與蕭山，治跡應無改。", "魚蝦莫厭腥，網罟從人采。", "天晴姚江深，縣鼓朝翻海。"]'),
('9041a411-556f-4c75-bbd8-59fa61bbc385','送周介之學士通判定州','梅堯臣','宋','宋诗','song-poetry','','[]','相公秉文武，視卒如嬰兒。',180,'全唐诗/poet.song.15000.json','["相公秉文武，視卒如嬰兒。", "今往佐其軍，豈不重撫綏。", "我有愚者慮，贈君臨路岐。", "相公居并州，拓土曾不疑。", "羌戎起潛變，一旦覆我師。", "我師無不勇，將吏實易之。", "常抱雪恥志，此旨君所知。", "兵家尤戒貪，持重養以威。", "正當土門路，自昔屯虎貔。", "朔朝及旬望，大校飫酒巵。", "未若投單醪，共飲河水湄。", "古人維其均，今人意參差。", "臨事欲之死，身往心已移。", "上能同甘苦，下必同安危。", "願君因議論，茲語何難爲。"]'),
('1394155c-2fe6-4841-8dcf-229dfb1ed745','送番禺杜桿主簿','梅堯臣','宋','宋诗','song-poetry','','[]','行識桄榔樹，初窺翡翠巢。',48,'全唐诗/poet.song.15000.json','["行識桄榔樹，初窺翡翠巢。", "地蒸蠻雨接，山潤海雲交。", "訟少通華語，蟲多入膳庖。", "不須思朔雪，梅吐臘前梢。"]'),
('c52effe1-b207-4e1e-b420-19b6422b312a','還柳瑾秘丞詩編','梅堯臣','宋','宋诗','song-poetry','','[]','吾友蘇子美，聞昔許君詩。',84,'全唐诗/poet.song.15000.json','["吾友蘇子美，聞昔許君詩。", "子美今下世，令人重嗟咨。", "當其不得志，泥水蟠蛟螭。", "未激西海流，安可氣吐霓。", "吳洲逢朱鼈，腹有百碧遺。", "他時使我觀，我觀顔忸怩。", "便欲焚筆硯，奈何難爭馳。"]'),
('d86527d2-6b5e-4f99-8821-c8fa30a248fc','送張殿丞吉甫知資陽','梅堯臣','宋','宋诗','song-poetry','','[]','單騎欲之蜀，綵衣初過秦。',48,'全唐诗/poet.song.15000.json','["單騎欲之蜀，綵衣初過秦。", "王喬鳬是舄，陶令酒名巾。", "灞上愁逢雪，襃中喜見春。", "兩川風物美，不似走京塵。"]'),
('e303aaa3-8e2a-4163-a21f-7ac03b14a47d','丁端公北使','梅堯臣','宋','宋诗','song-poetry','','[]','山聘天王使，來乘御史驄。',48,'全唐诗/poet.song.15000.json','["山聘天王使，來乘御史驄。", "馳車看燕婦，貂扇禦胡風。", "俗與華人似，言從左衽通。", "罽庭觀拜舞，不似未央中。"]'),
('3bf34761-479d-4d48-82f3-9f24e5707985','張斯立遂州司理','梅堯臣','宋','宋诗','song-poetry','','[]','自身買馬箠，爲婦置羃䍦。',108,'全唐诗/poet.song.15000.json','["自身買馬箠，爲婦置羃䍦。", "將出咸陽門，同涉蜀道危。", "疇昔未祿仕，日夕講書詩。", "不能青雲高，乃作黄綬卑。", "前人未遇時，往往甘棲遲。", "如築九層臺，始起一板基。", "雖然用功深，歲久終莫隳。", "我今惜君行，無力可致之。", "去勿藉芳草，世俗多夸毗。"]'),
('829a6919-85ad-4151-a597-13365964b5c8','寄題哀賢亭','梅堯臣','宋','宋诗','song-poetry','','[]','蒼蒼墓門樹，亦有黄鳥哀。',48,'全唐诗/poet.song.15000.json','["蒼蒼墓門樹，亦有黄鳥哀。", "賢者不在世，常恨埋蒿萊。", "山根入溪泉，流響出夜臺。", "東方見子胥，助濤高崔嵬。"]'),
('0a2318ef-8b8b-489e-8838-60f58be44cc5','答建州沈屯田寄新茶','梅堯臣','宋','宋诗','song-poetry','','[]','春芽研白膏，夜火焙紫餠。',48,'全唐诗/poet.song.15000.json','["春芽研白膏，夜火焙紫餠。", "價與黄金齊，包開青蒻整。", "碾爲玉色塵，遠及蘆底井。", "一啜同醉翁，思君聊引領。"]'),
('7ae129ab-24e4-49b0-a99d-4ac004528e8f','送曹測崇班駐泊相州','梅堯臣','宋','宋诗','song-poetry','','[]','知君鄴城去，歷覽古時蹟。',192,'全唐诗/poet.song.15000.json','["知君鄴城去，歷覽古時蹟。", "峨峨銅雀臺，其下遺瓦礫。", "不化鴛鴦飛，多近蟾蜍滴。", "哀哉魏武帝，雄智圖九錫。", "俄聞望西陵，作妓向朝夕。", "曾何百年間，事往如霹靂。", "空餘幾仞土，陰峭古蘚碧。", "下有牧羊人，上有牂與䍽。", "寒風吹枯草，草短聲剌剌。", "珠翠爲埃塵，冠劍埋百尺。", "顔回飲一瓢，仲尼不暖席。", "擁徒食人肝，生莫如盜跖。", "令名今猶存，焉在刻金石。", "我輩當太平，白首如戰敵。", "又知爲善樂，尚媿苟仕籍。", "行行勤撫兵，豎威酬德澤。"]'),
('e783150f-c00e-4b86-84e3-b3ba15884e8b','十一月二十三日歐陽永叔劉原甫范景仁何聖徒見訪之什','梅堯臣','宋','宋诗','song-poetry','','[]','夷門魏公子，來過抱關人。',144,'全唐诗/poet.song.15000.json','["夷門魏公子，來過抱關人。", "車馬立市中，貴義不恥貧。", "市人無不驚，此老面黧皴。", "豈將流俗眼，能辨玉與珉。", "爾後幾千載，此賢埋埃塵。", "誰謂四君子，蹈古猶比辰。", "上馬後苑門，訪我東城闉。", "爲公開蓬戶，沽酒焚紫鱗。", "銀杯青石盤，共飲不計巡。", "薄暮各已醉，歡笑頹冠巾。", "來既無猜嫌，去亦無疎親。", "曷若世上士，惟顧勢力均。"]'),
('501f4e7c-c2ec-4492-9c6b-c73d36d94bd7','次韻和原甫陪永叔景仁聖徒飲余家題庭中枯菊之什','梅堯臣','宋','宋诗','song-poetry','','[]','九月車馬過，我庭黄菊鮮。',144,'全唐诗/poet.song.15000.json','["九月車馬過，我庭黄菊鮮。", "重來踰七旬，枯萼無復妍。", "自非凌霜操，枝葉徒相連。", "衰敗未忍去，根荄尚翹然。", "不意憔悴叢，猶爲君子憐。", "固值時節晚，豈恨地勢偏。", "直如木上蘿，緣蔓欲到天。", "一朝風雪厲，零落向暮年。", "至此事乃等，高低復何言。", "公休誇松柏，彭祖與顔淵。", "各不相健羨，焉能論柔堅。", "願公時飲酒，周孔今下泉。"]'),
('e20ad1e4-a788-49dd-bd10-80ab682bf1c8','次韻和永叔飲余家詠枯菊','梅堯臣','宋','宋诗','song-poetry','','[]','今年重陽公欲來，旋種中庭已開菊。',192,'全唐诗/poet.song.15000.json','["今年重陽公欲來，旋種中庭已開菊。", "黄金碎翦千萬層，小樹婆娑嘉趣足。", "鬢頭插蕊惜光煇，酒面浮英愛芬馥。", "旋種旋摘趁時候，相笑相尋不拘束。", "各看華髮已垂顛，豈更少年苔色綠。", "自茲七十有三日，公又連鑣入余屋。", "堦傍猶見舊枯叢，根底青芽歡催促。", "但能置酒與公酌，獨欠琵琶彈啄木。", "所歎坐客盡豪英，槐上凍鴟偷側目。", "盤中有肉鴟伺之，烏鳥不知啼觜曲。", "諸公醉思索筆吟，吾兒暗寫千毫禿。", "明日持詩小吏忙，未解宿酲聊和屬。"]'),
('29d0c7f5-c762-43e4-b1ee-108e2e4c3f67','送李獻甫寺丞知虹縣先歸金陵','梅堯臣','宋','宋诗','song-poetry','','[]','今日歸爲美，塗金作馬纓。',48,'全唐诗/poet.song.15000.json','["今日歸爲美，塗金作馬纓。", "願言膏沐婦，相望石頭城。", "得邑柳堤合，還家梅野晴。", "里中多樂事，州牧是名卿。"]'),
('395d42ba-aed1-4570-bdfa-384b8daf4538','衛尉邵少卿挽詞二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','位至九卿亞，年過七十春。',48,'全唐诗/poet.song.15000.json','["位至九卿亞，年過七十春。", "桐鄉歸葬日，棠樹去思人。", "霧裏開蒿隧，原邊起石麟。", "地遥徒有淚，灑向北風頻。"]'),
('3e10faa2-9470-4ab9-8c32-8b68b27797a3','衛尉邵少卿挽詞二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','買得吳門宅，歸來自種花。',48,'全唐诗/poet.song.15000.json','["買得吳門宅，歸來自種花。", "春風未歌徹，東岱已魂賒。", "昔作千年調，今爲一日嗟。", "人將鎸美德，磨石取江沙。"]'),
('b4fdf86f-3052-4d44-9fe4-8c8959da0bca','次韻和永叔對雪十韻','梅堯臣','宋','宋诗','song-poetry','','[]','紛紛何亂目，凜凜自開門。',120,'全唐诗/poet.song.15000.json','["紛紛何亂目，凜凜自開門。", "著莫風難定，侵凌物已繁。", "裝成新樹色，遮盡古苔痕。", "冷入梁王苑，清乘衛國軒。", "欺貧凍蓬蓽，增險想轘轅。", "小隙皆能及，洪爐逼不溫。", "雲衣隨處積，水甲等閒屯。", "團戲爲丸轉，堆雕作獸蹲。", "豈愁空破履，幸喜有清樽。", "誰問諸公子，高樓與後園。"]'),
('6a9bf7f4-8421-4a3d-a7ae-b8edc2ac080d','寄題劉仲叟澤州園亭','梅堯臣','宋','宋诗','song-poetry','','[]','城臨太行谷，谷暖宜草木。',132,'全唐诗/poet.song.15000.json','["城臨太行谷，谷暖宜草木。", "既移洛陽花，又種阮家竹。", "五色雜黄紅，一林常翠綠。", "其間廣亭開，亦欲危榭築。", "春歸百禽嚎，摶黍及布穀。", "桑上啄椹食，林下窺果熟。", "果收椹已盡，飛去不須逐。", "婆娑黄楊樹，誰謂逢閏縮。", "物猶有進退，此理何用告。", "余心當郊君，未有地可卜。", "綴書豈貪樂，且以苟微祿。"]'),
('90c51b9f-ee07-4958-9039-597c891a1bbc','送李灝秀才南歸','梅堯臣','宋','宋诗','song-poetry','','[]','乘馿雪中來，別我千里歸。',48,'全唐诗/poet.song.15000.json','["乘馿雪中來，別我千里歸。", "江南梅花發，身與越烏飛。", "幾年客大梁，著盡篋中衣。", "空餘一束書，去恨識者稀。"]'),
('3d7584db-6c3d-402c-bf09-6f9989820b9e','送刁經臣歸潤州兼寄曇師','梅堯臣','宋','宋诗','song-poetry','','[]','古來山林士，一往不復返。',108,'全唐诗/poet.song.15000.json','["古來山林士，一往不復返。", "區區世上名，豈畢車自挽。", "前有高山危，後有落日晚。", "未知所止息，已慕田家飯。", "愛君京口歸，萬事不著眼。", "乘馬飾鞍轡，乘舟畫屋版。", "長途與白浪，健駛固莫限。", "力殫風定時，各各繫岸棧。", "寄語老空人，青崖勿鋤剗。"]'),
('487bb561-91c2-42d0-b7ef-fb7fe6117970','贈狄梁公十二代孫國賓','梅堯臣','宋','宋诗','song-poetry','','[]','雄雉飛上天，牝雉白日鳴。',108,'全唐诗/poet.song.15000.json','["雄雉飛上天，牝雉白日鳴。", "驅逐鳳皇雛，百鳥不出聲。", "豈無雕與鶚，至死莫得爭。", "孤鶴獨不懼，使風羽翼成。", "鶴性本君子，嘹唳通太清。", "至今有其孫，踉蹌田中行。", "明時與稻粱，重節亦貴名。", "爾無沖天力，且與鶖鶬并。", "慎勿啄泥穢，坐使白鷺輕。"]'),
('4aacf469-1502-4c15-8c11-dcdc6e63eed4','寄金山曇穎師呈永叔內翰','梅堯臣','宋','宋诗','song-poetry','','[]','江中峨峨山，上有道人住。',108,'全唐诗/poet.song.15000.json','["江中峨峨山，上有道人住。", "風濤響殿閣，雲霧生席屨。", "道人如不聞，道人如不顧。", "誰能識此心，來往只鷗鷺。", "京洛三十年，塵埃一相遇。", "我與信都公，已落衣冠故。", "平生守仁義，齒髮忽衰暮。", "世事不我拘，自有浩然趣。", "未由逢故人，坐石語平素。"]'),
('ad430cd9-b21e-4d3b-8234-093395a1f1a9','寄題刁經臣潤州園亭','梅堯臣','宋','宋诗','song-poetry','','[]','新作城邊圃，陂原上下斜。',48,'全唐诗/poet.song.15000.json','["新作城邊圃，陂原上下斜。", "竹多劉裕宅，松接戴顒家。", "山色不須買，江流何處涯。", "但邀東海月，莫聽五更鴉。"]'),
('d12cf5c2-b3a2-47bc-a5d4-2c75cca40bd5','次韻和永叔夜坐鼓琴有感二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','夜坐彈玉琴，琴韻與指隨。',60,'全唐诗/poet.song.15000.json','["夜坐彈玉琴，琴韻與指隨。", "不辭再三彈，但恨世少知。", "知公愛陶潛，全身衰弊時。", "有琴不安絃，與俗異所爲。", "寂然得真趣，乃至無言期。"]'),
('090b433c-0501-474c-a5ea-c65d12cfce2d','次韻和永叔夜坐鼓琴有感二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','舜琴曰朕有，語舜鬰陶乎。',84,'全唐诗/poet.song.15000.json','["舜琴曰朕有，語舜鬰陶乎。", "孝悌怨則否，傲狠愧豈無。", "我嘗撫卷歎，歎此孟氏書。", "此書有深意，仁義世久虛。", "公今乃有感，其不在茲歟。", "魚躍與鶴舞，物情曾未殊。", "無情則無應，何必問鳥魚。"]'),
('679fe48c-784e-4ad1-8171-1a2c2a98e24d','李尚書挽詞二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','相門三世貴，家法百年同。',48,'全唐诗/poet.song.15000.json','["相門三世貴，家法百年同。", "天子賜恩禮，史臣書祖風。", "笳聲空苦霧，隴穴啟寒蓬。", "自古焉能免，於茲是始終。"]'),
('bcdb0ba1-b51b-4dfa-a5f4-80c600c9ee70','李尚書挽詞二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','伊水西頭月，青山北脚雲。',48,'全唐诗/poet.song.15000.json','["伊水西頭月，青山北脚雲。", "夜臺無復曉，陰嶺有時熏。", "龍劍雙埋沒，庭蘭竟鬰芬。", "不知門下客，誰刻道傍文。"]'),
('a5732fb2-2653-442f-90d5-c34b780f975f','送朱司封知登州','梅堯臣','宋','宋诗','song-poetry','','[]','駕言發夷門，東方守牟城。',84,'全唐诗/poet.song.15000.json','["駕言發夷門，東方守牟城。", "城臨滄海上，不厭風濤聲。", "海市有時望，閭屋空虛生。", "車馬或隠見，人物亦縱橫。", "變怪其若此，安知無蓬瀛。", "昨日聞公說，今日聞公行。", "行將勸農耕，用之卜陰晴。"]'),
('71c14609-749a-46bf-bbd1-a44b4ad56469','送代州錢防禦','梅堯臣','宋','宋诗','song-poetry','','[]','堂堂鴈門行，赫赫符節分。',72,'全唐诗/poet.song.15000.json','["堂堂鴈門行，赫赫符節分。", "紫塞千里障，紅旗十萬軍。", "世家王爵貴，祖廟將臣勳。", "鍾鼓陳牛酒，衣裘論典墳。", "呼鷹下青漢，牧馬出黄雲。", "竇憲何爲者，燕然解勒文。"]'),
('02f814d7-f08a-40c2-b3d9-e7da52b8acb0','寄題廬陵董氏桂林書齋','梅堯臣','宋','宋诗','song-poetry','','[]','山東桑柘多，江南松桂茂。',84,'全唐诗/poet.song.15000.json','["山東桑柘多，江南松桂茂。", "種桑事春蠶，栽桂事華構。", "嘗聞雲蓋下，聚書爲大富。", "往往見子孫，緣天掇星宿。", "掇星星若珠，光彩出屋漏。", "秋收萬種田，作酒日爲壽。", "亦有千里歸，錦衣行白晝。"]'),
('d15ca9fc-ad92-4b03-adbe-40316cba4556','次韻永叔乞藥有感','梅堯臣','宋','宋诗','song-poetry','','[]','子厚論鍾乳，要若鵝翎筒。',216,'全唐诗/poet.song.15000.json','["子厚論鍾乳，要若鵝翎筒。", "安取啗棗栗，謂相出山東。", "所産有所美，慎勿憑村僮。", "公問我餌藥，石臼將使礱。", "我餌乃藤根，得方非倉公。", "曾聞李習之，其品今頗同。", "此物俗爲賤，不入貴品中。", "吾妻希孟光，自舂供梁鴻。", "荏苒歲月久，顔丹聽益聰。", "雖能氣血盛，不療貧病攻。", "何如面黧黑，腰金明光宮。", "亦莫如學釣，緡鉤懸香藭。", "但知烟水樂，寧計身瘠豐。", "我生無快意，豈異抱篤癃。", "公乎忽我求，略辨雌與雄。", "雄赤而雌白，由來不同功。", "沙合固切似，朋好殊未窮。", "長年苟不遇，笑殺渭上翁。"]'),
('4ba8542d-7f86-4e11-b6db-6bf928abea64','和王景彝正月十四夜有感','梅堯臣','宋','宋诗','song-poetry','','[]','燈光暖熱夜催春，天半樓開飲近臣。',64,'全唐诗/poet.song.15000.json','["燈光暖熱夜催春，天半樓開飲近臣。", "馳道橫頭起山岳，露臺周匝簇朱輪。", "隔簾豔色多相照，下馬輕豪各競新。", "我已暮年殊趣嚮，濃油一盞桉邊身。"]'),
('f712558a-b4ca-43a4-a8cf-ce301b30d304','送雷太簡知虢州','梅堯臣','宋','宋诗','song-poetry','','[]','牛車讀古書，少作游秦客。',96,'全唐诗/poet.song.15000.json','["牛車讀古書，少作游秦客。", "一朝起爲郎，華省何赫赫。", "若有南山雲，時時生枕席。", "雲潤不益老，呼吸乘間隙。", "抱痾初駭聞，既愈頼藥石。", "遂請虢太守，虢事簡且適。", "况有三堂存，韓詩猶可覿。", "永歌復飲酒，東平希阮籍。"]'),
('16017544-12f1-4482-b291-427e08c3779c','次韻和景彝元夕雨晴','梅堯臣','宋','宋诗','song-poetry','','[]','春雲收暮城，九陌灑然清。',48,'全唐诗/poet.song.15000.json','["春雲收暮城，九陌灑然清。", "星出紫霄下，月從滄海明。", "車音還似晝，鼓響已知晴。", "靜閉衡門卧，無心學後生。"]'),
('52964b04-2cd6-4807-a1b4-fc09be1c69c8','早春書局即事','梅堯臣','宋','宋诗','song-poetry','','[]','薔薇結舊蔓，夭桃種新紅。',48,'全唐诗/poet.song.15000.json','["薔薇結舊蔓，夭桃種新紅。", "傷根桃不死，著架蔓依叢。", "要以玩芳物，亦寧負春風。", "誰念太行下，移谷學愚公。"]'),
('2f5e5df2-fd18-4ed5-928b-bea1feef48f7','古意','梅堯臣','宋','宋诗','song-poetry','','[]','林中即鹿人，常爲虎所即。',48,'全唐诗/poet.song.15000.json','["林中即鹿人，常爲虎所即。", "虎豈援鹿者，亦各求其食。", "趨利不顧害，禍患安可息。", "古來遯世士，輕彼用智力。"]'),
('a82d4d16-cbf6-4342-9167-938b49084373','送李閣使知冀州','梅堯臣','宋','宋诗','song-poetry','','[]','騕褭黄金絡，春風北渡河。',48,'全唐诗/poet.song.15000.json','["騕褭黄金絡，春風北渡河。", "將軍守漢法，壯士發燕歌。", "綠水塘蒲短，晴天塞雁多。", "家聲復年少，矍鑠笑廉頗。"]'),
('1e805a9a-6fd8-49a5-af07-47f4bdfa12ef','郭園梅花','梅堯臣','宋','宋诗','song-poetry','','[]','未逢柳條青，獨見梅蕊好。',48,'全唐诗/poet.song.15000.json','["未逢柳條青，獨見梅蕊好。", "猶怯春風寒，不比江南早。", "清香拂酒杯，素色欺蓬葆。", "佳人金縷衣，唱徹嗟身老。"]'),
('9b450726-40e8-4d5d-b676-64eb6858b243','送襄陵李令彥輔','梅堯臣','宋','宋诗','song-poetry','','[]','公相爲近親，翰林爲故人。',96,'全唐诗/poet.song.15000.json','["公相爲近親，翰林爲故人。", "親舊各貴顯，青袍未離身。", "六十去作令，豈慕要路津。", "又思漢東歸，便置漉酒巾。", "深希陶淵明，澹然意已真。", "食棗齒宜黄，晉俗誠自淳。", "尚不顧隋珠，安肯與此鄰。", "送君識君心，掃跡向世塵。"]'),
('f41b9ded-b004-4827-8e2f-0ba3abe53750','詠劉仲更澤州園中醜石','梅堯臣','宋','宋诗','song-poetry','','["\u592a\u6e56"]','君家太湖石，何從太湖得。',108,'全唐诗/poet.song.15000.json','["君家太湖石，何從太湖得。", "太湖天東南，太行天西北。", "相去三千里，雖有何致力。", "古人煩舟車，頑質無羽翼。", "竅引木蓮根，木蓮依以植。", "秋蛇出其中，舌吐虹霓色。", "君嘗夸於我，怪怪亦特特。", "以醜世爲惡，茲以醜爲德。", "事固無醜好，醜好貴不惑。"]'),
('008ece41-ef38-4145-b6ad-160fc66c2e93','送趙子淵知潁州','梅堯臣','宋','宋诗','song-poetry','','[]','舊穀不棲畝，新春原鹿饑。',48,'全唐诗/poet.song.15000.json','["舊穀不棲畝，新春原鹿饑。", "野荒多寇奪，詔發撫疲羸。", "驛騎東風急，菑田小雨遲。", "應同漢太守，膏澤亦能隨。"]'),
('42435618-a2eb-4817-ae2f-5970b8b56859','寄題楊敏叔虢州吏隠亭','梅堯臣','宋','宋诗','song-poetry','','[]','賢哉虢略君，守虢事頗簡。',60,'全唐诗/poet.song.15000.json','["賢哉虢略君，守虢事頗簡。", "有亭後園中，登覽早至晚。", "了了松柏關，氣象入醉眼。", "花草發瑣細，禽鳥啼睍睆。", "竟日人不來，亦莫去杯盞。"]'),
('7960bac7-5152-4798-ba71-e6151d62293d','次韻王舍人憶省中小桃寄江學士','梅堯臣','宋','宋诗','song-poetry','','[]','淺綻燕脂紫蠟芳，深斟吳酎白瓊觴。',64,'全唐诗/poet.song.15000.json','["淺綻燕脂紫蠟芳，深斟吳酎白瓊觴。", "鳳池人憶去年豔，雉省客無今日狂。", "髣髴物華先上苑，依俙歌吹下昭陽。", "平明社雨莫催促，應翫移牀欲近傍。"]'),
('b5f546a0-ccf3-48f8-a6ca-0c0e783f2314','次韻劉原甫社後對雪','梅堯臣','宋','宋诗','song-poetry','','[]','社日遇羣飲，北風歸馬驕。',120,'全唐诗/poet.song.15000.json','["社日遇羣飲，北風歸馬驕。", "陽烏雲斗晦，來燕翅難調。", "朝霰侵花冷，春陰到地消。", "宿酲無酒解，薄被覺寒饒。", "爐炭重然獸，衣裘更御貂。", "蟄宮蟲復閉，時鳥腹將枵。", "點綴何多思，輕狂不奈飄。", "唯知妍可玩，寧恤氣爲妖。", "剡客偶然興，海神非次朝。", "唱高仍和寡，公又作長謠。"]'),
('0ceab530-ce26-4799-a7c2-3dca2f6591ab','次韻永叔二月雪','梅堯臣','宋','宋诗','song-poetry','','[]','春雪損萌芽，未必摧杞菊。',64,'全唐诗/poet.song.15000.json','["春雪損萌芽，未必摧杞菊。", "我心無愛憎，隨分樂自足。", "桃李紅間白，豈不悅我目。", "杞菊嫩且甘，豈不飽我腹。", "看花食蔬仍舉杯，趁取衰遲鬢猶綠。"]'),
('54f55d91-63c3-40c9-aee9-34fde8ee9484','聞王景彝雪中禖祀還','梅堯臣','宋','宋诗','song-poetry','','[]','二月漫漫雪，齋宮夜寂寥。',48,'全唐诗/poet.song.15000.json','["二月漫漫雪，齋宮夜寂寥。", "壇場祠乙鳥，桑柘響陰梟。", "履带春泥重，駒回廣野驕。", "還批五色詔，池上踏瓊瑶。"]'),
('ca0ddec1-5be2-4575-b25c-8c3ddc5e6a65','次韻景彝祀高禖書事','梅堯臣','宋','宋诗','song-poetry','','[]','聞說郊禖喜氣翔，曾由乙卯命封商。',64,'全唐诗/poet.song.15000.json','["聞說郊禖喜氣翔，曾由乙卯命封商。", "今朝鍾鼓登歌祀，何日熊羆作夢祥。", "掃雪野廬風凜凜，陞壇公衮佩鏘鏘。", "君門賜胙予何有，不似矜誇鳳沼傍。"]'),
('00b18723-2e40-4a7e-8d04-20e028b144bd','次韻和永叔雨中寄原甫舍人','梅堯臣','宋','宋诗','song-poetry','','[]','頼得春巢燕未歸，高簷終日雨衰衰。',64,'全唐诗/poet.song.15000.json','["頼得春巢燕未歸，高簷終日雨衰衰。", "細籠芳草踏青後，欲打梨花寒食時。", "美景已嗟空過盡，名園猶許悞相隨。", "錦鞍切莫九衢去，拍拍一如鵝鴨池。"]'),
('20419624-0924-4328-afdb-1f17186904b3','毛君寶秘校將出京示予詩因以答之','梅堯臣','宋','宋诗','song-poetry','','[]','古城踏成谷，不見人馬蹤。',84,'全唐诗/poet.song.15000.json','["古城踏成谷，不見人馬蹤。", "古人豈不行，舊跡豈不重。", "從何求故步，往返自憧憧。", "觀君百篇詩，善畫人形容。", "毫髮無不似，落筆任橫縱。", "曷如握明鏡，物物目所逢。", "贈以東南歸，擲去手中筇。"]'),
('48d34126-c96b-49c4-ae25-7e674eaab9b3','劉仲更於唐書局中種郁李','梅堯臣','宋','宋诗','song-poetry','','[]','冷局少風景，買花栽作春。',72,'全唐诗/poet.song.15000.json','["冷局少風景，買花栽作春。", "前時櫻桃過，今日雀李新。", "搦條紅蓓蕾，婀娜含雨勻。", "舊來薔薇叢，饒借與近鄰。", "始移棣萼密，不慙車下榛。", "日暮綴書罷，暫賞舉杯踆。"]'),
('758b9bb6-adac-443c-ab89-128a659237a4','和劉原甫復雨寄永叔','梅堯臣','宋','宋诗','song-poetry','','[]','階下青苔欲染衣，晴光纔漏又霏微。',64,'全唐诗/poet.song.15000.json','["階下青苔欲染衣，晴光纔漏又霏微。", "衝風燕子銜泥去，隔樹鵓鴣嗔婦歸。", "乍冷乍陰將禁火，自開自掩不關扉。", "渾身酸削懶能出，莫怪與公還往稀。"]'),
('fc9d50fe-a507-4685-8bba-b3014cf2963f','送正仲都官知睦州','梅堯臣','宋','宋诗','song-poetry','','[]','每嗟相逢少，常苦離別多。',204,'全唐诗/poet.song.15000.json','["每嗟相逢少，常苦離別多。", "行行復壯壯，往往起悲歌。", "古來易水上，義士有荆軻。", "捐軀思報恩，飲恨歌奈何。", "况彼兒女懷，牽纏如蔓蘿。", "是以世間人，鬢髮易番番。", "喜君得郡章，東歸隨春波。", "灘上嚴子祠，繫船聊經過。", "其人當漢興，富貴不可羅。", "足加天子腹，傲去釣於河。", "冬披破羊裘，夏披破草蓑。", "心中小宇宙，尤哂獻玉和。", "我慙賤丈夫，豈異戴面儺。", "未免爲鬼笑，誰知懼揮訶。", "安得如君行，收跡已蹉跎。", "空將閒歲月，塵埃浪銷磨。", "正同三峽賈，盡力向盤渦。"]'),
('5b177c1e-0fe8-4ec5-b0f3-ad96e89b1377','續永叔歸田樂秋冬二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','秋風忽來鳴蟪蛄，豆葉半黄陂水枯。',96,'全唐诗/poet.song.15000.json','["秋風忽來鳴蟪蛄，豆葉半黄陂水枯。", "織婦夜作露欲冷，社酒已熟人相呼。", "坎坎擊鼓坐林下，醉去自有兒童扶。", "壯男獨獵南山虎，中子已扱荒徑狐。", "田家此樂樂有餘，食肉緝皮裘豈無。", "我雖愛之乏寸土，待買短艇歸江湖。"]'),
('dd60fdcd-ab05-48ad-a6cd-579f2a53532a','續永叔歸田樂秋冬二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','北風如刀割寒骨，穀已成囷不倉猝。',96,'全唐诗/poet.song.15000.json','["北風如刀割寒骨，穀已成囷不倉猝。", "任從密雪落交加，旋採乾薪燒榾柮。", "鋤犂滿屋牛在牢，鵝鴨亂鳴雞亂發。", "割烹炊黍待鄰叟，飽向茅簷閒兀兀。", "田家此樂樂無涯，誰道一生空汨沒。", "公希平子定何如，我效梁鴻終適越。"]'),
('b4d55803-5fb4-422b-826e-e0c96eaa6279','和介甫明妃曲','梅堯臣','宋','宋诗','song-poetry','','[]','明妃命薄漢計拙，憑仗丹青死悞人。',112,'全唐诗/poet.song.15000.json','["明妃命薄漢計拙，憑仗丹青死悞人。", "一別漢宮空掩淚，便隨胡馬向胡塵。", "馬上山川難記憶，明明夜月如相識。", "月下琵琶旋製聲，手彈心苦誰知得。", "辭家只欲奉君王，豈意蛾眉入虎狼。", "男兒返覆尚不保，女子輕微何可望。", "青冢猶存塞路遠，長安不見舊陵荒。"]'),
('96179651-5eb5-47a0-8214-7a36176717bb','酬楊愈太丞之壽州見別','梅堯臣','宋','宋诗','song-poetry','','[]','疇昔西州謝法曹，聲名籍甚我徒勞。',64,'全唐诗/poet.song.15000.json','["疇昔西州謝法曹，聲名籍甚我徒勞。", "升沉一府已荒冢，憔悴兩人猶二毛。", "眼見榮華能幾日，心知富貴只秋毫。", "淮南魚美香粳滑，飽去清吟豈不高。"]'),
('65fa724a-107b-481b-8f98-0c2cb2b8676e','贈太子太傅王尚書挽詞二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','周原開隴隧，鹵部葬名臣。',48,'全唐诗/poet.song.15000.json','["周原開隴隧，鹵部葬名臣。", "北極履聲絕，東朝車跡湮。", "藏舟移夜壑，棲鵩去承塵。", "共看劉寬墓，碑陰幾許人。"]'),
('998e19de-1ac5-434a-8757-c9fd456bc6bd','贈太子太傅王尚書挽詞二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','平生性忠厚，所守必尊君。',48,'全唐诗/poet.song.15000.json','["平生性忠厚，所守必尊君。", "面實賢愚混，心惟白黑分。", "事光中執法，書集右將軍。", "天意苦埋沒，北邙松柏墳。"]'),
('31c98d35-1a0d-4478-afab-c8ca5d914ef6','送陝西都運彭待制','梅堯臣','宋','宋诗','song-poetry','','[]','塞下兵難去，關中粟未多。',72,'全唐诗/poet.song.15000.json','["塞下兵難去，關中粟未多。", "君心同漢帝，糧道得蕭何。", "函谷馬蹄入，渭橋車轍過。", "地形終險固，山色舊嵯峨。", "不媿先賢傳，重聽得寶歌。", "歸來奏天子，安穩看鳴珂。"]'),
('fdb3bda6-a953-4e51-b8bc-3a67089592dd','送羅職方知秀州','梅堯臣','宋','宋诗','song-poetry','','[]','陸雲嘗誇千里蒓，便輕羊酪同埃塵。',80,'全唐诗/poet.song.15000.json','["陸雲嘗誇千里蒓，便輕羊酪同埃塵。", "君今得郡正千里，已患無羊厭此珍。", "乃知南北各所樂，乘舟不如乘馬惡。", "水邊不見秦羅敷，縱有西施肌肉薄。", "使君事事未稱意，綠水芙蓉定何若。"]'),
('69c7bbfd-9178-46b0-86e5-558b4970a1e5','寄懷劉使君','梅堯臣','宋','宋诗','song-poetry','','[]','昔我從仲父，三年在河內。',144,'全唐诗/poet.song.15000.json','["昔我從仲父，三年在河內。", "春游丹水上，花木弄粉黛。", "人誇走馬來，盡眼看沒背。", "薄暮半醉歸，插花紅簇隊。", "使君今少年，時往勸耕耒。", "安行過樹下，野杏正破纇。", "何不學山公，酩酊還倒載。", "令人知使君，心膽不瑣碎。", "切莫懲婦翁，慷慨臨并代。", "一朝由謗謫，雖去民苦愛。", "實計幸不幸，豈較進與退。", "因書寄此懷，繩墨老且悔。"]'),
('18633f6d-f193-4ef0-9ef0-1776d2f35d11','贈僕射侍中劉相公挽詞三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','處外諸侯重，居朝聖主知。',48,'全唐诗/poet.song.15000.json','["處外諸侯重，居朝聖主知。", "妖逢庚子日，夢異武丁時。", "歸槨關山遠，凝笳道路悲。", "欲傳千古跡，佐世本無爲。"]'),
('7a374742-ec06-4504-934a-2f497f1766e6','贈僕射侍中劉相公挽詞三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','古今皆可見，富貴不常存。',48,'全唐诗/poet.song.15000.json','["古今皆可見，富貴不常存。", "歌者未離席，弔賓俄在門。", "朱輪空返轍，綠酒尚盈樽。", "人事固如此，令名貽後昆。"]'),
('34c2b22d-191b-4070-a9c0-11b844fc07c2','贈僕射侍中劉相公挽詞三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','歎此微末跡，見公三十年。',48,'全唐诗/poet.song.15000.json','["歎此微末跡，見公三十年。", "貴爲天子相，能擇大夫賢。", "東第門闌在，南州隴隧延。", "立碑思叔子，墮淚峴山前。"]'),
('037c1859-3f4c-4036-b139-fdcfc2fc7751','送胥平叔太博通判湖州','梅堯臣','宋','宋诗','song-poetry','','[]','依依堤邊柳，泛泛水中舟。',144,'全唐诗/poet.song.15000.json','["依依堤邊柳，泛泛水中舟。", "舟行無遠近，柳影不隨流。", "東風欲粉絮，相逐江上頭。", "正見鮆魚來，貫條尾脩脩。", "使斫橫刀膾，便銷千里愁。", "檣端燕暫語，即飛入高樓。", "樓上饒客飲，共候風色柔。", "明朝同挂帆，直過南徐州。", "吳地多平湖，纜柂明鏡秋。", "芙蕖拂雨舷，女艇花底謳。", "不羨乘五馬，却逢羅敷羞。", "此官當此時，莫憶塵中游。"]'),
('64e55116-c76a-419f-8564-aae6fc4060a9','寄題張令陽翟希隠堂','梅堯臣','宋','宋诗','song-poetry','','[]','每讀陶潛詩，令人忘世慮。',60,'全唐诗/poet.song.15000.json','["每讀陶潛詩，令人忘世慮。", "潛本太尉孫，心遠跡亦去。", "不希五斗粟，自種五株樹。", "曠然箕山情，復起濠上趣。", "今時有若此，我豈不懷慕。"]'),
('4b0888df-fc62-4ccc-8120-888ccd8ecf11','李士元學士守臨邛日有穀一莖九穟者數本芝數本蓮花連葉並蒂者各一本因賦之','梅堯臣','宋','宋诗','song-poetry','','[]','臨邛傳瑞物，太守在郡時。',48,'全唐诗/poet.song.15000.json','["臨邛傳瑞物，太守在郡時。", "既多九穟穀，復有三秀芝。", "芝以保萬壽，穀以豐東菑。", "更看芙容葉，並蒂照清池。"]'),
('8c3ded43-2cf2-4780-b029-a908a337183d','考試畢登銓樓','梅堯臣','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u767b\u697c", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','春雲濃淡日微光，雙闕重門聳建章。',32,'全唐诗/poet.song.15000.json','["春雲濃淡日微光，雙闕重門聳建章。", "不上樓來知幾日，滿城無算柳梢黄。"]'),
('199f35e7-feb9-4978-9c08-a67697e69520','戲謝師直','梅堯臣','宋','宋诗','song-poetry','','[]','古錦裁詩句，班衣戲坐隅。',24,'全唐诗/poet.song.15000.json','["古錦裁詩句，班衣戲坐隅。", "木奴今正熟，肯效陸郎無。"]'),
('5c3cd7db-e756-4109-8669-551e89cab7c1','憶遊嵩山','梅堯臣','宋','宋诗','song-poetry','','[]','四字丹書萬仞崖，神清之洞鎖樓臺。',32,'全唐诗/poet.song.15000.json','["四字丹書萬仞崖，神清之洞鎖樓臺。", "烟霞極目無人到，鸞鶴今應待我來。"]'),
('9892b78b-f545-4c95-a3f4-10d44e9c1de5','甘棠','梅堯臣','宋','宋诗','song-poetry','','[]','更衣入侍宮中貴，韡韡芸黄殿後花。',64,'全唐诗/poet.song.15000.json','["更衣入侍宮中貴，韡韡芸黄殿後花。", "鬭色長宜日光近，生輝尤喜蓋陰斜。", "依稀鞠服開風袂，約略仙盟裹露華。", "不與艷桃偷結子，漫天飛去作朝霞。"]'),
('0a4f6f98-5e61-494f-886e-dccdde145405','雞冠花','梅堯臣','宋','宋诗','song-poetry','','[]','秋至天地閉，百芳變枯草。',84,'全唐诗/poet.song.15000.json','["秋至天地閉，百芳變枯草。", "愛爾得雄名，宛然出陳寶。", "未甘階墀陋，肯與時節老。", "赤玉刻縝栗，丹芝謝彫槁。", "鮮鮮雲葉卷，粲粲鳬翁好。", "由來名實副，何必榮華早。", "郡看先春花，浮浪難自保。"]'),
('c5a89af7-2e11-4f86-b208-3e7460b46f8a','叔治遺草蟲枕屏','梅堯臣','宋','宋诗','song-poetry','','[]','世傳毗陵畫，妙絕僧居寧。',120,'全唐诗/poet.song.15000.json','["世傳毗陵畫，妙絕僧居寧。", "不爲權貴逼，所與乃忘形。", "英機三尺素，落筆酒未醒。", "忽爲雙飛蜂，忽就一蜻蜓。", "螳蜋相拒立，促織如可聽。", "蚣蝑與螻蟈，行躍勢未停。", "竹蟬及鬼蝶，飄飄翻翅翮。", "蚊蝱亦具體，纖悉皆可名。", "廣宗潘叔治，持作枕間屏。", "我行因以贈，益見雙眉清。"]'),
('6bfba59c-5f82-4654-a5c0-ab57f5ad27a2','早梅','梅堯臣','宋','宋诗','song-poetry','','[]','江南近臘時，梅亞雪中枝。',48,'全唐诗/poet.song.15000.json','["江南近臘時，梅亞雪中枝。", "一夜欲開盡，百花猶未知。", "人心空共惜，天意不教遲。", "莫訝無穠豔，芳筵最好吹。"]'),
('88c75995-26f0-4233-9568-c54739305705','送貢仲章之燕','梅堯臣','宋','宋诗','song-poetry','','[]','天啟文明泰運興，漢庭來召魯諸生。',64,'全唐诗/poet.song.15000.json','["天啟文明泰運興，漢庭來召魯諸生。", "我嬰世網空投老，君向容臺早著名。", "水闊風高鵬翼健，沙乾雲暖馬蹄輕。", "歸來衣錦看他日，何用樽前唱渭城。"]'),
('b0848ad3-d3dd-4fb8-bd69-5653c0222bf1','聞曼叔腹疾走筆爲戲','梅堯臣','宋','宋诗','song-poetry','','[]','方聞病下利，曾不藥物止。',48,'全唐诗/poet.song.15000.json','["方聞病下利，曾不藥物止。", "區區溷匽間，其往寧得已。", "每爲青蠅喧，似與紫姑喜。", "傾腸倒腹後，乃是胸中美。"]'),
('79570e0f-c372-4ef3-b681-a866370e1bee','答紹元老示太玄圖','梅堯臣','宋','宋诗','song-poetry','','[]','鵝湖有鵝吾不問，鵝湖無鵝吾不疑。',52,'全唐诗/poet.song.15000.json','["鵝湖有鵝吾不問，鵝湖無鵝吾不疑。", "道士須換黄庭經，釋子自名太虛辭。", "噫嘻兮，此意迥與山陰別，我亦曾非逸少爲。"]'),
('b6263eaf-e230-4898-9c83-2b841e28c58f','句  其一','梅堯臣','宋','宋诗','song-poetry','','[]','秋花冬更開，夏實冬還結。',24,'全唐诗/poet.song.15000.json','["秋花冬更開，夏實冬還結。", "物理性難常，人意自爲孽。"]'),
('3973f090-c1c7-4103-9a20-4b7562cdd733','句  其二','梅堯臣','宋','宋诗','song-poetry','','[]','亞夫金鼓從天落，韓信旌旗背水陳。',16,'全唐诗/poet.song.15000.json','["亞夫金鼓從天落，韓信旌旗背水陳。"]'),
('5864ac12-e7a2-4c43-9bed-f1978b52bbc9','存目','梅堯臣','宋','宋诗','song-poetry','','[]','詩題：紅梅首句：認桃無綠葉，辨杏有青枝。',20,'全唐诗/poet.song.15000.json','["詩題：紅梅首句：認桃無綠葉，辨杏有青枝。"]'),
('a9288c28-8f74-46ea-af1d-8bea7b746645','遊山門寺望文脊山','吳季野','宋','宋诗','song-poetry','','[]','宣城百山間，文脊尤奇峯。',96,'全唐诗/poet.song.15000.json','["宣城百山間，文脊尤奇峯。", "拔出飛鳥上，畫圖難爲容。", "聞昔有幽人，捫蘿追赤松。", "遺形此石室，孤坐鹿裘重。", "人去邈不返，洞壑空藏龍。", "側行蒼崖烟，俯仰求靈蹤。", "逝者追可得，甘棄萬戶封。", "安能久塵土，傾倒相迎逢。"]'),
('a6f8bbd8-b874-4d9a-a1c3-057d126fff74','句','盧氏','宋','宋诗','song-poetry','','[]','田舍轆轤出短牆，村落鞦韆挂高樹。',16,'全唐诗/poet.song.15000.json','["田舍轆轤出短牆，村落鞦韆挂高樹。"]'),
('ffdeee36-ae08-4a75-bda9-6e5029f2c35a','過洞庭','張栻','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','城頭鷄一號，浩蕩風脚回。',168,'全唐诗/poet.song.150000.json','["城頭鷄一號，浩蕩風脚回。", "篙師起相呼，牽帆上高桅。", "我亦推枕聽，波浪聲轟豗。", "窗間試一覘，萬頃銀山開。", "附火且安坐，念此亦快哉。", "良久天平明，已見金沙堆。", "泊舟古廟底，喜色動輿臺。", "我行正長夏，及此歲律摧。", "通籍恨亡補，敢賦歸去來。", "所至有何忙，妙處姑徘徊。", "險阻元自平，鷗鳥亦不猜。", "萬事有定理，渠謾費安排。", "明朝上湘水，雪意正栽培。", "行矣一杯酒，好在故園梅。"]'),
('73f3d340-4349-485b-871d-c6e693b44a08','次韻陳寺丞建除體','張栻','宋','宋诗','song-poetry','','[]','建議了亡補，歸來謝馳驅。',144,'全唐诗/poet.song.150000.json','["建議了亡補，歸來謝馳驅。", "除荒城南丘，有田十畝餘。", "滿城車馬喧，得此逃空虛。", "平湖永晝靜，泉聲雜塤竽。", "定自非偶然，供我耳目娛。", "執熱者誰子，來浣塵土褕。", "破顔爲我笑，共看雲卷舒。", "危機起於中，胡越生同車。", "成功妙克己，八荒元一區。", "收心試參此，得失竟焉如。", "開緘得君詩，嗜好如我迂。", "閉門君未可，出處本非疎。"]'),
('971d0511-fcaf-4e72-92b3-92937d486b89','湖南參議宋與道奉祠歸崇安里中賦此以別','張栻','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','憶昔歲丙寅，束書從吾翁。',276,'全唐诗/poet.song.150000.json','["憶昔歲丙寅，束書從吾翁。", "驅車服嶺南，弭節湟江東。", "湟江地僻左，窮年少過從。", "邂逅傾蓋友，一笑蠻煙空。", "秋水泛孤艇，春郊支短筇。", "琴書適有餘，酬唱寫不供。", "豈惟吾曹歡，固足愉親容。", "日月遽如許，于今再星終。", "中間亦會面，別去復轉蓬。", "歸來洞庭野，乃此相迎逢。", "回首歎風樹，欲語悲填胸。", "愛君堅忍姿，凜凜霜後松。", "徐公真有常，意味與曩同。", "而我學不進，長大加愚蠢。", "幸蒙故人惠，苦語相磨礲。", "梅霖漲宿潦，行李何匆匆。", "自云洞庭樂，遠勝千戶封。", "將兒更抱孫，綵衣映諼叢。", "搜奇萃圖刻，考古羅彝鐘。", "知君頗挾此，詎信詩能窮。", "同里有佳人，抱獨環堵中。", "未妨閒暇日，更共討論功。", "它時有新得，爲寄冥飛鴻。"]'),
('207bf5a4-f55d-403f-bd7e-a5b10269a1ae','嚴慶胄射策南歸迂途相訪六月二十有一日同遊城南書院論文鼓琴煮茶烹鮮徘徊湖上薄莫乃歸明日作別書此爲贈','張栻','宋','宋诗','song-poetry','','[]','炎暑盛三伏，駕言得清游。',144,'全唐诗/poet.song.150000.json','["炎暑盛三伏，駕言得清游。", "城南才里所，便有山林幽。", "崇蓮炫平堤，修竹綠高丘。", "方茲閔雨辰，亦有清泉流。", "舉網鮮可食，汲井瓜自浮。", "絲桐發妙音，更覺風颼颼。", "喜無舉業累，獨有講學憂。", "逮子閒暇日，微言要窮搜。", "譬彼治田者，黽勉在勿休。", "但勤穮蔉功，勿作刈穫謀。", "雖云千里別，豈無置書郵。", "祝子時嗣音，慰我日三秋。"]'),
('3e48f89d-5275-460b-b27d-9d1dba52115c','長沙歷冬無雪正月十日與客登卷雲亭望西山始見一白莫夜復大作竹聲蕭然是日坐上分韻得雲字','張栻','宋','宋诗','song-poetry','','[]','冬溫氣苦盭，玄冥未書勳。',120,'全唐诗/poet.song.150000.json','["冬溫氣苦盭，玄冥未書勳。", "薄雪殿餘臘，一夜收楚氛。", "歡欣想農圃，潤澤到蒿芹。", "我亦破曉出，喚客來卷雲。", "蒼蒼西山樹，棲此萬鶴羣。", "爽氣入病眼，幽懷愜前聞。", "意到自舉酒，語多祇論文。", "薄莫勢未已，飛花復繽紛。", "還將蕭瑟聲，一一付竹君。", "洗盞且更酌，清絕未酣醺。"]'),
('18bba7ee-1e14-4f20-a6bd-76dd97f2056a','次韻周畏知問訊城東梅塢七首  其一','張栻','宋','宋诗','song-poetry','','[]','城東幽事如許，一見定勝百聞。',28,'全唐诗/poet.song.150000.json','["城東幽事如許，一見定勝百聞。", "苦雨斜風無柰，斷橋流水餘芬。"]'),
('fe7daaea-afa7-4b62-8da1-e8a649c11e07','次韻周畏知問訊城東梅塢七首  其二','張栻','宋','宋诗','song-poetry','','[]','誰知牛鐸黄鐘，寡和陽春白雪。',28,'全唐诗/poet.song.150000.json','["誰知牛鐸黄鐘，寡和陽春白雪。", "如君句法飽參，妙處不關言說。"]'),
('1f5cf186-1d83-484e-8d22-98c4a6344830','次韻周畏知問訊城東梅塢七首  其三','張栻','宋','宋诗','song-poetry','','[]','春意新回庭樹，角聲莫起江城。',28,'全唐诗/poet.song.150000.json','["春意新回庭樹，角聲莫起江城。", "更著水仙爲伴，真成難弟難兄。"]'),
('1765c30f-9587-43de-ab5d-b0f7adc55c4e','次韻周畏知問訊城東梅塢七首  其四','張栻','宋','宋诗','song-poetry','','[]','可是看花不厭，城南更欲城東。',28,'全唐诗/poet.song.150000.json','["可是看花不厭，城南更欲城東。", "多謝諸君著語，莫教孤負春風。"]'),
('470d86f6-5b29-4e67-a88d-8148a9237dfc','次韻周畏知問訊城東梅塢七首  其五','張栻','宋','宋诗','song-poetry','','[]','堤上已垂新柳，屋邊尚有殘梅。',28,'全唐诗/poet.song.150000.json','["堤上已垂新柳，屋邊尚有殘梅。", "雪盡春生湖水，野航竟日悠哉。"]'),
('e5986050-48e9-4788-8dcf-7098e61a4fc6','次韻周畏知問訊城東梅塢七首  其六','張栻','宋','宋诗','song-poetry','','[]','人情自爾變遷，此道不渝燥濕。',28,'全唐诗/poet.song.150000.json','["人情自爾變遷，此道不渝燥濕。", "未妨靜處閑觀，要知二五即十。"]'),
('f8c304d5-400d-4a71-b431-22179ad8a7ee','次韻周畏知問訊城東梅塢七首  其七','張栻','宋','宋诗','song-poetry','','[]','短筇遍歷溪山，款段時尋鄰里。',28,'全唐诗/poet.song.150000.json','["短筇遍歷溪山，款段時尋鄰里。", "遇酒聊一中之，得句亦偶然耳。"]'),
('b494e272-a375-4ad4-92c8-484e9da162bc','別離情所鍾十二章章四句送定叟弟之官嚴陵  其一','張栻','宋','宋诗','song-poetry','','[]','別離情所鍾，會合意無斁。',24,'全唐诗/poet.song.150000.json','["別離情所鍾，會合意無斁。", "如何僅踰歲，復賦弟行役。"]'),
('04c3e6d5-307f-4e79-9f4c-98b46adbdc02','別離情所鍾十二章章四句送定叟弟之官嚴陵  其二','張栻','宋','宋诗','song-poetry','','[]','歲律亦已暮，風烈雪漫漫。',24,'全唐诗/poet.song.150000.json','["歲律亦已暮，風烈雪漫漫。", "去路阻且長，念子衣裘單。"]'),
('75b663be-7c36-45ef-bdc1-1ddd7b6e4062','別離情所鍾十二章章四句送定叟弟之官嚴陵  其三','張栻','宋','宋诗','song-poetry','','[]','嚴之水淪漪，其山復蒼蒼。',24,'全唐诗/poet.song.150000.json','["嚴之水淪漪，其山復蒼蒼。", "子陵釣游地，草木有餘光。"]'),
('f6628928-6a01-4242-a8f2-ed702b9724ff','別離情所鍾十二章章四句送定叟弟之官嚴陵  其四','張栻','宋','宋诗','song-poetry','','[]','我昔臨此州，民容拙使君。',24,'全唐诗/poet.song.150000.json','["我昔臨此州，民容拙使君。", "子行爲多謝，慰彼無毫分。"]'),
('7bca50f9-8244-4bf5-8dcb-e6d0d9afb915','別離情所鍾十二章章四句送定叟弟之官嚴陵  其五','張栻','宋','宋诗','song-poetry','','[]','別駕亦何事，休戚理則同。',24,'全唐诗/poet.song.150000.json','["別駕亦何事，休戚理則同。", "但使民受惠，無論別駕功。"]'),
('db7d6818-0741-4928-a1a4-f52d7ac029f2','別離情所鍾十二章章四句送定叟弟之官嚴陵  其六','張栻','宋','宋诗','song-poetry','','[]','巍巍孤高亭，念我昔所喟。',24,'全唐诗/poet.song.150000.json','["巍巍孤高亭，念我昔所喟。", "子也時一登，千載起立志。"]'),
('2d005936-9880-4931-8f30-8dcb78d1d76b','別離情所鍾十二章章四句送定叟弟之官嚴陵  其七','張栻','宋','宋诗','song-poetry','','[]','義路本如砥，利徑劇羊腸。',24,'全唐诗/poet.song.150000.json','["義路本如砥，利徑劇羊腸。", "何以書子紳，世德不可忘。"]'),
('3c7bcf54-b506-41d9-b015-ad09c66ff25f','別離情所鍾十二章章四句送定叟弟之官嚴陵  其八','張栻','宋','宋诗','song-poetry','','[]','自昔謹交際，人情易因循。',24,'全唐诗/poet.song.150000.json','["自昔謹交際，人情易因循。", "敬始以念終，君子貴守身。"]'),
('d741dee6-8a9b-4492-a941-a77282fc002a','別離情所鍾十二章章四句送定叟弟之官嚴陵  其九','張栻','宋','宋诗','song-poetry','','[]','鄰邦呂正字，質疑時以書。',24,'全唐诗/poet.song.150000.json','["鄰邦呂正字，質疑時以書。", "校官有袁子，苦語莫厭渠。"]'),
('d3ff61f0-0336-4447-8929-9189274ea24d','別離情所鍾十二章章四句送定叟弟之官嚴陵  其一○','張栻','宋','宋诗','song-poetry','','[]','藐茲遺體重，相對子與予。',24,'全唐诗/poet.song.150000.json','["藐茲遺體重，相對子與予。", "祝子以自愛，念不忝厥初。"]'),
('604625bf-1cdd-47a2-a377-e02e38c9b8f4','別離情所鍾十二章章四句送定叟弟之官嚴陵  其一一','張栻','宋','宋诗','song-poetry','','[]','雲滿南陽陌，書藏善和宅。',24,'全唐诗/poet.song.150000.json','["雲滿南陽陌，書藏善和宅。", "行行重回首，無使歸思隔。"]'),
('26bf7f02-5666-4222-a963-58d0acc699a5','別離情所鍾十二章章四句送定叟弟之官嚴陵  其一二','張栻','宋','宋诗','song-poetry','','[]','送子目力短，朔風吹我裾。',24,'全唐诗/poet.song.150000.json','["送子目力短，朔風吹我裾。", "心焉獨如結，子也當念予。"]'),
('96595946-4b75-4a0c-b010-5af25b2622d6','平時兄弟間十三章章四句送定叟弟之官桂林  其一','張栻','宋','宋诗','song-poetry','','[]','平時兄弟間，未省別離味。',24,'全唐诗/poet.song.150000.json','["平時兄弟間，未省別離味。", "別時已不堪，別後何由慰。"]'),
('e693e3cb-63db-4d4e-ba68-d399124b79e3','平時兄弟間十三章章四句送定叟弟之官桂林  其二','張栻','宋','宋诗','song-poetry','','[]','庭萱既荒蕪，綵綬委塵土。',24,'全唐诗/poet.song.150000.json','["庭萱既荒蕪，綵綬委塵土。", "子嘆予咨嗟，寒窗夜風雨。"]'),
('2cc08c79-a76f-4521-987c-081cc69676ea','平時兄弟間十三章章四句送定叟弟之官桂林  其三','張栻','宋','宋诗','song-poetry','','[]','逮此閑暇日，頼有先世書。',24,'全唐诗/poet.song.150000.json','["逮此閑暇日，頼有先世書。", "與子共紬繹，舍去情何如。"]'),
('db3adf15-162e-4e51-8846-0df0a4c83956','平時兄弟間十三章章四句送定叟弟之官桂林  其四','張栻','宋','宋诗','song-poetry','','[]','嗚呼忠獻公，典則垂後裔。',24,'全唐诗/poet.song.150000.json','["嗚呼忠獻公，典則垂後裔。", "遺言故在耳，夕惕當自厲。"]'),
('6252cbd3-6faf-4359-836c-681221707a49','平時兄弟間十三章章四句送定叟弟之官桂林  其五','張栻','宋','宋诗','song-poetry','','[]','何以嗣先烈，匪論達與窮。',24,'全唐诗/poet.song.150000.json','["何以嗣先烈，匪論達與窮。", "永惟正大體，不遠日用中。"]'),
('424859e8-e7d3-4aa7-a074-21f885e35a89','平時兄弟間十三章章四句送定叟弟之官桂林  其六','張栻','宋','宋诗','song-poetry','','[]','履度如履冰，猶恐有不及。',24,'全唐诗/poet.song.150000.json','["履度如履冰，猶恐有不及。", "毫釐儻不念，放去如决拾。"]'),
('e813f12b-d096-4b6a-bb13-15e8699afbac','平時兄弟間十三章章四句送定叟弟之官桂林  其七','張栻','宋','宋诗','song-poetry','','[]','事業無欲速，燕逸不可求。',24,'全唐诗/poet.song.150000.json','["事業無欲速，燕逸不可求。", "速成適多害，求逸翻百憂。"]'),
('15fda3cb-2ab0-4af3-9124-f740bc862432','平時兄弟間十三章章四句送定叟弟之官桂林  其八','張栻','宋','宋诗','song-poetry','','[]','南山有佳木，柯葉正敷榮。',24,'全唐诗/poet.song.150000.json','["南山有佳木，柯葉正敷榮。", "願圖歲晚功，大用寧小成。"]'),
('188c1620-5af9-4b10-a1f8-abad16c6f8cf','平時兄弟間十三章章四句送定叟弟之官桂林  其九','張栻','宋','宋诗','song-poetry','','[]','歲晚豈不念，風雨漂摇之。',24,'全唐诗/poet.song.150000.json','["歲晚豈不念，風雨漂摇之。", "但當護木根，紛紜爾何爲。"]'),
('a219583f-54d2-450e-8e3d-59517331f729','平時兄弟間十三章章四句送定叟弟之官桂林  其一○','張栻','宋','宋诗','song-poetry','','[]','嶺海坐清靜，府公金玉姿。',24,'全唐诗/poet.song.150000.json','["嶺海坐清靜，府公金玉姿。", "幕府省文書，簡編可委蛇。"]'),
('00bf5fb2-7025-483c-8a8f-5b4b2dbb507e','平時兄弟間十三章章四句送定叟弟之官桂林  其一一','張栻','宋','宋诗','song-poetry','','[]','十步有茂草，會府宜多賢。',24,'全唐诗/poet.song.150000.json','["十步有茂草，會府宜多賢。", "親仁古所貴，更誦伐木篇。"]'),
('a6440d6f-57c5-48f2-b5d8-767e982a4dff','平時兄弟間十三章章四句送定叟弟之官桂林  其一二','張栻','宋','宋诗','song-poetry','','[]','聞之元城公，南州宜止酒。',24,'全唐诗/poet.song.150000.json','["聞之元城公，南州宜止酒。", "止酒縱未能，少飲還得不。"]'),
('d724ab22-55f8-43ac-ab35-5e1a532cb018','平時兄弟間十三章章四句送定叟弟之官桂林  其一三','張栻','宋','宋诗','song-poetry','','[]','子行日以遠，我思日以長。',24,'全唐诗/poet.song.150000.json','["子行日以遠，我思日以長。", "政或少閒暇，書來不可忘。"]'),
('09b33e88-42b8-4bdb-8520-e34def41db84','芭蕉茶送伯承伯承賦詩三章次韻  其一','張栻','宋','宋诗','song-poetry','','[]','與子藝蘭九畹，勝渠賜璧一雙。',28,'全唐诗/poet.song.150000.json','["與子藝蘭九畹，勝渠賜璧一雙。", "更碾春風白雪，同看明月清江。"]'),
('8a48dca4-1d12-4210-b00f-44f5793f7373','芭蕉茶送伯承伯承賦詩三章次韻  其二','張栻','宋','宋诗','song-poetry','','[]','正色可參官焙，妙香還近嵇山。',28,'全唐诗/poet.song.150000.json','["正色可參官焙，妙香還近嵇山。", "草木叢中清絕，天教散在人間。"]'),
('fdcb99e9-be52-4064-977b-8c07e4afeeaa','芭蕉茶送伯承伯承賦詩三章次韻  其三','張栻','宋','宋诗','song-poetry','','[]','春去雲藏嶽麓，梅黄雨漲昭潭。',28,'全唐诗/poet.song.150000.json','["春去雲藏嶽麓，梅黄雨漲昭潭。", "政爾倚欄無那，一甌喚起清談。"]'),
('c4ec5763-0004-4b61-b6ba-4897a16453cc','賦遺經閣','張栻','宋','宋诗','song-poetry','','[]','生世豈云晚，六籍初未亡。',144,'全唐诗/poet.song.150000.json','["生世豈云晚，六籍初未亡。", "向來言外旨，瞠視多茫茫。", "隠微會見獨，如日照八荒。", "始知傳心妙，初豈隔毫芒。", "絕學繼顔孟，淳風返虞唐。", "讀書無妙解，數墨仍尋行。", "況復志寵利，荆榛塞康莊。", "自云稽古功，此病真膏肓。", "君家屹飛閣，面對羣山蒼。", "匪爲登臨娛，牙籤富書藏。", "邀予爲著語，會意詎可忘。", "一洗漢儒陋，活法付諸郎。"]'),
('f70227e4-72ce-448e-9575-cbbb510b64ec','三友堂','張栻','宋','宋诗','song-poetry','','[]','寒窗政爾念蕭瑟，況復故人疎近音。',32,'全唐诗/poet.song.150000.json','["寒窗政爾念蕭瑟，況復故人疎近音。", "憑欄爲子賦三友，便覺冰霜千古心。"]'),
('156d3f57-9141-4312-b22f-6b7d32ba6b0a','初春和折子明歲前兩詩  其一','張栻','宋','宋诗','song-poetry','','[]','古今同活法，妙處在阿堵。',48,'全唐诗/poet.song.150000.json','["古今同活法，妙處在阿堵。", "浮雲不作祟，白黑可坐數。", "窮冬掩關卧，豈爲作詩苦。", "挑燈讀韋編，至味可深咀。"]'),
('ce85e0f5-4309-405d-a258-26df6d9b64e5','初春和折子明歲前兩詩  其二','張栻','宋','宋诗','song-poetry','','[]','新春風雨中，日日鳩鳴屋。',48,'全唐诗/poet.song.150000.json','["新春風雨中，日日鳩鳴屋。", "小園政可步，柰此泥涴足。", "却坐問樽酒，知足乃不辱。", "一杯徑陶然，敢羨車載麴。"]'),
('f11c5924-2408-4f17-9534-0240f504c829','和德美韓吏部笋詩','張栻','宋','宋诗','song-poetry','','[]','籜龍春雨後，得勢類乘軒。',288,'全唐诗/poet.song.150000.json','["籜龍春雨後，得勢類乘軒。", "驟長寧嫌速，駢生詎厭煩。", "錯連非異族，蒼老見玄孫。", "色并蒲葵扇，香侵老瓦盆。", "靜依花影轉，新带蘚文昏。", "外美看彪炳，中虛驗晏溫。", "出欄俄競秀，侵徑恍孤騫。", "穎脫錐囊見，森嚴武庫存。", "風回飄粉霧，龜拆露坤垠。", "生理知無息，神功本不言。", "牙籌誰數箇，玉斧莫傷根。", "錯立環兵衛，周羅儼翰藩。", "危岑遥寸露，睹浪忽驚奔。", "勁節回青眼，齊觀壯小園。", "嚴凝難奪志，霢霂合知恩。", "蛟鰐蟠深宅，牛羊隠半垣。", "委蛇隨戶牖，撐拄動荃蓀。", "愛惜滋千畝，高低辨兩番。", "藐真應莫稱，著譜欲重論。", "豈止同苞茂，真成後嗣繁。", "兒童防戲折，口腹謝空飧。", "深夜共椽燭，清朝列戟門。", "於菟真筆楗，季子屢髯掀。", "北海雖頻設，南山可盡髠。"]'),
('71bfca43-c151-447f-b793-580fc8d321b5','生辰謝邵廣文惠仁者壽賦','張栻','宋','宋诗','song-poetry','','[]','左弧念當辰，藐此卧歲晚。',132,'全唐诗/poet.song.150000.json','["左弧念當辰，藐此卧歲晚。", "重雲不予蔭，敢望滋九畹。", "南鄰有良朋，敏質快瓴建。", "進道方駸駸，吐辭看衮衮。", "妙語極吹噓，至理屬關鍵。", "嗟予澹泊好，學植自穮蔉。", "豈能益涓埃，感子意繾綣。", "昭然隠微中，當念仁豈遠。", "起知妙乾體，實理踐坤簡。", "大易乃在我，亙古當一本。", "期君得真傳，永以息邪遁。"]'),
('b79ac596-5528-46db-bd78-12982f45889c','五月十六日夜城南觀月分韻得月字','張栻','宋','宋诗','song-poetry','','[]','梅收清風來，宇凈實鑑揭。',84,'全唐诗/poet.song.150000.json','["梅收清風來，宇凈實鑑揭。", "頻年城南游，未有今夜月。", "呼舟泛微瀾，游魚亦出沒。", "危榭倒影浮，倚檻凉入骨。", "舉酒屬西山，寒光動林樾。", "諸君興未已，南阜上突兀。", "目極大江流，高情更超越。"]'),
('3a45d1e0-d730-4801-bf5b-43baffde2aa8','三月七日城南書院偶成','張栻','宋','宋诗','song-poetry','','[]','積雨欣始霽，清和在茲時。',120,'全唐诗/poet.song.150000.json','["積雨欣始霽，清和在茲時。", "林葉既敷榮，禽聲亦融怡。", "鳴泉來不窮，湖風起淪漪。", "西山卷餘雲，逾覺秀色滋。", "層層叢綠間，愛彼松柏姿。", "青青初不改，似與幽人期。", "坐久還起步，堤邊足逶迤。", "游魚傍我行，野鶴向我飛。", "敢云昔賢志，亦復詠而歸。", "寄言山中友，和我和平詩。"]'),
('d2be44a8-940d-48e3-8c58-26aa018da7d2','四月二十日與客來城南積潦方盛湖光恬然如平時泛舟終日分韻得水字','張栻','宋','宋诗','song-poetry','','[]','澤國盛梅雨，漲潦彌兩涘。',180,'全唐诗/poet.song.150000.json','["澤國盛梅雨，漲潦彌兩涘。", "常時侵溢患，乃復到城市。", "納湖迫西闉，衝突固其理。", "今年築隄防，楗石細積累。", "艱辛迄崇成，龜魚亦歡喜。", "節宣有程度，盈縮無壅底。", "昨宵水沒岸，民居例遷徙。", "走馬來問訊，屹若堅城壘。", "江濤從渺茫，湖光自清泚。", "小舟足游泳，新荷方薿薿。", "嘉我二三客，共此風日美。", "相期寂寞濱，雅意淡如水。", "念言隄防功，得失乃如彼。", "而况檢身者，詎可忘所止。", "明朝更哦詩，斯言或當紀。"]'),
('26bf21e4-aa23-4c20-bc2e-28426e27dac2','展省龍塘有作','張栻','宋','宋诗','song-poetry','','["\u8861\u5c71"]','十年衡山陰，驅馬幾往還。',84,'全唐诗/poet.song.150000.json','["十年衡山陰，驅馬幾往還。", "山色如故人，牧豎隨馬鞍。", "俯伏長松下，清晨涕汍瀾。", "念昔初拱把，茲焉影團欒。", "白雲歸何時，日月如轉環。", "矯首祝融峯，依前倚高寒。", "於焉百感集，欲去良獨難。"]'),
('8bc2cf65-787b-4585-ad2d-94b58ddf6177','田舍','張栻','宋','宋诗','song-poetry','','[]','竹葉带曉露，茅簷起炊煙。',96,'全唐诗/poet.song.150000.json','["竹葉带曉露，茅簷起炊煙。", "蛩吟枯草根，犬吠壞垣邊。", "田家亦何營，生理固足憐。", "風霜摧我稼，稂莠長我阡。", "卒歲復何念，一飽未補前。", "我思昔之人，備豫理所先。", "積倉徧郊野，甘雨盈公田。", "臨風重搔首，復古何由緣。"]'),
('984ed0ef-8eda-461d-8644-d8e3b4825a38','舊聞長沙城東梅塢甚盛近歲亦買園其間念欲一往未果也癸巳仲冬二十有八日始與客遊過東屯渡十餘里間玉雪彌望平時所未見也歸而爲詩以紀之','張栻','宋','宋诗','song-poetry','','[]','半生客荆楚，歷覽非一隅。',192,'全唐诗/poet.song.150000.json','["半生客荆楚，歷覽非一隅。", "寧知城東路，有此梅萬株。", "瘦馬路曉寒，清風起菰蒲。", "度溪上平坂，頓覺景物殊。", "霏雪下晴晝，香霧迷前驅。", "近坡與遠嶺，玉立同一區。", "老樹固瑰特，小枝亦敷腴。", "有如衆君子，彙聚德不孤。", "精粗無可揀，酥酪與醍醐。", "千株未覺多，此語信不誣。", "班荆或小憩，沽酒時一斟。", "勝賞諒難盡，昭質知不渝。", "我有十畝園，丘壑正盤紆。", "念此縞袂侶，歲晚足我娛。", "來遊自今始，琴書與之俱。", "回首桃李場，冷淡莫邪揄。"]'),
('0d8d4703-98ef-426d-9c4e-f5a6087efbcd','平父求筍炙既并以法授之乃用往歲張安國詩韻爲謝輒復和答','張栻','宋','宋诗','song-poetry','','[]','知君友竹君，寧使食無肉。',56,'全唐诗/poet.song.150000.json','["知君友竹君，寧使食無肉。", "更哦脯笋詩，句妙騷可僕。", "南公鮭菜傖父齏，嗜好自爾元非癡。", "君但將從力噉此，大勝折腰鄉里兒。"]'),
('9c48a502-4825-45e3-95ad-6f9bd3bba6b3','題淮陰祠','張栻','宋','宋诗','song-poetry','','[]','秦關昔先驅，南鄭豈淹久。',108,'全唐诗/poet.song.150000.json','["秦關昔先驅，南鄭豈淹久。", "夜中丞相歸，平明印垂肘。", "古來豪傑人，調度出窠臼。", "登壇一軍驚，六合已在手。", "從茲看廓清，指揮如運帚。", "時艱思奇才，廟古酹樽酒。", "出門望長淮，故國長稂莠。", "風雲正慘澹，人事極紛糾。", "拘攣儻無累，吾欲獻九九。"]'),
('01224ff9-23d7-4489-9b50-ec178eee3528','時爲桂林之役前一日刑部劉公置酒相餞曾節夫預焉既而劉公用陶靖節斜川詩韻見貽亦復同賦以謝','張栻','宋','宋诗','song-poetry','','[]','通籍念無補，先廬獲歸休。',120,'全唐诗/poet.song.150000.json','["通籍念無補，先廬獲歸休。", "所忻三載間，暇日從公遊。", "城中十畝園，頗復依清流。", "渺渺送歸鴈，翩翩下輕鷗。", "駕言欲南騖，踟躕眷林丘。", "況且遠晤言，公唱孰與酬。", "祖席近佳日，呼客仍我儔。", "相與千載思，誰復念此不。", "新詩更紆餘，用以寬離憂。", "它年南阜約，剝啄時相求。"]'),
('69564fc3-515d-4cfb-b6c2-ce989bf2e533','送劉樞密留守建康','張栻','宋','宋诗','song-poetry','','[]','整駕欲南騖，乃復送公舟。',204,'全唐诗/poet.song.150000.json','["整駕欲南騖，乃復送公舟。", "公行民所瞻，願言勿淹留。", "向來秉事樞，正色有忠謀。", "坐覺國勢尊，已驗權綱收。", "如何霖雨澤，偏使及南州。", "新春紫詔下，聞者寬百憂。", "誰昇今重鎮，百萬宿貔貅。", "控江撫長淮，聲勢接上流。", "吾皇志經略，此地合綢繆。", "不應萬全策，歲月空悠悠。", "先當植本根，次第施良籌。", "未聞欲外攘，而乃忽內修。", "幕府方宏開，人才要旁搜。", "可不念葑菲，惟當別薰蕕。", "留鑰豈淹久，即歸侍前旒。", "盡舒醫國手，調瘵會有瘳。", "還憶遐荒守，時能寄音不。"]'),
('565ae1a4-c8be-4e47-b5c3-95fe80f2e3cd','淳熙乙未春予有桂林之役自湘潭往省先塋以二月二日過碧泉與客煮茗泉上徘徊久之','張栻','宋','宋诗','song-poetry','','[]','下馬步深徑，洗盞酌寒泉。',120,'全唐诗/poet.song.150000.json','["下馬步深徑，洗盞酌寒泉。", "念不踐此境，于今復三年。", "人事苦多變，泉色故依然。", "緬懷德人游，物物生春妍。", "當時疏闢功，妙意太古前。", "屐齒不可尋，題榜尚覺鮮。", "書堂何寂寂，草樹亦芊芊。", "于役有王事，未暇謀息肩。", "聊同二三子，煮茗蒼崖邊。", "預作他年約，扶犁山下田。"]'),
('73089876-de3e-46e4-91b0-8977739f81b2','七月旦日晚登湘南樓','張栻','宋','宋诗','song-poetry','','[]','又書稍去眼，日夕進微凉。',132,'全唐诗/poet.song.150000.json','["又書稍去眼，日夕進微凉。", "高樓一徙倚，清風爲我長。", "漁父蔭深樾，歸人度浮梁。", "仰看河漢明，俯視羣山蒼。", "平生會心處，於此故難忘。", "舊聞水東勝，巖巒發天藏。", "豈無一日暇，勇往聊徜徉。", "民瘼未渠補，況敢懷樂康。", "天邊雲物佳，似復爲雨祥。", "秋成儻可期，歲晚或自强。", "當從農家鼓，一歷水雲鄉。"]'),
('63ba8a98-ffd3-40ad-8d95-6d6618249e9d','望後一日與客自水鄉登湘南月色佳甚翌日用鄉字韻簡游誠之','張栻','宋','宋诗','song-poetry','','[]','一雨五日餘，南州三伏凉。',132,'全唐诗/poet.song.150000.json','["一雨五日餘，南州三伏凉。", "喚客近方沼，笑譚引杯長。", "相將復登樓，月色在屋梁。", "念我懷百憂，忽忽髮變蒼。", "及此少自舒，觴詠未可忘。", "孤光凜下照，景妙無留藏。", "沙邊數白鷺，欲下仍翔徉。", "羣動亦自得，如我四體康。", "平生子游子，虛白生吉祥。", "官舍并樓居，登臨筋力强。", "未可效王粲，居然思故鄉。"]'),
('e2e7504f-7d0b-4314-9ed6-fd6be877ca5f','定叟弟生朝遣詩爲壽','張栻','宋','宋诗','song-poetry','','[]','我昔在嚴城，惟子桂林思。',144,'全唐诗/poet.song.150000.json','["我昔在嚴城，惟子桂林思。", "舊游復更踐，相望仍今茲。", "行止不可期，會合何參差。", "況乃近重九，清杯憶同持。", "想子撫初度，難忘蓼莪詩。", "而我獨東向，慇懃頌期頤。", "祝子以愛身，永佩過庭規。", "勉子事遠業，昔賢以爲師。", "安車按節度，中道行逶迤。", "他年老兄弟，鶴髮仍龐眉。", "歲晚話平生，期以無媿辭。", "及此良未易，兢兢願同之。"]'),
('1eabb495-8787-496b-804d-c945c1738bc0','八月既望要詳刑護漕游水東早飯碧虛徧觀棲霞程曾龍隠諸巖晚酌松關放舟過水月洞月色佳甚逼夜分乃歸賦此紀遊','張栻','宋','宋诗','song-poetry','','[]','灕江即湘江，戢戢清見石。',288,'全唐诗/poet.song.150000.json','["灕江即湘江，戢戢清見石。", "其東列羣峯，秋色碧復碧。", "日出霧露收，草徑上逼側。", "憑欄揩望眼，已足慰疇昔。", "更窺巖穴勝，創見爲驚咋。", "如何數里間，奇觀相接迹。", "寬同厦屋深，劃若巨靈擘。", "日月遞光景，風雲變朝夕。", "石橋幾年成，乳竇時一滴。", "神龍舊隠處，仰視多辟易。", "蛻迹凜猶存，隠隠印霜脊。", "下有澄湫深，餘波漱蒼壁。", "往者已仙去，來者此其宅。", "薄晚扣松關，風過聲索索。", "聊麾車騎退，容我且散策。", "却望訾家洲，輕舫度前磧。", "回首煙樹林，已復挂蟾魄。", "宇曠凈餘滓，羣物被光澤。", "何所寄遐思，空巖皎虛白。", "清輝可一規，水色相激射。", "天邊與川上，亭亭如合璧。", "居然廣寒游，不用假六翮。", "班坐依微瀾，晤賞共佳客。", "因之想千載，詎有今古隔。"]'),
('caa51ae1-38cd-4412-8f1c-03888b9fd8bd','次韓機幕韻','張栻','宋','宋诗','song-poetry','','[]','韓杜有佳句，炯炯如辰星。',240,'全唐诗/poet.song.150000.json','["韓杜有佳句，炯炯如辰星。", "自昔此邦勝，中土亦飫聽。", "奇觀今愈多，洞戶長不扃。", "秀色真可餐，腴澤到畦丁。", "寒巖度輕舫，瘦嶺著危亭。", "固已小鴈蕩，寧復談錦屏。", "自我來擁麾，每思御風泠。", "如何半載間，足迹才一經。", "居然俯仰中，便覺塵慮冥。", "舊刻暗蒼蘚，往事過奔霆。", "頗聞煙霞外，往往接神靈。", "向來羽衣士，吐內誇奇齡。", "終焉亦歸盡，難留鬢毛青。", "塞鴈度霄漢，沙鷗飛遠汀。", "大哉天壤間，逍遥各隨形。", "人生亦何有，泛若水上萍。", "勿作分外念，但勉明德馨。", "乘時各努力，日馭不我停。", "夢回故園好，蘭菊羅中庭。", "從知靖節醉，遠勝次公醒。"]'),
('3639f601-77f0-432c-85dc-94032fb4eeb7','秘閣鄭公移節鄉部置酒餞別詩以侑之','張栻','宋','宋诗','song-poetry','','[]','嗜僻寡同好，意合難語離。',204,'全唐诗/poet.song.150000.json','["嗜僻寡同好，意合難語離。", "傾蓋今幾年，盍簪愜心期。", "況復王事同，退食陪委蛇。", "窺君肺腑中，落落無藩籬。", "獨有見義勇，褰裳欲從之。", "憂時多苦語，懷古更餘悲。", "坐使嶺海間，冰雪映清規。", "我拙倚君重，孤懷良自知。", "正如乘霧行，不覺蒙其滋。", "人生豈無別，念此尤依依。", "維閩號蕃庶，今亦困繭絲。", "平時里社游，耳目到隠微。", "想當入境初，不待褰車帷。", "晝綉匪所榮，民瘼要深醫。", "看培邦本强，詎止鄉國肥。", "還歸報明主，廟論資扶持。", "願堅歲寒節，慰我別離思。"]'),
('a7cb5200-7af8-46ab-a4bc-474d0a870659','清明後七日與客同爲水東之游翌朝賦此','張栻','宋','宋诗','song-poetry','','[]','平生山水癖，妙處只自知。',216,'全唐诗/poet.song.150000.json','["平生山水癖，妙處只自知。", "夙約常寡味，邂逅愜心期。", "幅巾與藜杖，安步隨所之。", "朅來坐官府，頗覺此願違。", "城頭望羣峯，欲往類絆羈。", "三春苦風雨，晴日一伸眉。", "沙邊散車騎，竹輿從嘔咿。", "獨與三四客，野服相追隨。", "亭高俯空曠，洞古探瓌奇。", "懸崖隠日月，幽壑蟠蛟螭。", "澗水雜鳴佩，松風發清吹。", "興來即傾酒，語到亦論詩。", "聊揩簿書眼，償此閒暇時。", "所歷固未厭，所感多餘思。", "昔遊木葉下，今茲綠陰肥。", "江山雖可識，歲月迺如馳。", "素餐豈不念，懷安敢云私。", "歸來耿不寐，欹枕聽晨鷄。"]'),
('ad6cf08b-5c42-48cc-b071-3c53f9b2972d','題榕溪閣','張栻','宋','宋诗','song-poetry','','[]','寒溪澹容與，老木枝相樛。',156,'全唐诗/poet.song.150000.json','["寒溪澹容與，老木枝相樛。", "其誰合二美，名此景物幽。", "太史昔南騖，於焉曾少休。", "想當下榻初，清與耳目謀。", "品題得要領，亦有翰墨留。", "我來訪遺址，密竹鳴鈎輈。", "稍令舊觀復，還與佳客遊。", "樹影散香篆，水光泛茶甌。", "市聲不到耳，永日風颼颼。", "所忻簿書隙，有此足夷猶。", "平生丘壑願，如痼不可瘳。", "雖知等喧寂，終覺靜理優。", "更思濯滄浪，榕根浮小舟。"]'),
('519014c2-deb8-4572-995c-c8a259049467','送陳擇之','張栻','宋','宋诗','song-poetry','','[]','君能千里來，乃作觸熱去。',228,'全唐诗/poet.song.150000.json','["君能千里來，乃作觸熱去。", "凉秋幸非遥，歸計無已遽。", "向來文字間，講論有平素。", "及茲共王事，益得君佳處。", "幾微獨深窺，圭角本不露。", "豈期寂寞濱，獲此友朋助。", "吾邦雖云僻，山水足奇趣。", "更期休沐晨，相與窮杖屨。", "匆匆何少悰，咄咄出別語。", "君懷負丞恩，行矣當及戍。", "我亦念歸歟，霜天收栗芋。", "後會未可期，往事屢回顧。", "贈言復何有，獨以此道故。", "寥寥千載前，達者同一路。", "所趨固絕塵，所履無虛步。", "臨深覺居高，仰止有餘慕。", "要須學滄溟，匯此百川注。", "他年儻相憶，訪我城南圃。", "無使歲月深，永思編簡蠹。"]'),
('d20ec042-bc0b-462f-bb41-9f76796caa0e','止酒','張栻','宋','宋诗','song-poetry','','[]','淵明通達士，止酒乃成詩。',84,'全唐诗/poet.song.150000.json','["淵明通達士，止酒乃成詩。", "終焉未能忘，寄意良在茲。", "勇哉典午君，覆觴無再期。", "念彼萬乘貴，艱難有深思。", "況乃一介士，而或志可移。", "祓齋揆前訓，剛制聖所辭。", "銘心諒無斁，多言亦奚爲。"]'),
('5537c347-aa6a-4ac0-a259-7702f7d80334','斜川日雪觀所賦','張栻','宋','宋诗','song-poetry','','[]','行客念故里，勞者思少休。',120,'全唐诗/poet.song.150000.json','["行客念故里，勞者思少休。", "如何歲華新，尚爾天南游。", "涉五遇佳日，品題自名流。", "聊復揩病眼，沙邊玩輕鷗。", "和風著冠巾，春意動林丘。", "緬懷千載人，孤高諒難儔。", "亦有一二士，舉酒相勸酬。", "未知吾故園，草木如此不。", "政拙甘下考，智短空百憂。", "賜歸儻蒙幸，舊盟良可求。"]'),
('82f2e640-b837-4b43-9f6e-a8108e246182','靜江歸舟中讀書','張栻','宋','宋诗','song-poetry','','[]','南風駕小雨，羣山凈如沐。',120,'全唐诗/poet.song.150000.json','["南風駕小雨，羣山凈如沐。", "吾歸及新凉，所歷慰心目。", "軋軋柔櫓鳴，卧見山起伏。", "推枕意悠然，還取我書讀。", "平生領解處，於焉更三復。", "老矣百念疎，但欲斯境熟。", "向來五嶺游，日力半吏牘。", "小心了官事，終覺媿惸獨。", "世路自險夷，人情費追逐。", "翩翩孤飛翼，息蔭望林麓。"]'),
('d643b84d-3c78-43dd-8f54-767614e29cd0','張子真楊政光吳德夫追路湘源賦此以別','張栻','宋','宋诗','song-poetry','','[]','驅車出嚴關，觸熱歸路長。',216,'全唐诗/poet.song.150000.json','["驅車出嚴關，觸熱歸路長。", "一雨羣物蘇，吾行亦清凉。", "灕水自南去，湘流正洋洋。", "眷言二三友，跋馬勤送將。", "蕭然短長亭，每語夜未央。", "張子名家駒，千里方騰驤。", "楊郎嶺中彥，而能歛鋒鋩。", "延陵舊所熟，氣味固難忘。", "向來幕府遊，三秀麗齋房。", "居然出別語，分袂楚粵鄉。", "人生會有別，勿悲參與商。", "獨有贈言意，臨岐更平章。", "風俗易移人，宦途劇羊腸。", "千鈞有不守，决去飛鳥翔。", "要當勉自持，詩書作金湯。", "他年相會處，刮目看增光。", "爲謝桂父老，無澤留一方。", "惟餘石間字，時與洗苔蒼。"]'),
('959e279b-3939-4403-a73b-3efa1a2977fe','登江陵郡城觀雪','張栻','宋','宋诗','song-poetry','','[]','黄雲澹四垂，飛雪忽無際。',156,'全唐诗/poet.song.150000.json','["黄雲澹四垂，飛雪忽無際。", "排空風力靜，整整若有制。", "穿林初著花，點瓦已成毳。", "低連七澤波，遠接關河勢。", "憑城領奇觀，壯思起病滯。", "四年領邊州，氣候苦多盭。", "清秋日昏昏，仲冬雷虺虺。", "雪花有時零，轉首即開霽。", "及茲洗瘴眸，天公豈無意。", "爲邦抱百憂，但願得豐歲。", "對之一欣然，不飲心已醉。", "春前尚餘臘，三白或可冀。", "更約竹間梅，共作歲寒計。"]'),
('dc9aefa3-31c9-4fe9-bbba-d120635c5591','正甫還長沙復用斜川日和陶韻爲別','張栻','宋','宋诗','song-poetry','','[]','吾黨有佳士，寡欲自日休。',120,'全唐诗/poet.song.150000.json','["吾黨有佳士，寡欲自日休。", "眷言平生心，從我萬里游。", "披雲度嶺嶠，犯雪臨江流。", "顧我無定蹤，飄然若輕鷗。", "茲行雖云遠，所忻近故丘。", "況得與君俱，豈患寡朋儔。", "有酒君爲飲，有句君能酬。", "如何舍我歸，頗亦念此不。", "我老百念冷，獨有謀道憂。", "臨岐無他祝，簡編細研求。"]'),
('6c8aac63-f076-4fdf-94b8-4f056c7a485b','子遠使君出守廣漢始獲傾蓋諸官賦詩贈別某廣漢人也故末章及之','張栻','宋','宋诗','song-poetry','','[]','半生落南州，分與岷峨疎。',216,'全唐诗/poet.song.150000.json','["半生落南州，分與岷峨疎。", "朅來荆江上，所忻近鄉閭。", "吾鄉多雋豪，雜遝來舟車。", "時從說情話，頗覺中懷舒。", "中間識胡公，粹美真璠璵。", "心遠氣自靜，語簡意有餘。", "向來有推轂，入校中祕書。", "名場萬夫立，人亟我則徐。", "拳拳抱忠愛，百慮纔一攄。", "白雲已在望，思親惜居諸。", "乞州枌榆邊，政以便版輿。", "同舍挽不住，清風挾歸裾。", "觀君進退間，此豈爲名譽。", "春帆肯小駐，論交良慰予。", "愛君秉質高，且復富蓄儲。", "任重則道遠，願言勿踟躕。", "吾州得賢牧，父老想樂胥。", "我亦有一廛，徑思歸荷鋤。"]'),
('2f91f408-d67e-4620-9617-56971e03868a','李仁甫用東坡寄王定國韻賦新羅參見貽亦復繼作','張栻','宋','宋诗','song-poetry','','[]','三韓接蓬萊，祥雲護山頂。',144,'全唐诗/poet.song.150000.json','["三韓接蓬萊，祥雲護山頂。", "涵濡雨露春，吞納日月景。", "美蔭背幽壑，靈根發奇穎。", "艱難航瀚海，包裹走湖嶺。", "仙翁閲世故，未肯遽生癭。", "相期汗漫游，歲晚共馳騁。", "願持紫團珍，往扣黄庭境。", "想翁面敷腴，玉色带金井。", "芸芸納歸根，湛此方寸靜。", "清規照濁俗，不惑類楊秉。", "懸知藥籠中，此物配丹鼎。", "從今談天舌，不用更澆茗。"]'),
('4bf91893-d53d-44d7-a533-da79fdd619d4','外弟信臣總幹西歸駐舟沙岸得半月之款於其行口占道別','張栻','宋','宋诗','song-poetry','','[]','外家源流遠，文物被諸孫。',96,'全唐诗/poet.song.150000.json','["外家源流遠，文物被諸孫。", "嗟我數年來，頗識佳弟昆。", "酥酪本同味，蘭芷非殊根。", "競爽有如此，知當大其門。", "信也來過我，氣貌清而溫。", "方忻駐足地，中有靜者存。", "皎然明月光，豈復受濁渾。", "塤箎迭和時，此理試共論。"]'),
('653fa786-894c-4655-bfcb-5a9a90bc6894','廬山有勝處曰卧龍南康朱使君始築茅繪諸葛武侯像於其中以書屬予賦詩寄題此篇','張栻','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山仙靈宅，佳處固非一。',144,'全唐诗/poet.song.150000.json','["廬山仙靈宅，佳處固非一。", "頗聞卧龍勝，幽深諒難匹。", "懸瀑瀉琮琤，石壁兩崒嵂。", "草木被光輝，波瀾動回沒。", "今年朱使君，下馬恍若失。", "徘徊領妙趣，指點築茅室。", "爲愛卧龍名，英姿慨超軼。", "於焉儼繪事，長風起蕭瑟。", "髣髴梁父吟，尚想翁抱膝。", "慘澹風雲會，飄忽日月疾。", "獨存經世心，千載詎可汩。", "褰裳欲從之，雲濤渺寒日。"]'),
('bfad9e1f-9a26-4086-ab55-482e9d8e6cfc','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一','張栻','宋','宋诗','song-poetry','','[]','熙熙陽春，既發既舒。',20,'全唐诗/poet.song.150000.json','["熙熙陽春，既發既舒。", "翼翼南畝，是展是圖。"]'),
('8e4f4ca1-4662-492f-aacf-5c0e53669220','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其二','張栻','宋','宋诗','song-poetry','','[]','嗟爾農夫，各敬乃事。',20,'全唐诗/poet.song.150000.json','["嗟爾農夫，各敬乃事。", "往利爾器，誡爾婦子。"]'),
('4f526f1f-22c8-407f-b2e7-49feb93c51ef','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其三','張栻','宋','宋诗','song-poetry','','[]','惟生在勤，勤則及時。',20,'全唐诗/poet.song.150000.json','["惟生在勤，勤則及時。", "惟時之趨，時不爾違。"]'),
('9d21058c-2ed4-46e0-9b94-f5786912f49a','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其四','張栻','宋','宋诗','song-poetry','','[]','祁祁甘雨，膏我下土。',20,'全唐诗/poet.song.150000.json','["祁祁甘雨，膏我下土。", "習習谷風，和澤乃普。"]'),
('9f0182a3-9261-4add-b225-2187608fe3dc','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其五','張栻','宋','宋诗','song-poetry','','[]','往即爾耕，惟力之深。',20,'全唐诗/poet.song.150000.json','["往即爾耕，惟力之深。", "往蒔爾苗，勿倦其耘。"]'),
('c7f64250-56e2-4b39-9278-46a64541becb','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其六','張栻','宋','宋诗','song-poetry','','[]','于日于夕，自遂自達。',20,'全唐诗/poet.song.150000.json','["于日于夕，自遂自達。", "爾心勿忘，彼生孰遏。"]'),
('71877250-34b2-4fe3-a984-6ba17177d1d6','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其七','張栻','宋','宋诗','song-poetry','','[]','惟天之心，矜我下民。',20,'全唐诗/poet.song.150000.json','["惟天之心，矜我下民。", "民不違天，使爾有成。"]'),
('1699d422-d5b3-4248-b513-53c8ec934c37','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其八','張栻','宋','宋诗','song-poetry','','[]','既穟既實，既堅既好。',20,'全唐诗/poet.song.150000.json','["既穟既實，既堅既好。", "爾穫既周，先養爾老。"]'),
('22b10663-e07a-4f46-91bf-a90be752b92b','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其九','張栻','宋','宋诗','song-poetry','','[]','保爾家室，撫爾幼穉。',20,'全唐诗/poet.song.150000.json','["保爾家室，撫爾幼穉。", "既迄有年，復思嗣歲。"]'),
('da32acef-8636-4d8d-b7a5-f9bec425b922','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一○','張栻','宋','宋诗','song-poetry','','[]','嗟爾父老，其訓其誡。',20,'全唐诗/poet.song.150000.json','["嗟爾父老，其訓其誡。", "俾務於本，惟土物愛。"]'),
('75c6170b-fa8c-445a-b0bf-f0c9e1cde11a','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一一','張栻','宋','宋诗','song-poetry','','[]','不念其本，則越其思。',20,'全唐诗/poet.song.150000.json','["不念其本，則越其思。", "所思既越，害斯百罹。"]'),
('9493c61b-3008-4ebc-95ed-d136fec62fac','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一二','張栻','宋','宋诗','song-poetry','','[]','嗟爾父老，其告其喻。',20,'全唐诗/poet.song.150000.json','["嗟爾父老，其告其喻。", "爾之有生，君實覆汝。"]'),
('a5ab55a3-60fd-41ce-a413-544530965b76','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一三','張栻','宋','宋诗','song-poetry','','[]','尊君親上，其篤勿忘。',20,'全唐诗/poet.song.150000.json','["尊君親上，其篤勿忘。", "小心畏忌，率于憲章。"]'),
('e6cc98c7-f463-49ef-b9f2-1718c60be17d','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一四','張栻','宋','宋诗','song-poetry','','[]','嗟爾父老，教之孝悌。',20,'全唐诗/poet.song.150000.json','["嗟爾父老，教之孝悌。", "孰無父母，與其同氣。"]'),
('350d1700-365f-429f-99b1-5192a0f84e04','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一五','張栻','宋','宋诗','song-poetry','','[]','反于爾心，孰無愛敬。',20,'全唐诗/poet.song.150000.json','["反于爾心，孰無愛敬。", "即是而推，烏往不順。"]'),
('319825cf-48ed-4e7e-94a7-20a1cd7bd6ef','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一六','張栻','宋','宋诗','song-poetry','','[]','嗟爾父老，勿替諄諄。',20,'全唐诗/poet.song.150000.json','["嗟爾父老，勿替諄諄。", "其未率從，警厲其身。"]'),
('f1b72d9c-4371-4235-8a45-b248d35ebaa2','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一七','張栻','宋','宋诗','song-poetry','','[]','告以禍患，其使知懼。',20,'全唐诗/poet.song.150000.json','["告以禍患，其使知懼。", "無俾蹉跌，以陷罪罟。"]'),
('2d6a9146-5713-4783-b495-d27d20ddc643','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一八','張栻','宋','宋诗','song-poetry','','[]','惟國之法，燁燁其垂。',20,'全唐诗/poet.song.150000.json','["惟國之法，燁燁其垂。", "使爾知避，豈欲爾施。"]'),
('872e0622-91e2-484d-811b-32b58e235181','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其一九','張栻','宋','宋诗','song-poetry','','[]','爾或自陷，予疚予恫。',20,'全唐诗/poet.song.150000.json','["爾或自陷，予疚予恫。", "曷使予懷，寘于爾衷。"]'),
('8813b449-e1c6-49a4-baf8-0d8612c9af1d','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其二○','張栻','宋','宋诗','song-poetry','','[]','於赫聖主，敷德流澤。',20,'全唐诗/poet.song.150000.json','["於赫聖主，敷德流澤。", "布宣弗勤，時予之責。"]'),
('762660ae-67ee-49a2-9b6d-14ab4e353cf6','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其二一','張栻','宋','宋诗','song-poetry','','[]','咨爾父老，助予念茲。',20,'全唐诗/poet.song.150000.json','["咨爾父老，助予念茲。", "豈予之助，報國是宜。"]'),
('7646121f-d845-4186-8ff5-36139982b8f5','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其二二','張栻','宋','宋诗','song-poetry','','[]','粵以今日，勸相于郊。',20,'全唐诗/poet.song.150000.json','["粵以今日，勸相于郊。", "乃作此詩，以懋爾勞。"]'),
('bcf59d8a-5636-48f0-bb87-94405bc0e19a','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其二三','張栻','宋','宋诗','song-poetry','','[]','咨爾父老，尚演厥義。',20,'全唐诗/poet.song.150000.json','["咨爾父老，尚演厥義。", "其諷其歌，于鄉于里。"]'),
('63d89ec8-178c-4106-9f94-3ed43805cedc','淳熙四年二月既望靜江守臣張某奉詔勸農于郊乃作熙熙陽春之詩二十四章章四句以示父老俾告于其鄉之人而歌之  其二四','張栻','宋','宋诗','song-poetry','','[]','俾一其心，服我訓言。',20,'全唐诗/poet.song.150000.json','["俾一其心，服我訓言。", "擊鼓坎坎，自古有年。"]'),
('5c852896-c201-430f-b817-1e77e45bbe04','和石通判酌白鶴泉','張栻','宋','宋诗','song-poetry','','[]','談天終日口瀾翻，來乞清甘醒舌根。',64,'全唐诗/poet.song.150000.json','["談天終日口瀾翻，來乞清甘醒舌根。", "滿座松聲聞金石，微瀾鶴影漾瑶琨。", "淡中知味誰三嚥，妙處相期豈一樽。", "有本自應來不竭，濫觴端可驗龍門。"]'),
('d1668126-83d8-41d7-be35-92812879b956','憩清風峽','張栻','宋','宋诗','song-poetry','','[]','扶疎古木矗危梯，開始知經幾攝提。',64,'全唐诗/poet.song.150000.json','["扶疎古木矗危梯，開始知經幾攝提。", "還有石橋容客坐，仰看蘭若與雲齊。", "風生陰壑方鳴籟，日烈塵寰正望霓。", "從此上山君努力，瘦藤今日得同携。"]'),
('d3f861aa-9d4f-4259-a188-4be51ace1257','讀李邕碑','張栻','宋','宋诗','song-poetry','','[]','荒榛日莫倚筇時，歎息危亭北海碑。',64,'全唐诗/poet.song.150000.json','["荒榛日莫倚筇時，歎息危亭北海碑。", "後輩但知尊字畫，當年不得戍邊垂。", "豈關貝錦能成禍，祇恐干將不自奇。", "杜老惜才千古意，如今誰詠六公辭。"]'),
('44a7cb74-507f-49da-a844-fec1ab576851','登法華臺','張栻','宋','宋诗','song-poetry','','[]','山間景物轉流年，臺上風光處處傳。',64,'全唐诗/poet.song.150000.json','["山間景物轉流年，臺上風光處處傳。", "放目便應雲夢小，憑欄平挹祝融巔。", "忽尋故國占天際，誰看孤舟繫岸邊。", "百感還將山下去，肯同槁木墮深禪。"]'),
('d1396ea0-0839-41a8-8b64-cdb0217683e1','謝楊文昭主簿寄詩楊之父紹興間倅建康不屈於兀朮而死','張栻','宋','宋诗','song-poetry','','[]','迺翁詈賊氣如虹，千載衣冠起懦庸。',64,'全唐诗/poet.song.150000.json','["迺翁詈賊氣如虹，千載衣冠起懦庸。", "雙廟已應同卞壺，佳兒今喜見甄逢。", "傳郵贈我凌雲句，斷簡知君學古胸。", "忠孝可全須力勉，策勳寧復羨侯封。"]'),
('1bda096c-c450-467c-badb-91235f4de3a4','喜廣仲伯逢來會','張栻','宋','宋诗','song-poetry','','[]','二阮向來俱莫逆，支筇爲我到山巔。',64,'全唐诗/poet.song.150000.json','["二阮向來俱莫逆，支筇爲我到山巔。", "濁醪共飲聊復爾，勝集于今亦偶然。", "人立千峯秋色裏，月生滄海暮雲邊。", "高談此地曾知幾，一笑歸來對榻眠。"]'),
('5e4ab7eb-325c-4453-bef6-f07414cc1a2a','和黄仲秉喜雨','張栻','宋','宋诗','song-poetry','','[]','雨後清泉遶舍流，懸知耘耜遍南州。',64,'全唐诗/poet.song.150000.json','["雨後清泉遶舍流，懸知耘耜遍南州。", "占相歲事端無恙，勞苦農人亦少休。", "好句收功經百鍊，彌旬不見便三秋。", "閑來只願長豐稔，江海白鷗盟共求。"]'),
('7b50aced-8a12-4cf1-9e56-0e54b63adce4','遊道場山次沈國錄韻','張栻','宋','宋诗','song-poetry','','[]','玻瓈盆外起千鬟，路入空濛紫翠間。',64,'全唐诗/poet.song.150000.json','["玻瓈盆外起千鬟，路入空濛紫翠間。", "心遠最便天宇迥，眼明偏見野雲閑。", "寒泉宰木留千載，清磬疎鐘度兩山。", "我亦湘城三徑在，湖邊歸去洗塵顔。"]'),
('7c2a81cc-0503-46b9-9ebc-b777821e1198','早秋湖亭','張栻','宋','宋诗','song-poetry','','[]','澤國今年秋氣蚤，湖亭清晚獨裴徊。',64,'全唐诗/poet.song.150000.json','["澤國今年秋氣蚤，湖亭清晚獨裴徊。", "翩翻荷蓋隨風舞，蕭瑟松聲带雨來。", "靜處豈云身計得，吟邊但覺歲華催。", "悠悠遠思憑誰寫，多病新來罷酒杯。"]'),
('ecd0d4fa-9120-4594-8197-a699e7f872ff','賦周畏知寓齋','張栻','宋','宋诗','song-poetry','','[]','知君隨寓即能安，久矣家山詠考槃。',64,'全唐诗/poet.song.150000.json','["知君隨寓即能安，久矣家山詠考槃。", "幕府漫游從鬢禿，竹窗寄傲有書觀。", "此身詎可忘三省，世路何妨閲萬端。", "俯仰周旋皆實理，未應祇向寓中看。"]'),
('44047d00-ff7c-419a-b2c6-0829826f06a4','送甘可大','張栻','宋','宋诗','song-poetry','','[]','子陵溪水千年綠，猶憶登臨日暮時。',64,'全唐诗/poet.song.150000.json','["子陵溪水千年綠，猶憶登臨日暮時。", "子去定能尋勝概，書來當復慰相思。", "簡編有味寧論晚，得失從渠莫自疑。", "也學迂疎教似舅，不應空賦渭陽詩。"]'),
('48b22cf1-5003-4bec-b67c-d48ad2e0ab2c','送胡伯逢之官金陵','張栻','宋','宋诗','song-poetry','','[]','相望數舍已云疎，遠別何因執子袪。',64,'全唐诗/poet.song.150000.json','["相望數舍已云疎，遠別何因執子袪。", "漫仕想應同捧檄，舊聞當不廢觀書。", "月明淮水空陳迹，山繞新亭有故墟。", "暇日更須頻訪古，因來爲我道何如。"]'),
('f06bb592-ae70-4421-b951-ac6b6b977f17','寄題建安公梅山堂','張栻','宋','宋诗','song-poetry','','[]','梅公山色近庭除，勝日供公几杖餘。',64,'全唐诗/poet.song.150000.json','["梅公山色近庭除，勝日供公几杖餘。", "千古謾傳棲迹地，當年誰憶愛君書。", "丹心炯炯元無間，白髮星星不用鉏。", "待得斯民俱奠枕，歸來端亦愛吾廬。"]'),
('570f6f5e-01a0-4bb5-8404-2775e7f72270','重九陪詳刑護漕東西樓之集','張栻','宋','宋诗','song-poetry','','[]','獵獵西風滿角巾，登臨秋思與雲平。',64,'全唐诗/poet.song.150000.json','["獵獵西風滿角巾，登臨秋思與雲平。", "山圍四野高低碧，江遶東城今古清。", "莫恨寒花未堪摘，且忻樽酒得同傾。", "政須客裏頻回首，細話家山此日情。"]'),
('33b5e875-0d18-4cda-b86b-fbc3c5c179ba','次趙漕贈王昭州韻','張栻','宋','宋诗','song-poetry','','[]','煌煌金節按江城，驛路梅花正小春。',64,'全唐诗/poet.song.150000.json','["煌煌金節按江城，驛路梅花正小春。", "聞說爭迎來滿道，定將何術慰斯民。", "憩棠異日誇南國，懷橘歸時拜壽親。", "流澤會看均一路，要令治象復熙淳。"]'),
('c2cae4e0-7645-4f45-a989-46a40d6881c1','九日登千山觀','張栻','宋','宋诗','song-poetry','','[]','清晨領客上巉巖，野路衣襟濕翠嵐。',64,'全唐诗/poet.song.150000.json','["清晨領客上巉巖，野路衣襟濕翠嵐。", "九日開樽仍絕景，西風欹帽且高談。", "地形盤薄一都會，山色周遭萬玉簪。", "却指飛鴻煙漠漠，故園茱菊老江潭。"]'),
('51beb4ed-e6f2-407a-be73-839f7825514d','和正父游榕溪韻','張栻','宋','宋诗','song-poetry','','[]','隔岸高低露碧山，眼明便作故園看。',64,'全唐诗/poet.song.150000.json','["隔岸高低露碧山，眼明便作故園看。", "直從榕影度輕舫，更傍溪光撫曲欄。", "鴻雁來希空悵望，梅花開早未初寒。", "喜君萬里同情話，明月清風足佐歡。"]'),
('9062ddcc-8112-4151-8d16-6373777f0f45','仲冬朔日登湘南樓復用正父前韻','張栻','宋','宋诗','song-poetry','','[]','歷遍江南處處山，嶠南還得倚樓看。',64,'全唐诗/poet.song.150000.json','["歷遍江南處處山，嶠南還得倚樓看。", "化工此地無餘巧，爽氣窮冬更逼欄。", "官事隨時寧解了，書盟平日未應寒。", "相逢自有論文樂，只把空杯未礙歡。"]'),
('861fc2a5-0105-448b-922d-e7e3b2b8cd52','六月二十六日秀青亭初成與客同集','張栻','宋','宋诗','song-poetry','','[]','亭成勝日好風光，佳客携將共一觴。',64,'全唐诗/poet.song.150000.json','["亭成勝日好風光，佳客携將共一觴。", "蒼壁插空千古色，高松蔭堤三伏凉。", "網魚縷膾寒水玉，剝蓮煮鼎甘露漿。", "便覺故園渾在眼，祇應灕水似瀟湘。"]'),
('4f9fa5fe-70be-4098-97b6-260020d7f073','送韓宜州','張栻','宋','宋诗','song-poetry','','[]','頃年未識宜州面，已信諸賢品藻公。',64,'全唐诗/poet.song.150000.json','["頃年未識宜州面，已信諸賢品藻公。", "幕下從容逢益友，胸中骯髒本家風。", "一麾且與寬凋瘵，華髮應無慕勇功。", "從古安邊須自治，人情初不間華戎。"]'),
('71221f87-615f-443c-8960-8d57d5fbfe4e','鹿鳴宴','張栻','宋','宋诗','song-poetry','','[]','從昔山川夸八桂，只今文物盛南州。',64,'全唐诗/poet.song.150000.json','["從昔山川夸八桂，只今文物盛南州。", "秋風萬里携書劍，春日端門拜冕旒。", "聖世取才先實用，儒生報國豈身謀。", "且看廷策三千字，爲寫平時畎畝憂。"]'),
('dc7ee9ae-4f7b-4dc7-860c-c7f561333168','送宇文正甫','張栻','宋','宋诗','song-poetry','','[]','重來能復幾旬餘，臨水登山又送渠。',64,'全唐诗/poet.song.150000.json','["重來能復幾旬餘，臨水登山又送渠。", "夜雨已知農事好，春寒未放小桃舒。", "眼前佳處應難盡，別後書來詎可疎。", "我亦相將歸舊隠，杖藜時復訪樓居。"]'),
('3353e06c-3f6e-4b48-a0cf-e337db09a043','雨後同周允升登雪觀','張栻','宋','宋诗','song-poetry','','[]','一雨端能減百憂，肩輿徑上最高樓。',64,'全唐诗/poet.song.150000.json','["一雨端能減百憂，肩輿徑上最高樓。", "山容凈洗無窮碧，江水新添自在流。", "已覺春隨花片老，不應身似賈胡留。", "煙蓑風笠南山下，正好歸歟看麥秋。"]'),
('5840f0d4-4bb2-4205-8608-8c65d67f8dd3','題邢使君釣隠','張栻','宋','宋诗','song-poetry','','[]','使君卜築占芳洲，短檻疎籬處處幽。',64,'全唐诗/poet.song.150000.json','["使君卜築占芳洲，短檻疎籬處處幽。", "風月隨時供燕几，笑談終日在中流。", "翩翩影落來賓鴈，漠漠寒生欲下鷗。", "城市山林俱寓目，問君底處足消憂。"]'),
('6ea27b5d-285c-4523-b7b7-f0e82a68ca41','某辱歸父丈惠貺新詩謹次韻末章爲別','張栻','宋','宋诗','song-poetry','','[]','淮海相從幾歲年，南州鴈不到西川。',64,'全唐诗/poet.song.150000.json','["淮海相從幾歲年，南州鴈不到西川。", "重逢影落煙沙外，却喜身如金石堅。", "莫歎武城資莞爾，且看平楚正蒼然。", "剸繁自是君餘事，毫髮難逃止水淵。"]'),
('a4740e89-5c24-4cab-a938-267909c65fce','和查仲文雪中即席所賦','張栻','宋','宋诗','song-poetry','','[]','方帽衝泥有客來，九衢俗眼莫驚猜。',64,'全唐诗/poet.song.150000.json','["方帽衝泥有客來，九衢俗眼莫驚猜。", "一樽相對十年外，兩脚新從萬里回。", "壯志未隨衰鬢改，孤懷良爲故人開。", "雪中細放梅花發，不用匆匆羯鼓催。"]'),
('b9c0f73a-14b7-4cdd-a8cd-d39561f924bd','和宇文正甫探梅','張栻','宋','宋诗','song-poetry','','[]','天與孤清迥莫鄰，祇應空谷伴幽人。',64,'全唐诗/poet.song.150000.json','["天與孤清迥莫鄰，祇應空谷伴幽人。", "千林掃迹愁無那，一點橫梢眼便親。", "顧影莫驚身易老，哦詩尚覺句能新。", "幾多生意冰霜裏，說與夭桃自在春。"]'),
('df6a1efd-cd1e-4145-bd9c-614eb5a58283','襄州護漕使者張侯寄示所作快目亭記辭多慷慨予讀而壯之且想斯亭觀覽之勝爲賦此','張栻','宋','宋诗','song-poetry','','[]','聞說君家快目亭，湓江直上起千尋。',64,'全唐诗/poet.song.150000.json','["聞說君家快目亭，湓江直上起千尋。", "昔人事業規摹在，故國山河草木深。", "世態從渠翻覆手，壯圖還我短長吟。", "會須一展平戎策，始稱平生灑落襟。"]'),
('d8d79919-a8e1-408f-83ae-4cfd90c5d148','送舜臣撫幹表兄赴部','張栻','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','疇昔相看意便傾，重逢便覺眼增明。',64,'全唐诗/poet.song.150000.json','["疇昔相看意便傾，重逢便覺眼增明。", "半生漫仕壯心在，五月長江去棹輕。", "龜櫝久藏千乘寶，鵬風方快九霄程。", "公朝兼用人門選，外氏傳家舊有聲。"]'),
('63154a0a-a3cb-4545-a28c-e0245e853993','壽定叟弟','張栻','宋','宋诗','song-poetry','','[]','爲邦和氣滿鄉閭，袖手還家樂有餘。',64,'全唐诗/poet.song.150000.json','["爲邦和氣滿鄉閭，袖手還家樂有餘。", "案上簡編元好在，閑中日月更寬舒。", "功名且要身長健，尋尺何求計不疎。", "好泛菊英斟壽酒，扁舟吾欲賦歸歟。"]'),
('1f735159-9564-4824-ad62-761961074ccd','重九日與賓佐登龍山','張栻','宋','宋诗','song-poetry','','[]','曉風獵獵笛橫秋，澤國名山九日游。',64,'全唐诗/poet.song.150000.json','["曉風獵獵笛橫秋，澤國名山九日游。", "萬里煙雲歸老眼，千年形勢接中州。", "丘原到處堪懷古，萸菊隨時豈解愁。", "此日此心誰共領，朝宗江漢自東流。"]'),
('3258e49c-2b8c-41a2-b660-9b5f6ac6f3ac','贈樂仲恕','張栻','宋','宋诗','song-poetry','','[]','老子曾從先覺遊，後來文采繼風流。',64,'全唐诗/poet.song.150000.json','["老子曾從先覺遊，後來文采繼風流。", "胸中有意窮千古，筆下成章映九秋。", "塵世利名無著莫，聖門事業要精求。", "詠歸消息今猶在，魚躍鳶飛會得不。"]'),
('3b83ca24-8d43-4b59-8c1b-f4df20599e93','小園荼䕷盛開伯承以詩見督置酒于此爲增不敏之歎','張栻','宋','宋诗','song-poetry','','[]','留連紅紫計無從，晚惜芬芳萬卉空。',64,'全唐诗/poet.song.150000.json','["留連紅紫計無從，晚惜芬芳萬卉空。", "枕上幾回清夢斷，風前政可碧紗籠。", "春隨夜雨但三歎，韻入香醪尚一中。", "長有花開消息在，不應鳴鼓便相攻。"]'),
('42251b17-b0a9-4a89-a53b-3ee30be56785','再和  其一','張栻','宋','宋诗','song-poetry','','[]','閉門謝客少過從，獨倚修篁傲碧空。',64,'全唐诗/poet.song.150000.json','["閉門謝客少過從，獨倚修篁傲碧空。", "忽喜千條發瓊蕊，紛如萬鶴出樊籠。", "與君前日徘徊久，得句懸知慘淡中。", "胸次本無愁可著，何爲苦要酒兵攻。"]'),
('6c78b067-7856-44c6-82f7-0db80678f925','再和  其二','張栻','宋','宋诗','song-poetry','','[]','夜讀韋編起欲從，門前流水落花空。',64,'全唐诗/poet.song.150000.json','["夜讀韋編起欲從，門前流水落花空。", "春同心事應長在，月當燈光不用籠。", "弔古誰能嗟澤畔，高吟且欲效隆中。", "君詩似玉無瑕玷，豈有他山石可攻。"]'),
('869696c9-bfc7-4c8f-9ed0-6a8380adbd34','再和  其三','張栻','宋','宋诗','song-poetry','','[]','市朝車馬列雲從，君有危樓出半空。',64,'全唐诗/poet.song.150000.json','["市朝車馬列雲從，君有危樓出半空。", "但覺乾坤增老眼，不妨日月轉空籠。", "花開花落關何事，江北江南只此中。", "互出新詩殊未艾，長城尚許短兵攻。"]'),
('07179b6f-2ec8-4f37-84e5-3b6b5952161c','和楊教授  其一','張栻','宋','宋诗','song-poetry','','[]','道在無今昔，才難有屈伸。',48,'全唐诗/poet.song.150000.json','["道在無今昔，才難有屈伸。", "青編知了意，白眼付時人。", "鏡裏顔容舊，胸中事業新。", "絕歎知味鮮，渠自說甘辛。"]'),
('24022fe2-295f-4e6e-8893-2865e3ca3a98','和楊教授  其二','張栻','宋','宋诗','song-poetry','','[]','客少從蒿長，居深懶戶開。',48,'全唐诗/poet.song.150000.json','["客少從蒿長，居深懶戶開。", "孤城歲云莫，瘦馬子能來。", "長策憐葵向，新詩更雨催。", "相看前日事，此首忍重回。"]'),
('2c955e18-ea97-4eb4-b9ad-2106a2eedcd6','送少隠兄赴興元幕  其一','張栻','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','出手寧嫌晚，論心本不欺。',48,'全唐诗/poet.song.150000.json','["出手寧嫌晚，論心本不欺。", "五年江左客，萬里故園思。", "肯枉洞庭棹，來尋棠棣詩。", "固知名義重，豈但慰朝饑。"]'),
('ba2221f4-a580-4cba-ba27-5f943d0d5e4a','送少隠兄赴興元幕  其二','張栻','宋','宋诗','song-poetry','','[]','邊塞連關隴，貔貅罷戰征。',48,'全唐诗/poet.song.150000.json','["邊塞連關隴，貔貅罷戰征。", "幕中須預計，堂上乃奇兵。", "漢水追前策，秦原憶舊耕。", "書生亦多事，慷慨試經行。"]'),
('81851a1e-85e7-4ede-94c0-9ac781641122','廉州何使君挽詩二首  其一','張栻','宋','宋诗','song-poetry','','[]','橘井登賢籍，槐宮并俊游。',48,'全唐诗/poet.song.150000.json','["橘井登賢籍，槐宮并俊游。", "姓名題鴈塔，文字上瀛洲。", "青簡窮千載，朱轓但一州。", "有懷終未試，眼看落山丘。"]'),
('22ef43ae-0c15-4a55-a357-2fdf4ec605c9','廉州何使君挽詩二首  其二','張栻','宋','宋诗','song-poetry','','[]','憶昔湟江上，相逢意便傾。',48,'全唐诗/poet.song.150000.json','["憶昔湟江上，相逢意便傾。", "胸中元浩蕩，筆下更縱橫。", "士伏徐公德，人言景倩清。", "定應鄉里敬，枌社祭先生。"]'),
('c45b8b38-eb92-471e-920c-422726d48527','和張晉彥遊嶽麓','張栻','宋','宋诗','song-poetry','','[]','齋舫凌煙浦，雲屏入畫圖。',48,'全唐诗/poet.song.150000.json','["齋舫凌煙浦，雲屏入畫圖。", "日烘花炫晝，風定水明湖。", "布穀催春種，提壺勸客沽。", "湘中無限景，賦詠繼三都。"]'),
('8903e193-878f-4de5-8d40-982b7242e6c0','送臨武雷令  其一','張栻','宋','宋诗','song-poetry','','[]','詔舉循良吏，時資撫字功。',48,'全唐诗/poet.song.150000.json','["詔舉循良吏，時資撫字功。", "人情平易看，治道古今同。", "綠野新耕盛，潢池舊習空。", "便應君課最，名姓御屏中。"]'),
('037a0b5c-0fac-4318-bcfd-72ba369bd38b','送臨武雷令  其二','張栻','宋','宋诗','song-poetry','','[]','去路連崇嶺，扁舟上漲濤。',48,'全唐诗/poet.song.150000.json','["去路連崇嶺，扁舟上漲濤。", "不違將母願，敢歎獨賢勞。", "境靜歸鳧鴈，庭空長艾蒿。", "不妨頻拄頰，千里寄風騷。"]'),
('538b4036-48f9-4667-998a-e1dde5e7e885','喜雨呈安國','張栻','宋','宋诗','song-poetry','','[]','望歲民心切，爲霖帝力均。',48,'全唐诗/poet.song.150000.json','["望歲民心切，爲霖帝力均。", "崇朝變炎暑，舉目盡清新。", "坎坎連村鼓，熙熙萬室春。", "北窗凉枕簟，安穩到閑人。"]'),
('9b30773d-e1fe-4d08-a648-28209e43ecf6','十二月十六日夜枕上聞雷已而大雪','張栻','宋','宋诗','song-poetry','','[]','春信梅邊動，雷聲枕上驚。',48,'全唐诗/poet.song.150000.json','["春信梅邊動，雷聲枕上驚。", "忽看窗紙白，頓覺竹聲清。", "江海空餘夢，壺觴起自傾。", "朝來倚樓處，玉樹滿湘城。"]'),
('10281a54-6d7e-400d-a600-1c83593c821f','過湘潭劉信叔舊居有感','張栻','宋','宋诗','song-poetry','','[]','北渚留行客，東陵憶舊侯。',48,'全唐诗/poet.song.150000.json','["北渚留行客，東陵憶舊侯。", "池蓮半枯折，風葉正颼飀。", "事業留千載，英雄去一丘。", "平生許國志，歲晚詎悠悠。"]'),
('95479d1a-994b-4057-acc3-8f2d0bf74b78','題唐興寺湘江亭','張栻','宋','宋诗','song-poetry','','[]','寺廢蒼崖聳，江回遠岸明。',48,'全唐诗/poet.song.150000.json','["寺廢蒼崖聳，江回遠岸明。", "風霜摧翰墨，歲月老絲緡。", "兀坐知茶味，閑行忘去程。", "長哦伊水句，回首若爲情。"]'),
('b9b5dbfb-6fc2-4ed9-b5d5-9ea6b35c457e','彪德美來會于泉有詩因次韻','張栻','宋','宋诗','song-poetry','','["\u8861\u5c71"]','君卧衡山北，我行湘水濱。',48,'全唐诗/poet.song.150000.json','["君卧衡山北，我行湘水濱。", "相逢還莫逆，清絕兩無塵。", "勝集追前日，輕陰近小春。", "濯纓聊復爾，舉首謝簪紳。"]'),
('5019892e-3518-4128-a4f5-2d35496de156','上封有懷元晦','張栻','宋','宋诗','song-poetry','','[]','憶共朱夫子，登臨冰雪中。',48,'全唐诗/poet.song.150000.json','["憶共朱夫子，登臨冰雪中。", "劇談無俗調，得句有新功。", "別去鴈橫浦，重來月滿空。", "遥憐今夕意，清夢儻相同。"]'),
('29acf606-f84a-4e42-b699-1c7d5957d3bc','題福巖','張栻','宋','宋诗','song-poetry','','[]','擲鉢峯前寺，肩輿幾度來。',48,'全唐诗/poet.song.150000.json','["擲鉢峯前寺，肩輿幾度來。", "樓臺還舊觀，杉檜撫新栽。", "湘水堂堂去，秋山面面開。", "裴徊千古思，風壑有餘哀。"]'),
('7ce7334c-c6e6-47d3-9226-b5e41e0bf6f5','題南臺寺','張栻','宋','宋诗','song-poetry','','[]','相望幾蘭若，勝處是南臺。',48,'全唐诗/poet.song.150000.json','["相望幾蘭若，勝處是南臺。", "閣迥規摹穩，門空晝夜開。", "回風時浩蕩，高嶺更崔嵬。", "謾說石頭滑，支筇得往來。"]'),
('e0e700bd-8b8c-4d0c-85f2-f5c54ab8f299','由西嶺行後洞山路','張栻','宋','宋诗','song-poetry','','[]','西嶺更西路，雲嵐最窈深。',48,'全唐诗/poet.song.150000.json','["西嶺更西路，雲嵐最窈深。", "水流千澗底，樹合四時陰。", "幽絕無僧住，閑來有客吟。", "山行三十里，鐘磬忽傳音。"]'),
('26469936-9355-4b92-84f5-e479ff11a60a','過高臺寺','張栻','宋','宋诗','song-poetry','','[]','著屋懸崖畔，開窗疊嶂秋。',48,'全唐诗/poet.song.150000.json','["著屋懸崖畔，開窗疊嶂秋。", "半欹雲榭冷，不斷石泉流。", "茗椀味能永，竹風聲更幽。", "平生版庵老，得句似湯休。"]'),
('7a270102-6ab4-49be-a944-692906b38754','宿方廣寺','張栻','宋','宋诗','song-poetry','','[]','俗塵元迥隔，景物自天成。',48,'全唐诗/poet.song.150000.json','["俗塵元迥隔，景物自天成。", "山近四圍碧，泉鳴永夜清。", "月華侵戶冷，秋氣與雲橫。", "曉起尋歸路，題詩寄此情。"]'),
('2071c2e2-f764-4402-aeae-f512b4b02db9','和黄漕雪中將至長沙','張栻','宋','宋诗','song-poetry','','[]','吾道元如砥，人間謾畏途。',48,'全唐诗/poet.song.150000.json','["吾道元如砥，人間謾畏途。", "未容舟泝峽，且泛雪平湖。", "子孝寧投杼，天回看脫弧。", "不應從我懶，欲老豆麻區。"]'),
('64d29b13-119e-46fb-a446-c909e8effcd4','人日遊城東晚飯陳仲思茅亭分韻得香字','張栻','宋','宋诗','song-poetry','','[]','絕憐梅事晚，與客到林塘。',48,'全唐诗/poet.song.150000.json','["絕憐梅事晚，與客到林塘。", "瓦椀村醪釅，杯羹野菜香。", "舊遊看壁字，新歲尚他鄉。", "一笑俱真率，悠然意未央。"]'),
('3108bc13-d3a4-4a42-8cf4-bbfecb49fb33','二月十日野步城南晚與吳伯承諸友飲裴臺分韻得江字','張栻','宋','宋诗','song-poetry','','[]','春日煙沙岸，禪房風竹窗。',48,'全唐诗/poet.song.150000.json','["春日煙沙岸，禪房風竹窗。", "有時傾綠酒，隨處見清江。", "世路紛多轍，吾生老此邦。", "千林看不盡，白鳥去雙雙。"]'),
('4014c09c-f103-481b-bdb5-8884a88d6a33','與弟姪飲梅花下分韻得香字','張栻','宋','宋诗','song-poetry','','[]','日多色愈正，春和天與香。',48,'全唐诗/poet.song.150000.json','["日多色愈正，春和天與香。", "提携一樽酒，問訊滿園芳。", "嗣歲詩多思，懷人心甚長。", "更須多秉燭，玉立勝紅粧。"]'),
('413d1d9c-5b72-4c93-b431-268914048d15','十四日陪黄仲秉渡湘飲嶽麓臺上分韻得長字','張栻','宋','宋诗','song-poetry','','[]','支筇穿百級，把酒問春光。',48,'全唐诗/poet.song.150000.json','["支筇穿百級，把酒問春光。", "喬木依然在，幽蘭祇自芳。", "未當湘水滿，更覺橘洲長。", "暝色猶回首，天涯話故鄉。"]'),
('c95388c3-734c-42dd-8984-3166f559df4b','王長沙約飲縣圃梅花下分韻得梅字','張栻','宋','宋诗','song-poetry','','[]','平生佳絕處，心事付江梅。',48,'全唐诗/poet.song.150000.json','["平生佳絕處，心事付江梅。", "縣圃經年見，芳樽薄暮開。", "朗吟空激烈，燒燭且徘徊。", "未逐徵書去，窮冬尚一來。"]'),
('643f1bb5-e7ea-4bff-ac9a-e0a2fd6d482c','湯總管邢監廟約遊城東酒間求詩爲賦此','張栻','宋','宋诗','song-poetry','','[]','春事已如許，客愁空自多。',48,'全唐诗/poet.song.150000.json','["春事已如許，客愁空自多。", "梅花成莫逆，樽酒付亡何。", "楚楚邢郎子，眈眈老伏波。", "定應容我醉，耳熱更高歌。"]'),
('1bf7274c-b48b-4cb7-9caf-631847a138da','謝胡掾惠詩','張栻','宋','宋诗','song-poetry','','[]','一見知心事，旋觀慰月評。',48,'全唐诗/poet.song.150000.json','["一見知心事，旋觀慰月評。", "慈祥漢循吏，儒雅魯諸生。", "莫作周南歎，終期冀北程。", "新詩連夜讀，梅影伴孤清。"]'),
('db3083d7-f07d-4faf-8254-a9a3211b81ef','除夜立春','張栻','宋','宋诗','song-poetry','','[]','積雪陰難解，新梅凍未開。',48,'全唐诗/poet.song.150000.json','["積雪陰難解，新梅凍未開。", "誰知殘臘底，已報早春來。", "一氣元無息，羣兒浪自猜。", "短檠非守歲，百感政交懷。"]'),
('c4c022a7-f8a0-44c2-9599-c613badb75cf','送趙節卿','張栻','宋','宋诗','song-poetry','','[]','昭代才難歎，宗盟世有人。',48,'全唐诗/poet.song.150000.json','["昭代才難歎，宗盟世有人。", "千鈞定晚試，一角信逢真。", "政擬尋梅共，還經折柳新。", "青雲看穩上，回首楚江春。"]'),
('db0e0e7c-18d9-4841-90ea-d7f88935b345','二月二十五日登裴臺坐上口占','張栻','宋','宋诗','song-poetry','','[]','朝來風雨好，抱病亦登臨。',48,'全唐诗/poet.song.150000.json','["朝來風雨好，抱病亦登臨。", "故國江山在，荒城花柳深。", "憂時空百慮，望遠只微吟。", "春事如櫻筍，幽盟可重尋。"]'),
('0d57ba1e-79a1-4d26-bda3-b6479394593d','上巳日晚登裴臺自仲春凡三登','張栻','宋','宋诗','song-poetry','','[]','前日看花地，重來對落暉。',48,'全唐诗/poet.song.150000.json','["前日看花地，重來對落暉。", "雨餘山著色，沙沒水初肥。", "寒食家家出，殘紅樹樹飛。", "還同二三子，及此詠而歸。"]'),
('8fcf344f-39e6-4ece-adc4-59964577a8fa','長沙郡丞丁君挽詞','張栻','宋','宋诗','song-poetry','','[]','廉吏今尤重，朝家詔舉頻。',48,'全唐诗/poet.song.150000.json','["廉吏今尤重，朝家詔舉頻。", "方看千里駕，忽盡百年身。", "職業憂勞甚，遊從笑語真。", "空令行路歎，沒後見清貧。"]'),
('23ab2cd0-a662-4572-bd27-751dcedf8912','和黄仲秉喜雨','張栻','宋','宋诗','song-poetry','','[]','雨凉窗戶好，佳木正陰陰。',48,'全唐诗/poet.song.150000.json','["雨凉窗戶好，佳木正陰陰。", "畎畝憂時念，乾坤濟物心。", "引泉聊自照，移竹更親臨。", "尚想皇華使，風前擁鼻吟。"]'),
('fceef374-0d4c-417b-9806-39e70302a191','寄侯彥周','張栻','宋','宋诗','song-poetry','','[]','塞鴈仍南去，慇懃問耒陽。',48,'全唐诗/poet.song.150000.json','["塞鴈仍南去，慇懃問耒陽。", "催科應獨拙，理髮詎能長。", "邑古絃歌地，年豐魚稻鄉。", "婆娑還得不，三徑未云荒。"]'),
('18e48b2b-422e-4140-a205-1ad18577db2b','過長橋','張栻','宋','宋诗','song-poetry','','[]','西風吹短髮，復此渡長橋。',48,'全唐诗/poet.song.150000.json','["西風吹短髮，復此渡長橋。", "木落波空闊，亭孤影動摇。", "徘徊念今昔，領畧到漁樵。", "儻有山中隠，憑誰爲一招。"]'),
('4ce3dd34-fd42-4444-a26b-84e4f4859707','多景樓','張栻','宋','宋诗','song-poetry','','[]','疇昔南徐地，登臨北固樓。',48,'全唐诗/poet.song.150000.json','["疇昔南徐地，登臨北固樓。", "平原迷故國，滄海接江流。", "木落煙莎晚，城孤鼓角秋。", "寄言鷗鷺侶，吾已具扁舟。"]'),
('b064106e-87fd-4736-b5c1-2b3c145a8468','金山','張栻','宋','宋诗','song-poetry','','[]','萬頃洪濤裏，巍然閲古今。',48,'全唐诗/poet.song.150000.json','["萬頃洪濤裏，巍然閲古今。", "雲煙三島接，花木四時深。", "亂石維舟住，西風倚檻吟。", "朝宗知不斷，凄切此時心。"]'),
('3f3e2cae-1760-4561-b075-8ea6265313bd','重陽前一日','張栻','宋','宋诗','song-poetry','','[]','九日明朝是，清樽强自開。',48,'全唐诗/poet.song.150000.json','["九日明朝是，清樽强自開。", "蕭蕭疎雨暗，滾滾大江來。", "野菊閑無數，沙鷗靜不猜。", "何須騎臺飲，此興亦悠哉。"]'),
('3ab6bf8e-1121-4b6c-b342-81d21c5f8c0a','十五日過小孤山','張栻','宋','宋诗','song-poetry','','[]','沃野迥千里，巋然突孤標。',48,'全唐诗/poet.song.150000.json','["沃野迥千里，巋然突孤標。", "崖分勢亦裂，江靜影頻摇。", "栖鶻巢何險，盤柯凍不凋。", "吾行足觀覽，未覺客程遥。"]'),
('834e79dc-cd27-4a38-a5a3-dbc46ebeb9a1','新亭','張栻','宋','宋诗','song-poetry','','[]','風景自今古，斯亭今是非。',48,'全唐诗/poet.song.150000.json','["風景自今古，斯亭今是非。", "絕憐江水去，還有故山圍。", "得失同千慮，成虧共一機。", "所思惟謝傅，不但勝淮淝。"]'),
('05340d57-9194-441c-899a-b1166739b199','庚申過青草湖','張栻','宋','宋诗','song-poetry','','[]','已越重湖險，張帆勝順流。',48,'全唐诗/poet.song.150000.json','["已越重湖險，張帆勝順流。", "亂雲藏野寺，橫網閙漁舟。", "物色湖南好，風霜歲晚謀。", "未知荒歉後，得似向來不。"]'),
('ea7419ae-95d4-45a5-8e52-f4d9e2d2cd48','喜聞定叟弟歸','張栻','宋','宋诗','song-poetry','','[]','吾弟三年別，歸舟半月程。',48,'全唐诗/poet.song.150000.json','["吾弟三年別，歸舟半月程。", "瘦肥應似舊，歡喜定如兄。", "秋日聯鴻影，凉窗聽雨聲。", "人間團聚樂，身外總云輕。"]'),
('972d84f1-dea0-437a-b6dc-acd21f02bb3b','聞定叟弟已近適迫祀事未能出先遣姪輩往迎書此問訊','張栻','宋','宋诗','song-poetry','','[]','漸喜書題近，懸知歸意忙。',48,'全唐诗/poet.song.150000.json','["漸喜書題近，懸知歸意忙。", "才聞下湘水，早已過衡陽。", "雨洗秋山凈，凉生桂樹香。", "慇懃二三子，策馬爲迎將。"]'),
('272bc732-056e-4f75-9543-9eb1956860ae','醇叟崇道之喪未得往哭聞窀穸有期輒賦二章以相挽者  其一','張栻','宋','宋诗','song-poetry','','[]','慶席親賢胄，心知道義尊。',48,'全唐诗/poet.song.150000.json','["慶席親賢胄，心知道義尊。", "如何著閑處，終不近修門。", "三載成長別，微言未細論。", "人琴俱寂寞，風雨閉丘園。"]'),
('75a591bc-bf55-4753-97b3-57c3b8987dd3','醇叟崇道之喪未得往哭聞窀穸有期輒賦二章以相挽者  其二','張栻','宋','宋诗','song-poetry','','[]','晚歲渾無事，端居只自如。',48,'全唐诗/poet.song.150000.json','["晚歲渾無事，端居只自如。", "冰霜澆塊磊，日月老籧篨。", "山寺留題墨，晴窗罷卷書。", "從今行嶽路，忍復過公廬。"]'),
('1687a762-b791-4c48-ac81-9739b290e86f','故太子詹事王公挽詩二首  其一','張栻','宋','宋诗','song-poetry','','[]','大節元無玷，中心本不欺。',48,'全唐诗/poet.song.150000.json','["大節元無玷，中心本不欺。", "排姦力扛鼎，憂國鬢成絲。", "方喜三旌召，俄興一鑑悲。", "西風吹淚眼，夫豈哭吾私。"]'),
('1a6c401e-1018-4ae5-886e-47c92230fdd5','故太子詹事王公挽詩二首  其二','張栻','宋','宋诗','song-poetry','','[]','睿主龍飛日，如公舊學臣。',48,'全唐诗/poet.song.150000.json','["睿主龍飛日，如公舊學臣。", "忠言關國計，清節映廷紳。", "歲月身多外，江湖澤在民。", "當年遺直歎，千古更如新。"]'),
('da7f133b-020c-480e-b767-1a9331babc62','詩送陳仲思參佐廣右幕府','張栻','宋','宋诗','song-poetry','','[]','舊說桂林好，君今幕府遊。',48,'全唐诗/poet.song.150000.json','["舊說桂林好，君今幕府遊。", "江山資暇日，梅雪類吾州。", "煮海何多說，安邊更預謀。", "政應勤婉畫，不用賦離憂。"]'),
('12a1be6a-b1b0-4e07-83c9-6f517d739f75','呂善化秩滿而歸兩詩贈行  其一','張栻','宋','宋诗','song-poetry','','[]','令尹三年政，湘民去息思。',48,'全唐诗/poet.song.150000.json','["令尹三年政，湘民去息思。", "艱難救災歉，憂瘁見云爲。", "薦牘今交上，夷途去不疑。", "正須頻顧省，御者可無辭。"]'),
('e09e0ca3-d0a7-46bb-a441-9f5f2764e478','呂善化秩滿而歸兩詩贈行  其二','張栻','宋','宋诗','song-poetry','','[]','伯氏相從舊，歸來意若何。',48,'全唐诗/poet.song.150000.json','["伯氏相從舊，歸來意若何。", "從渠笑方拙，還我自吟哦。", "聖有詩書在，人多歲月過。", "德門好兄弟，夜雨細研磨。"]'),
('69fbe959-31c6-4501-b815-e6638c07fe00','默姪之官襄陽兩詩以送之  其一','張栻','宋','宋诗','song-poetry','','[]','默也相從久，吾心念汝多。',48,'全唐诗/poet.song.150000.json','["默也相從久，吾心念汝多。", "又爲江漢別，空覺歲年過。", "氣習須消靡，工夫在講磨。", "惟應介如石，人事易蹉跎。"]'),
('785b72ed-4e21-4355-b609-19d9543f3d8f','默姪之官襄陽兩詩以送之  其二','張栻','宋','宋诗','song-poetry','','[]','潦雨彌旬月，予方念鞠窮。',48,'全唐诗/poet.song.150000.json','["潦雨彌旬月，予方念鞠窮。", "子行何草草，別語又匆匆。", "漢沔英靈在，江山今昔同。", "未須登峴首，先合拜隆中。"]'),
('b5f44cf2-1521-4100-b174-a961536c8ab4','送零陵賈使君二首  其一','張栻','宋','宋诗','song-poetry','','[]','藉甚零陵郡，風流記昔賢。',48,'全唐诗/poet.song.150000.json','["藉甚零陵郡，風流記昔賢。", "宅存元水部，人識范忠宣。", "山近地宜竹，溪清岸有泉。", "官閒時訪古，餘韻故依然。"]'),
('56bc7f03-47f8-407b-b77f-aeb0c20b7c66','送零陵賈使君二首  其二','張栻','宋','宋诗','song-poetry','','[]','孝友傳家法，如君好弟兄。',48,'全唐诗/poet.song.150000.json','["孝友傳家法，如君好弟兄。", "祇應推此意，便足慰民情。", "間歲仍艱食，新書督勸耕。", "想今瀟水畔，惟日望雙旌。"]'),
('070c0a8d-a5c6-4c12-ab00-e6d8097f5a47','寄曾節夫','張栻','宋','宋诗','song-poetry','','[]','曾子別經月，相思如幾秋。',48,'全唐诗/poet.song.150000.json','["曾子別經月，相思如幾秋。", "不應行役歎，却爲賈胡留。", "雨後湖光滿，梅邊春意浮。", "須君細商略，晴日共茶甌。"]'),
('59a7a4b4-9ab6-49bb-9fce-c92e27a98ac8','送周畏知二首  其一','張栻','宋','宋诗','song-poetry','','[]','秋冬仍苦雨，旬浹喜霜晴。',48,'全唐诗/poet.song.150000.json','["秋冬仍苦雨，旬浹喜霜晴。", "木末樓臺見，江頭橘柚明。", "登臨方適意，離別已增情。", "後夜相思地，寒梅影正橫。"]'),
('5084168f-4379-4be7-853d-a8249a7e42c3','送周畏知二首  其二','張栻','宋','宋诗','song-poetry','','[]','半世功名誤，蒼顔幕府游。',48,'全唐诗/poet.song.150000.json','["半世功名誤，蒼顔幕府游。", "文辭追楚些，得失付陽秋。", "薦牘方交上，衡門豈重留。", "青雲看穩去，快處一回眸。"]'),
('73792510-d749-402a-98a6-82af418e0320','題伏龍寺壁','張栻','宋','宋诗','song-poetry','','[]','少日憶曾到，歸途得小留。',48,'全唐诗/poet.song.150000.json','["少日憶曾到，歸途得小留。", "回還山寺古，蕭瑟柿林秋。", "道路情無那，琴書可細求。", "從來士窮達，分付水悠悠。"]'),
('94042f36-9981-4424-9288-1fa583298971','送外弟宇文挺臣二首  其一','張栻','宋','宋诗','song-poetry','','[]','合族情尤重，論交意復深。',48,'全唐诗/poet.song.150000.json','["合族情尤重，論交意復深。", "還爲萬里別，未盡幾年心。", "佳處應相憶，書來儻嗣音。", "及時須努力，莫待鬢華侵。"]'),
('429b9a0d-bc54-49a4-bb14-78adaa89e83f','送外弟宇文挺臣二首  其二','張栻','宋','宋诗','song-poetry','','[]','漠漠灕江上，匆匆送客情。',48,'全唐诗/poet.song.150000.json','["漠漠灕江上，匆匆送客情。", "平原宵雨濕，絕壁野雲橫。", "世路多新轍，韋編有舊盟。", "中流屹砥柱，過浪豈能傾。"]'),
('5e535f66-49ce-48fa-bdaa-416fa27125e5','寄題周功父溪園三詠 嫣然亭','張栻','宋','宋诗','song-poetry','','[]','聞說亭花好，居然似蜀鄉。',48,'全唐诗/poet.song.150000.json','["聞說亭花好，居然似蜀鄉。", "色深姿不俗，香淡意能長。", "高燭留深夜，輕陰護晚芳。", "何心較桃李，只擬答春光。"]'),
('9713a73c-7afa-463d-b8f0-1a4d938c78f3','寄題周功父溪園三詠 溪亭','張栻','宋','宋诗','song-poetry','','[]','未識主人面，先爲溪上吟。',48,'全唐诗/poet.song.150000.json','["未識主人面，先爲溪上吟。", "澄潭依近岸，絕壁聳遥林。", "領略襟期遠，登臨歲律深。", "想當軒冕外，三歎有餘音。"]'),
('8e68510b-7d85-46f6-8294-d2087cab4847','寄題周功父溪園三詠 雪亭','張栻','宋','宋诗','song-poetry','','[]','溪園平廣處，雅稱雪中游。',48,'全唐诗/poet.song.150000.json','["溪園平廣處，雅稱雪中游。", "疎密看千變，高低共一丘。", "寒知松節勁，靜覺竹聲幽。", "還有故人否，當能著小舟。"]'),
('d60741de-f252-4d25-99c3-f40fbfd8780b','曾節夫罷官歸旴江以小詩寄別','張栻','宋','宋诗','song-poetry','','[]','俗隘寧爲異，言深敢自欺。',48,'全唐诗/poet.song.150000.json','["俗隘寧爲異，言深敢自欺。", "如何幕中辯，翻作暗投疑。", "行李秋將半，家園菊正滋。", "反躬端得味，當復有餘師。"]'),
('94d307f0-61dc-4172-9208-636563ff8f85','寄趙漕','張栻','宋','宋诗','song-poetry','','[]','想得昭潭上，兒童夾道迎。',48,'全唐诗/poet.song.150000.json','["想得昭潭上，兒童夾道迎。", "皇華今日使，竹馬舊時情。", "梅蕊冬前拆，山光雨後清。", "使君桃李客，當爲駐車旌。"]'),
('f0bddd24-5cf5-4a09-b1f8-5211de106b9e','送李新州','張栻','宋','宋诗','song-poetry','','[]','清絕湘南地，鄉間見老成。',48,'全唐诗/poet.song.150000.json','["清絕湘南地，鄉間見老成。", "蔽棠方有望，折柳却關情。", "側聽輿人誦，還新月旦評。", "相望幸鄰壤，猶得借餘明。"]'),
('4f114e3d-ee48-48c6-a756-61d191064175','游誠之來廣西相從幾一年今當赴官九江極與之惜別兩詩餞行  其一','張栻','宋','宋诗','song-poetry','','[]','游子名家後，天資更敏强。',48,'全唐诗/poet.song.150000.json','["游子名家後，天資更敏强。", "壯懷知自許，遠業定難量。", "幕府文書簡，韋編趣味長。", "悵然成闊別，音寄莫相忘。"]'),
('a0761d56-b386-49a7-91b9-33de2336ccc0','游誠之來廣西相從幾一年今當赴官九江極與之惜別兩詩餞行  其二','張栻','宋','宋诗','song-poetry','','[]','士學端成己，工夫要自程。',48,'全唐诗/poet.song.150000.json','["士學端成己，工夫要自程。", "聖門窺廣大，中德養和平。", "美玉資勤琢，良才詎小成。", "心期須後會，拭目更增明。"]'),
('c6c8c6d3-ff44-4d97-8d48-810a81179976','寄宇文邛州','張栻','宋','宋诗','song-poetry','','[]','寄語臨邛守，相望萬里情。',48,'全唐诗/poet.song.150000.json','["寄語臨邛守，相望萬里情。", "有來詩句好，足驗教條清。", "好古從時訕，爲邦已政成。", "無尋子虛賦，忠厚詔諸生。"]'),
('698d924b-1304-4ec4-99d5-7c8afa21caaa','次陳擇之遊湖韻','張栻','宋','宋诗','song-poetry','','[]','落日遊鱼上，青林白鳥過。',48,'全唐诗/poet.song.150000.json','["落日遊鱼上，青林白鳥過。", "稻香來隔岸，巖影占清波。", "招隠何年賦，尋幽此地多。", "晚凉容縱棹，聽我采菱歌。"]'),
('ef57af51-aea0-4c50-8193-eedb956740f4','送但能之守潯州','張栻','宋','宋诗','song-poetry','','[]','循吏古猶少，嶺民今未蘇。',48,'全唐诗/poet.song.150000.json','["循吏古猶少，嶺民今未蘇。", "丁寧煩詔旨，推擇得吾徒。", "根本誰深念，詩書計不迂。", "惟應敦此意，豈但應時須。"]'),
('b4152c35-2458-40eb-a4db-5acecfa1154e','送祖七姪西歸二首  其一','張栻','宋','宋诗','song-poetry','','[]','萬里逢猶子，中年憶故鄉。',48,'全唐诗/poet.song.150000.json','["萬里逢猶子，中年憶故鄉。", "只知情話好，豈覺去途長。", "巫峽波濤壯，秦山檜柏蒼。", "何能從汝往，佇立看歸艎。"]'),
('f547723e-3aa2-4225-8a5c-1bcae65f00d3','送祖七姪西歸二首  其二','張栻','宋','宋诗','song-poetry','','[]','故國非喬木，名家重典刑。',48,'全唐诗/poet.song.150000.json','["故國非喬木，名家重典刑。", "飄零念吾黨，寂寞撫遺經。", "菽水知何病，芝蘭要滿庭。", "汝歸應記取，爲我話丁寧。"]'),
('15aa00c4-1943-4543-b7bc-16e3e2a48a28','中春過陽亭','張栻','宋','宋诗','song-poetry','','[]','亭古危臨岸，林幽巧近城。',48,'全唐诗/poet.song.150000.json','["亭古危臨岸，林幽巧近城。", "煙容隨雨住，花片著溪清。", "春事已如許，客懷誰與傾。", "亭前兩好樹，滿意欲敷榮。"]'),
('44db3263-7103-41be-9f3a-e72c52819c74','堯廟','張栻','宋','宋诗','song-poetry','','[]','明祀崇千載，荒山拱萬靈。',48,'全唐诗/poet.song.150000.json','["明祀崇千載，荒山拱萬靈。", "插天巉絕壁，飛瀑下空庭。", "繪事存淳古，真風寄杳冥。", "蘋繁何以薦，帝德日惟馨。"]'),
('57371f2e-09b1-417b-9381-55d599b7945c','戶曹廬陵胡君引年求謝事予視其精力未衰留之踰半載乃今告去不復可挽爲詩送別澹庵君之叔父也','張栻','宋','宋诗','song-poetry','','[]','出守嗟何晚，懷歸已倦游。',48,'全唐诗/poet.song.150000.json','["出守嗟何晚，懷歸已倦游。", "細看渾矍鑠，可是畏伊優。", "幕下傾三語，山中賦四愁。", "平生大小阮，來往足風流。"]'),
('6fc7530c-7ec7-4252-a13e-e0dee6b906eb','若海運使移節廣東賦詩贈別予每過若海諸郎誦書于旁琅琅可喜爲之重賦  其一','張栻','宋','宋诗','song-poetry','','[]','行止非人料，驅馳未席溫。',48,'全唐诗/poet.song.150000.json','["行止非人料，驅馳未席溫。", "傳聞選膚使，端爲慰黎元。", "瘴嶺農耕少，山城海氣昏。", "唯勤凋瘵慮，此外更何言。"]'),
('c8d2600a-5dff-446d-86f7-f7506d25ac98','若海運使移節廣東賦詩贈別予每過若海諸郎誦書于旁琅琅可喜爲之重賦  其二','張栻','宋','宋诗','song-poetry','','[]','玉雪明人眼，森然膝下郎。',48,'全唐诗/poet.song.150000.json','["玉雪明人眼，森然膝下郎。", "原流知衮衮，誦讀聽琅琅。", "有子若何慕，他年我莫量。", "願崇詩禮訓，勿近利名場。"]'),
('2661ae48-43ce-4341-8ed2-9c97dcf6314d','送李崧老歸閩二首  其一','張栻','宋','宋诗','song-poetry','','[]','歷數勳賢後，如君到眼希。',48,'全唐诗/poet.song.150000.json','["歷數勳賢後，如君到眼希。", "胸中藴金石，筆下出珠璣。", "傾蓋嗟何晚，臨流又送歸。", "他年儻相憶，尋我釣魚磯。"]'),
('212c4177-fd9a-4333-b13a-e0207859a786','送李崧老歸閩二首  其二','張栻','宋','宋诗','song-poetry','','[]','公事妨開卷，遐征念索居。',48,'全唐诗/poet.song.150000.json','["公事妨開卷，遐征念索居。", "能來數月款，端爲百憂紓。", "師友洛川上，人才元祐初。", "歸來有新益，不惜幾行書。"]'),
('b3011cc9-b705-44ce-a04d-a04bd4655ffa','和定叟送行韻','張栻','宋','宋诗','song-poetry','','[]','舊別情何限，重逢意豁然。',48,'全唐诗/poet.song.150000.json','["舊別情何限，重逢意豁然。", "相看疑似夢，款語不成眠。", "但欲燈窗共，其如事役牽。", "固應回首處，祇在集雲前。"]'),
('f0d76be7-b377-4c65-ad4e-f568af004f0e','題益陽清修寺','張栻','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','峯勢香爐直，溪流峽水潺。',48,'全唐诗/poet.song.150000.json','["峯勢香爐直，溪流峽水潺。", "居然一蘭若，喚作小廬山。", "老木千崖表，孤亭萬竹間。", "明朝問征路，回首白雲閑。"]'),
('3d9d1ae7-023f-4be2-b251-e28495bc877a','故觀文建安劉公挽詩四首  其一','張栻','宋','宋诗','song-poetry','','[]','憶昨登廊廟，忠言達帝聰。',48,'全唐诗/poet.song.150000.json','["憶昨登廊廟，忠言達帝聰。", "所思惟盡瘁，敢復計成功。", "半世江湖上，千憂寤寐中。", "汗青誰秉筆，請考衆言公。"]'),
('a08eb917-82ac-4543-b6c4-020715ab0b22','故觀文建安劉公挽詩四首  其二','張栻','宋','宋诗','song-poetry','','[]','國恥臣當死，公家二世心。',48,'全唐诗/poet.song.150000.json','["國恥臣當死，公家二世心。", "忍看垂絕筆，誰續斷絃音。", "精爽今如在，衣冠恨更深。", "却嗟蜍與志，處世漫侵尋。"]'),
('df9f2149-af8e-4eb7-accb-3a711d2f8176','故觀文建安劉公挽詩四首  其三','張栻','宋','宋诗','song-poetry','','[]','平日多奇節，中間似富公。',48,'全唐诗/poet.song.150000.json','["平日多奇節，中間似富公。", "天從廬墓請，人說救荒功。", "辛苦培邦本，雍容遏亂鋒。", "文傳遺奏切，更過子囊忠。"]'),
('b65dd64b-7d19-40ed-849c-976b49dbcd95','故觀文建安劉公挽詩四首  其四','張栻','宋','宋诗','song-poetry','','[]','曾是南荆地，他年竹馬迎。',48,'全唐诗/poet.song.150000.json','["曾是南荆地，他年竹馬迎。", "旌旂嚴騎士，弧矢盛民兵。", "細考規摹舊，還知節制明。", "思公如峴首，同我淚縱橫。"]'),
('ffdbf054-5937-4c61-9d6b-c9859021f482','追餞馬憲','張栻','宋','宋诗','song-poetry','','[]','膚使行原隰，清風伴往還。',48,'全唐诗/poet.song.150000.json','["膚使行原隰，清風伴往還。", "詩情渾漫興，雪意正相關。", "許國心何壯，憂民鬢易斑。", "留連三日語，解后十年間。"]'),
('4499b3ac-c404-4e5c-ad33-998c1302c7ea','某以四十字送詳刑使君','張栻','宋','宋诗','song-poetry','','[]','拙守荆江上，無人共往還。',48,'全唐诗/poet.song.150000.json','["拙守荆江上，無人共往還。", "能來慰牢落，話舊幾間關。", "冬壑龍蛇蟄，風林虎豹斑。", "相期涵養力，且到古人間。"]'),
('77cc73da-ba33-47af-a5a2-53aee6e17b2e','除夕登仲宣樓','張栻','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','懷土昔人志，傷時此日心。',48,'全唐诗/poet.song.150000.json','["懷土昔人志，傷時此日心。", "長江霜潦凈，故國莫煙深。", "訪古多遺恨，憑欄更獨吟。", "細看前浦樹，生意已堪尋。"]'),
('f438e8dd-02a9-4a00-a240-39c6666f23a1','隔牆聞正父鄉飲甚樂偶畏風不預用前韻敬簡','張栻','宋','宋诗','song-poetry','','[]','元日忻晴色，新年祇舊心。',48,'全唐诗/poet.song.150000.json','["元日忻晴色，新年祇舊心。", "故人同客裏，鄉話自情深。", "儘說成都酒，休爲楚澤吟。", "相逢須痛飲，歲月易侵尋。"]'),
('5905b037-a49d-450c-871d-5a023ac50686','劉勝因自襄陽過予渚宮於其歸小詩贈別','張栻','宋','宋诗','song-poetry','','[]','骯髒寧多忤，棲遲久倦游。',48,'全唐诗/poet.song.150000.json','["骯髒寧多忤，棲遲久倦游。", "折肱諳世味，袖手惜良籌。", "日月隆中晚，風煙峴首愁。", "登臨應慷慨，還解寄詩不。"]'),
('0bdece67-b6c3-402d-929e-7f1ace4f2f50','光弼姪得邑西歸賦詩勉之併示光義二首  其一','張栻','宋','宋诗','song-poetry','','[]','共惟二百載，詩禮一門中。',48,'全唐诗/poet.song.150000.json','["共惟二百載，詩禮一門中。", "冷落吾憂甚，扶持爾輩同。", "傳心無異轍，隨用不言功。", "外慕知何極，惟應念祖風。"]'),
('24ecd8db-07ae-4bba-9a12-9c4c4cf2a7a6','光弼姪得邑西歸賦詩勉之併示光義二首  其二','張栻','宋','宋诗','song-poetry','','[]','得邑寧論小，居官最近民。',48,'全唐诗/poet.song.150000.json','["得邑寧論小，居官最近民。", "中誠儻無倦，同體會相親。", "暇日書還讀，清源政自新。", "吾兄有遺訓，爾輩足持循。"]'),
('cb1580cf-aeb1-4494-97f8-45c2f9ccdb53','送曾裘父','張栻','宋','宋诗','song-poetry','','[]','交舊間何闊，能來浹日留。',48,'全唐诗/poet.song.150000.json','["交舊間何闊，能來浹日留。", "還尋佳橘頌，惜別仲宣樓。", "探古書盈屋，憂時雪滿頭。", "絕思黄閣老，招隠意綢繆。"]'),
('79cc7386-b133-488a-a558-2ac325b2a99d','帳幹周君桂林相從之舊己亥莫春出嶺迂道相過臨別求予言姑賦此','張栻','宋','宋诗','song-poetry','','[]','江北逢新雨，湘南憶舊遊。',48,'全唐诗/poet.song.150000.json','["江北逢新雨，湘南憶舊遊。", "能來慰岑寂，恨不小遲留。", "日月徒催老，巧名浪自愁。", "惟應編簡樂，在己可深求。"]'),
('17d047cd-7b5b-4cf4-9aac-37ec86c44046','中秋與僚佐登江陵郡城觀月','張栻','宋','宋诗','song-poetry','','[]','凉意今年早，蟾光七澤多。',48,'全唐诗/poet.song.150000.json','["凉意今年早，蟾光七澤多。", "憑欄共懷古，擁袂獨高歌。", "風物關山遠，功名歲月過。", "一樽聊復爾，於此興如何。"]'),
('55dbb4df-627d-4aad-8e54-d0d21561519c','遊章華臺','張栻','宋','宋诗','song-poetry','','[]','楚國舊雄勝，荒臺今是非。',48,'全唐诗/poet.song.150000.json','["楚國舊雄勝，荒臺今是非。", "平川留宿潦，蕭寺掩斜暉。", "木落秋聲急，天高鴈影微。", "凄凉無處問，騎馬踏堤歸。"]'),
('37fe9273-69d8-46ff-9fe2-5e842313e160','和元晦擇之有詩見懷','張栻','宋','宋诗','song-poetry','','[]','作別又如許，何當置我旁。',48,'全唐诗/poet.song.150000.json','["作別又如許，何當置我旁。", "卷舒書在手，展轉月侵床。", "合志師千載，相思謾一方。", "臨風三歎息，此意渺難量。"]'),
('26a4ff79-8431-4ed0-86fb-a769b80bf138','送范伯崇','張栻','宋','宋诗','song-poetry','','[]','堂堂延閣老，遺範見斯人。',48,'全唐诗/poet.song.150000.json','["堂堂延閣老，遺範見斯人。", "孝友傳家舊，詩書用力新。", "人心危易失，聖學妙難親。", "願勉思弘毅，求仁可得仁。"]'),
('8643ad44-bc4e-4e90-93fa-fdd8a3aebfc7','定叟弟生辰','張栻','宋','宋诗','song-poetry','','[]','清秋記弧矢，舉酒頌年長。',48,'全唐诗/poet.song.150000.json','["清秋記弧矢，舉酒頌年長。", "別去今踰歲，情親祇對床。", "韋編閑玩味，幕府小徜徉。", "刮目它時看，光暉映棣棠。"]'),
('9a3eee4c-a986-4ee6-a174-48064ce114f7','南軒木犀','張栻','宋','宋诗','song-poetry','','[]','不隨秋月閟天香，冰雪叢中見縷黄。',32,'全唐诗/poet.song.150000.json','["不隨秋月閟天香，冰雪叢中見縷黄。", "却得清寒惜花地，少須梅影慰孤芳。"]'),
('2b04c7f3-d814-44f8-8a59-905d21b6e5de','和安國送茶','張栻','宋','宋诗','song-poetry','','[]','官焙蒼雲小卧龍，使君分餉自題封。',32,'全唐诗/poet.song.150000.json','["官焙蒼雲小卧龍，使君分餉自題封。", "打門驚起曲肱夢，公案從今又一重。"]'),
('5e43b06d-872c-49e3-a44a-c3c5e6c2321e','賦鄭子禮壽芝堂','張栻','宋','宋诗','song-poetry','','[]','莫向堂中覓壽芝，主人心地本平夷。',32,'全唐诗/poet.song.150000.json','["莫向堂中覓壽芝，主人心地本平夷。", "子孫保此傳家瑞，世享長年自不疑。"]'),
('af8ba47b-8523-4e67-b706-2f3643befbaa','喜雨呈安國  其一','張栻','宋','宋诗','song-poetry','','[]','懸知雨意未渠已，一夜簷聲到枕間。',32,'全唐诗/poet.song.150000.json','["懸知雨意未渠已，一夜簷聲到枕間。", "曉上高樓望雲氣，蟄龍千丈起西山。"]'),
('68f19544-338c-48fc-bcc2-b2395366a2e1','喜雨呈安國  其二','張栻','宋','宋诗','song-poetry','','[]','早秧出隴蠶已絲，眼中一雨正垂垂。',32,'全唐诗/poet.song.150000.json','["早秧出隴蠶已絲，眼中一雨正垂垂。", "農家辛苦渠能識，請誦周公七月詩。"]'),
