('e50f9174-1702-4f01-bab8-bf0e72e7f505','仲春有懷  其三','張栻','宋','宋诗','song-poetry','','[]','老木高枝不可攀，玉泉飛出半崖間。',32,'全唐诗/poet.song.150000.json','["老木高枝不可攀，玉泉飛出半崖間。", "如何借得清冷水，一洗瘡痍爲解顔。"]'),
('20c5104e-0086-40c8-8ddc-fd635492388d','仲春有懷  其四','張栻','宋','宋诗','song-poetry','','[]','楚翠亭邊花正開，道鄉臺下石崔嵬。',32,'全唐诗/poet.song.150000.json','["楚翠亭邊花正開，道鄉臺下石崔嵬。", "主人今有此客否，客亦思君日百回。"]'),
('56cc4c28-804f-41ef-98f7-508c107c51e3','仲春有懷  其五','張栻','宋','宋诗','song-poetry','','[]','想見城南春水深，春來夜夜動歸心。',32,'全唐诗/poet.song.150000.json','["想見城南春水深，春來夜夜動歸心。", "隔牆季子應無恙，爲託飛鴻寄好音。"]'),
('0be92060-f7b9-469a-8b63-94df6b436d21','次韻無爲使君尊兄見寄之什','張栻','宋','宋诗','song-poetry','','[]','江山接境相望近，風雨一春音問疎。',32,'全唐诗/poet.song.150000.json','["江山接境相望近，風雨一春音問疎。", "安得從公苕霅上，幅巾一葉卧看書。"]'),
('e36e3f42-ad16-49a5-9c76-f8396782de64','從呂揚州覓芍藥栽','張栻','宋','宋诗','song-poetry','','[]','揚州風物故依然，夢想他時楚水邊。',32,'全唐诗/poet.song.150000.json','["揚州風物故依然，夢想他時楚水邊。", "乞與靈根歸自種，梢頭繭栗看新年。"]'),
('b7eb93b1-dd49-47d6-a321-19c9900f8336','鶴','張栻','宋','宋诗','song-poetry','','[]','月底風前意味多，不妨佇立勝婆娑。',32,'全唐诗/poet.song.150000.json','["月底風前意味多，不妨佇立勝婆娑。", "軒中君子知多少，遣汝乘軒看若何。"]'),
('0437d4f9-30b0-465c-a0d0-33464f835bb9','望廬山','張栻','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','却望廬山倚柁樓，半空宿靄未全收。',32,'全唐诗/poet.song.150000.json','["却望廬山倚柁樓，半空宿靄未全收。", "蒼然五老獨獻狀，似欲勸人求一遊。"]'),
('6dda108e-1c43-4223-a9b7-b9f3f3bcd281','十二月乙卯登岳陽樓丙辰再登','張栻','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','維舟徑上岳陽樓，風雨排空暝不收。',32,'全唐诗/poet.song.150000.json','["維舟徑上岳陽樓，風雨排空暝不收。", "明日重來天色好，君山元自翠光浮。"]'),
('667f487a-e515-45f9-bb8d-9ffc0e78eae4','舟行湘陰道中雪作','張栻','宋','宋诗','song-poetry','','[]','歲晚歸來風雪裏，有懷端復爲誰開。',32,'全唐诗/poet.song.150000.json','["歲晚歸來風雪裏，有懷端復爲誰開。", "江清沙白湘陰路，却似當年訪戴回。"]'),
('9f108b07-9862-474b-a1ca-042266a3de21','登樓','張栻','宋','宋诗','song-poetry','','[]','風雨經旬只閉門，朝來倚檻已春深。',32,'全唐诗/poet.song.150000.json','["風雨經旬只閉門，朝來倚檻已春深。", "不知花片飛多少，但覺江城滿綠陰。"]'),
('183097ba-a252-48a2-9054-f133557f81ae','題城南書院三十四詠  其一','張栻','宋','宋诗','song-poetry','','[]','差差竹影連坡靜，細細荷風透屋香。',32,'全唐诗/poet.song.150000.json','["差差竹影連坡靜，細細荷風透屋香。", "午寂睡餘聊隠几，人間何用較閑忙。"]'),
('8fbfdae9-9a7a-4e2e-8470-43e19a845db0','題城南書院三十四詠  其二','張栻','宋','宋诗','song-poetry','','[]','新竹成林蕉葉青，隔籬深處有蟬鳴。',32,'全唐诗/poet.song.150000.json','["新竹成林蕉葉青，隔籬深處有蟬鳴。", "晚凉更覺長堤靜，自遶荷花待月明。"]'),
('516400b1-85f3-46a1-bf52-66e1a8c377a9','題城南書院三十四詠  其三','張栻','宋','宋诗','song-poetry','','[]','堦前樹影開還合，葉底蟬聲短復長。',32,'全唐诗/poet.song.150000.json','["堦前樹影開還合，葉底蟬聲短復長。", "睡起更知茶味永，客來聊共竹風凉。"]'),
('7fb78248-3d2d-4d9d-b3dc-5b6bd2409d9c','題城南書院三十四詠  其四','張栻','宋','宋诗','song-poetry','','[]','新凉物物有精神，靜倚書窗聽雨聲。',32,'全唐诗/poet.song.150000.json','["新凉物物有精神，靜倚書窗聽雨聲。", "忽憶子綦元未解，强分天籟太粗生。"]'),
('55513ca3-1a5d-4924-8a29-add651d3f412','題城南書院三十四詠  其五','張栻','宋','宋诗','song-poetry','','[]','凌晨騎馬路新凉，來挹湖邊風露香。',32,'全唐诗/poet.song.150000.json','["凌晨騎馬路新凉，來挹湖邊風露香。", "妙意此時誰共領，波間鷗鷺靜相忘。"]'),
('b8113e20-7bd0-4774-b51a-a6b759089cfe','題城南書院三十四詠  其六','張栻','宋','宋诗','song-poetry','','[]','林塘過雨不勝秋，萬蓋跳珠寫碧流。',32,'全唐诗/poet.song.150000.json','["林塘過雨不勝秋，萬蓋跳珠寫碧流。", "倚檻孤吟天欲暮，更穿芒屩上方舟。"]'),
('8e5afe4b-6462-4a63-86cf-9e46fb3a50ca','題城南書院三十四詠  其七','張栻','宋','宋诗','song-poetry','','[]','山色頓清秋欲半，湖光更凈日平西。',32,'全唐诗/poet.song.150000.json','["山色頓清秋欲半，湖光更凈日平西。", "凉風獵獵低荷蓋，歸翼翩翩度柳堤。"]'),
('750cb127-8af1-467b-ad42-d953aa5774f6','題城南書院三十四詠  其八','張栻','宋','宋诗','song-poetry','','[]','湖邊小築喜新成，秋入西山照眼明。',32,'全唐诗/poet.song.150000.json','["湖邊小築喜新成，秋入西山照眼明。", "不是厭喧來覓靜，四時光景本均平。"]'),
('69048122-3ab2-48b0-91d2-245a8e2a9f8b','題城南書院三十四詠  其九','張栻','宋','宋诗','song-poetry','','[]','秋風颯颯林塘晚，萬綠叢中數點紅。',32,'全唐诗/poet.song.150000.json','["秋風颯颯林塘晚，萬綠叢中數點紅。", "若識榮枯是真實，不知何物更談空。"]'),
('8fa9a8b0-d7b4-4d38-9bdd-c4fb4a800728','題城南書院三十四詠  其一○','張栻','宋','宋诗','song-poetry','','[]','移得幽蘭幾本來，竹籬深處手栽培。',32,'全唐诗/poet.song.150000.json','["移得幽蘭幾本來，竹籬深處手栽培。", "芬芳不必紉爲佩，月白風清取次開。"]'),
('321464e4-8dc0-41fb-a6f6-2b60b3d8c83a','題城南書院三十四詠  其一一','張栻','宋','宋诗','song-poetry','','[]','今年少雨菊花遲，青蕊方開三兩枝。',32,'全唐诗/poet.song.150000.json','["今年少雨菊花遲，青蕊方開三兩枝。", "但得悠然真意在，青山何處不相宜。"]'),
('a8a06281-a74f-409c-a443-11aee9a214ca','題城南書院三十四詠  其一二','張栻','宋','宋诗','song-poetry','','[]','秋後冬前一月晴，小園佳處日經行。',32,'全唐诗/poet.song.150000.json','["秋後冬前一月晴，小園佳處日經行。", "半山木落樓臺露，幾樹霜餘橘柚明。"]'),
('d474331e-d097-44fc-a81d-0d4eb7c73010','題城南書院三十四詠  其一三','張栻','宋','宋诗','song-poetry','','[]','鐃鼓喧豗十里城，人情正喜上元晴。',32,'全唐诗/poet.song.150000.json','["鐃鼓喧豗十里城，人情正喜上元晴。", "瘦筇獨立湖邊路，却有白鷗同眼明。"]'),
('99297a17-4f6f-4418-a8ce-cb23b291d8b0','題城南書院三十四詠  其一四','張栻','宋','宋诗','song-poetry','','[]','和風習習禽聲樂，晴日遲遲花氣深。',32,'全唐诗/poet.song.150000.json','["和風習習禽聲樂，晴日遲遲花氣深。", "妙理沖融無間斷，湖邊佇立此時心。"]'),
('3fa1e6f1-280b-4e7d-b2d9-132ef0bf6c9f','題城南書院三十四詠  其一五','張栻','宋','宋诗','song-poetry','','[]','曉來天氣便清新，獨倚闌干正暮春。',32,'全唐诗/poet.song.150000.json','["曉來天氣便清新，獨倚闌干正暮春。", "花落花開鶑自語，東風吹水細鱗鱗。"]'),
('0f7e56ef-57e1-4c3c-b34f-2ae9d2317570','題城南書院三十四詠  其一六','張栻','宋','宋诗','song-poetry','','[]','花柳芳妍十日晴，五更風雨送餘春。',32,'全唐诗/poet.song.150000.json','["花柳芳妍十日晴，五更風雨送餘春。", "莫嫌紅紫都吹盡，新綠滿園還可人。"]'),
('ba347cb0-2975-4ba2-964a-ad4b7cb1e1c2','題城南書院三十四詠  其一七','張栻','宋','宋诗','song-poetry','','[]','並湖數畝新疏闢，便有魚兒作隊行。',32,'全唐诗/poet.song.150000.json','["並湖數畝新疏闢，便有魚兒作隊行。", "我亦隨流浮小艇，晚凉細看縠紋生。"]'),
('559c74fb-7f16-4bb0-847e-a5384b4de451','題城南書院三十四詠  其一八','張栻','宋','宋诗','song-poetry','','[]','無言桃李也成陰，葉底黄鸝自好音。',32,'全唐诗/poet.song.150000.json','["無言桃李也成陰，葉底黄鸝自好音。", "一縷爐煙清晝永，韋編卷罷短長吟。"]'),
('d3bff5e4-2202-4b61-a748-e8324445d5cb','題城南書院三十四詠  其一九','張栻','宋','宋诗','song-poetry','','[]','化工生意源源在，靜處詳觀總不偏。',32,'全唐诗/poet.song.150000.json','["化工生意源源在，靜處詳觀總不偏。", "飛絮滿空春不盡，新荷貼水已田田。"]'),
('acd914ca-ddcc-453d-9a49-aec771ef28f3','題城南書院三十四詠  其二○','張栻','宋','宋诗','song-poetry','','[]','野艇新成尋丈許，柳堤橘浦足周旋。',32,'全唐诗/poet.song.150000.json','["野艇新成尋丈許，柳堤橘浦足周旋。", "添蓬不但爲遮日，準擬乘凉聽雨眠。"]'),
('574f0e26-b4f0-4dc6-89db-6b649e5414fb','題城南書院三十四詠  其二一','張栻','宋','宋诗','song-poetry','','[]','暮從別墅跨馿歸，風雨蕭蕭泥濺衣。',32,'全唐诗/poet.song.150000.json','["暮從別墅跨馿歸，風雨蕭蕭泥濺衣。", "出門回首且按轡，細聽泉聲和式微。"]'),
('ddb5303b-aa8c-45a0-bc14-950aef5e8cfa','題城南書院三十四詠  其二二','張栻','宋','宋诗','song-poetry','','[]','陰陰松竹影自轉，午枕無人到北窗。',32,'全唐诗/poet.song.150000.json','["陰陰松竹影自轉，午枕無人到北窗。", "何許狂風來動地，夢回波浪洶春江。"]'),
('0f28dc1b-3036-4154-9b39-083aed386580','題城南書院三十四詠  其二三','張栻','宋','宋诗','song-poetry','','[]','疎竹蕭蕭正雨聲，眼中日影又還晴。',32,'全唐诗/poet.song.150000.json','["疎竹蕭蕭正雨聲，眼中日影又還晴。", "鈎窗燕坐夏將半，荷葉已香湖水清。"]'),
('f8af404f-8a32-4402-9460-85c7f175c516','題城南書院三十四詠  其二四','張栻','宋','宋诗','song-poetry','','[]','莫道閑中一事無，閑中事業有工夫。',32,'全唐诗/poet.song.150000.json','["莫道閑中一事無，閑中事業有工夫。", "閉門清晝讀書罷，掃地焚香到日晡。"]'),
('50e41113-b72b-4f93-ae12-598d1ee06e78','題城南書院三十四詠  其二五','張栻','宋','宋诗','song-poetry','','[]','亭畔薰風盡日凉，來從水面過新篁。',32,'全唐诗/poet.song.150000.json','["亭畔薰風盡日凉，來從水面過新篁。", "悠然但覺盈襟抱，千古虞絃意未央。"]'),
('f6e9bd5a-7f7d-4417-a372-658117e549de','題城南書院三十四詠  其二六','張栻','宋','宋诗','song-poetry','','[]','拍堤水滿草茸茸，盡日野航西復東。',32,'全唐诗/poet.song.150000.json','["拍堤水滿草茸茸，盡日野航西復東。", "欲去未須愁日暮，月明波面更溶溶。"]'),
('cd36f1de-4520-4cb0-8074-61fb868548a2','題城南書院三十四詠  其二七','張栻','宋','宋诗','song-poetry','','[]','烏雲夭矯風作惡，雷奔電掣雨懸河。',32,'全唐诗/poet.song.150000.json','["烏雲夭矯風作惡，雷奔電掣雨懸河。", "須臾天宇復清霽，突兀西山紫翠多。"]'),
('f4d4e440-de2b-48f8-a91e-55fa187b1bfb','題城南書院三十四詠  其二八','張栻','宋','宋诗','song-poetry','','[]','朝陽初上藕花香，下馬虛亭一味凉。',32,'全唐诗/poet.song.150000.json','["朝陽初上藕花香，下馬虛亭一味凉。", "山鳥自呼魚自樂，誰云身世可相忘。"]'),
('1a2cf5f3-0b38-4eb0-bca5-3f93ee706e89','題城南書院三十四詠  其二九','張栻','宋','宋诗','song-poetry','','[]','北窗竹簟午陰凉，亦有清風到我旁。',32,'全唐诗/poet.song.150000.json','["北窗竹簟午陰凉，亦有清風到我旁。", "還與陶公事同否，未妨諸子細商量。"]'),
('71d3a196-44b0-4f5a-b9c9-eea38e0626dd','題城南書院三十四詠  其三○','張栻','宋','宋诗','song-poetry','','[]','睡覺西山月正平，荷香不斷曉凉生。',32,'全唐诗/poet.song.150000.json','["睡覺西山月正平，荷香不斷曉凉生。", "園中隻鶴知人意，已作金風警露聲。"]'),
('0dc046dc-3966-4cdc-b6ae-651658903f13','題城南書院三十四詠  其三一','張栻','宋','宋诗','song-poetry','','[]','西風夜半摧炎暑，曉看雲橫天際秋。',32,'全唐诗/poet.song.150000.json','["西風夜半摧炎暑，曉看雲橫天際秋。", "時序轉移皆妙理，惟應及早戒衣裘。"]'),
('4ff794c8-9f4f-41e6-bf22-fbfcfc04d9de','題城南書院三十四詠  其三二','張栻','宋','宋诗','song-poetry','','[]','新凉修竹意愈靜，初日芙蕖色倍鮮。',32,'全唐诗/poet.song.150000.json','["新凉修竹意愈靜，初日芙蕖色倍鮮。", "物態直須閑裏見，人情多向快中偏。"]'),
('06d596a3-303f-4c8a-bb67-913df5a4ede9','題城南書院三十四詠  其三三','張栻','宋','宋诗','song-poetry','','[]','四面紅蕖鏡綠波，晚凉柰此野情何。',32,'全唐诗/poet.song.150000.json','["四面紅蕖鏡綠波，晚凉柰此野情何。", "憑城更覺看山穩，入戶還欣得月多。"]'),
('89bad481-92f0-4eee-9e0e-3799ea34864b','題城南書院三十四詠  其三四','張栻','宋','宋诗','song-poetry','','[]','殷雷終日在前山，風卷雲環意作難。',32,'全唐诗/poet.song.150000.json','["殷雷終日在前山，風卷雲環意作難。", "泊暮有懷空佇立，忽然飛雨到闌干。"]'),
('1a16fa4f-703f-49f8-bbeb-6f80210f4512','臘月二十二日渡湘登道鄉臺夜歸得五絕  其一','張栻','宋','宋诗','song-poetry','','[]','三年不作山中客，才踏船舷眼便明。',32,'全唐诗/poet.song.150000.json','["三年不作山中客，才踏船舷眼便明。", "曳杖直登千尺磴，尚欣脚力慰生平。"]'),
('a41c9906-f894-4af4-bcba-c00be0594a18','臘月二十二日渡湘登道鄉臺夜歸得五絕  其二','張栻','宋','宋诗','song-poetry','','[]','舊日書堂倚翠屏，只今棟宇尚高明。',32,'全唐诗/poet.song.150000.json','["舊日書堂倚翠屏，只今棟宇尚高明。", "門前恍若聞絃誦，㶁㶁遶牆流水聲。"]'),
('7ce9d179-f9d5-403b-95b9-c24685d92473','臘月二十二日渡湘登道鄉臺夜歸得五絕  其三','張栻','宋','宋诗','song-poetry','','[]','道旁老松高拂雲，刳心取明彼何人。',32,'全唐诗/poet.song.150000.json','["道旁老松高拂雲，刳心取明彼何人。", "說與往來須愛護，雪霜時節看長身。"]'),
('b916ffb6-8c59-480d-9b19-0b8cb3e0eb89','臘月二十二日渡湘登道鄉臺夜歸得五絕  其四','張栻','宋','宋诗','song-poetry','','[]','人來人去空千古，花落花開任四時。',32,'全唐诗/poet.song.150000.json','["人來人去空千古，花落花開任四時。", "白鶴泉頭茶味永，山僧元自不曾知。"]'),
('980d0e21-dab2-42a1-8f1e-ba8b6d739a8d','臘月二十二日渡湘登道鄉臺夜歸得五絕  其五','張栻','宋','宋诗','song-poetry','','[]','湘江歲晚水清淺，橘洲霜後猶青葱。',32,'全唐诗/poet.song.150000.json','["湘江歲晚水清淺，橘洲霜後猶青葱。", "歸舟著沙未渠進，且看漁火聽疎鐘。"]'),
('88dee025-c152-42cb-88c0-5de8fc3e26b4','次韻許深父  其一','張栻','宋','宋诗','song-poetry','','[]','日日經行只小園，靜搘邛竹聽鳴泉。',32,'全唐诗/poet.song.150000.json','["日日經行只小園，靜搘邛竹聽鳴泉。", "此時心事何人共，素壁題詩第幾篇。"]'),
('bde77bb6-2e89-4354-924a-b7240ebef19a','次韻許深父  其二','張栻','宋','宋诗','song-poetry','','[]','西山老木正亭亭，雲影參差陰復晴。',32,'全唐诗/poet.song.150000.json','["西山老木正亭亭，雲影參差陰復晴。", "手卷殘書天欲暮，聞君剝啄叩門聲。"]'),
